-- Poems batch 67
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d88f7e42-1374-400b-a5d4-9784381d5784','泰山獵人石室遇仙聞董雙成奏《雲和》笙詞','不詳','唐','唐诗','tang','','["\u6cf0\u5c71"]','淅瀝復悠溶，諸天樂所宗。',65,'全唐诗/poet.tang.56000.json','["淅瀝復悠溶，諸天樂所宗。", "愔愔形類鳳，冉冉勢從龍。", "片觸峻嶒碎，聲飄列缺重。", "不辭歌一曲，此會信難逢。", "（《燈下閑談》卷下《獵猪遇仙》）。"]'),
('43be979e-c090-4056-aeee-20379e03839b','羅浮松續賈松句（題擬）','不詳','唐','唐诗','tang','','[]','白髮不由己。',176,'全唐诗/poet.tang.56000.json','["白髮不由己。", "（賈松。", "）黃金留待誰？", "（松作人語。", "見《燈下閑談》卷上《松作人語》。", "）（〖1〗《燈下閑談》云：「松乃諾之，遂同入羅浮，三年守真丹竃，藥既無成，吟且不廢。", "因夜靠松瞑目，吟曰：『白髮不由己。", "』如是數四，至於中夜。", "忽聞松上應聲曰：『黃金留待誰？", "」按：賈松，字夢得，乾寧中游宜春，與齊己、虛中等遊。", "光化四年登進士第，名列第八人。", "後至宜春與鄭谷遊。", "）。"]'),
('9a8ed4d0-776d-44bf-9a8a-f1cecef57967','日華月華君贈鄭冠卿詩（題擬） 一','不詳','唐','唐诗','tang','','[]','倏忽而來蹔少留，凡間風月已三秋。',89,'全唐诗/poet.tang.56000.json','["倏忽而來蹔少留，凡間風月已三秋。", "趨名競利何時了，害物傷人早晚休。", "禍極累成爲世謗，貴榮過却（《仙迹記》作「榮過恩却」）與身讎。", "君看虎戰龍爭者（《仙迹記》作「處」），幾樹白楊飄隴頭。"]'),
('0908543f-7363-4ebb-94a6-f2da9967e9e7','日華月華君贈鄭冠卿詩（題擬） 二','不詳','唐','唐诗','tang','','[]','名利教疏便可疏，俗情時態莫踟躕。',282,'全唐诗/poet.tang.56000.json','["名利教疏便可疏，俗情時態莫踟躕。", "人寰律歷千迴換，僊洞光陰數息餘。", "應（《仙迹記作「頃」》）信令威曾化鶴，亦（《仙迹記》作「今」）知莊叟美（《仙迹記》作「羨」）游魚。", "不緣過去行方便，那得今來（《仙迹記》、《碧虛銘》作「朝」）會碧虛。", "（見《燈下閑談》卷下《代名納稅》。", "又見桂林市文管局編《桂林石刻》錄桂林七星洞磨崖宋尹穡紹興五年撰《仙迹記》、《粵西金石略》卷九錄范成大《碧虛銘》錄「不緣」二句。", "《全唐詩》卷八六二僅收「不緣」二句，似即出《碧虛銘》。", "）（按：《燈下閑談》一書，舊題宋江洵著，實誤。", "據拙考應爲五代間人著，作者姓名已佚，約生於唐末，而書成則在後唐天成以後。", "）。"]'),
('f3441fb1-f00c-4777-8e4b-b5b762ad3961','王母贈魏夫人歌一章（幷序）','項宗','唐','唐诗','tang','','["\u8861\u5c71"]','駕我八景輿，歘然入玉清。',108,'全唐诗/poet.tang.56000.json','["駕我八景輿，歘然入玉清。", "龍裙拂霄漢，虎旂攝朱兵。", "逍遙玄津際，萬流無暫停。", "哀此去留會，劫盡天地傾。", "當盡無中景，不死亦無生。", "體彼自然道，寂觀合太冥。", "南嶽挺真翰，玉映曜穎精。", "有任靡期事，虛心自受靈。", "嘉會絳河內，相與樂未央。"]'),
('d5b0369e-1d49-4116-9fa7-f2ef8edc6c07','雙禮珠彈雲璈而答歌一章','項宗','唐','唐诗','tang','','[]','玉清出九天，神館飛霞外。',120,'全唐诗/poet.tang.56000.json','["玉清出九天，神館飛霞外。", "霄臺煥嵯峨，靈夏秀蔚翳。", "五雲興翠華，八風扇綠氣。", "仰吟消魔詠，俯研智與慧。", "萬真啓晨景，唱期絳房會。", "挺穎德音子，神映乃拂沛。", "天嶽凌空構，洞臺深幽邃。", "遊海悟井隘，履真覺世穢。", "儛輪宴重空，筌魚自然廢。", "廻我大椿羅，長謝朝生世。"]'),
('e2a3b1f9-f54b-456a-83ac-286a417047cb','高仙盼遊洞靈之曲一章（幷序）','項宗','唐','唐诗','tang','','[]','玉室煥東霞，紫輦浮絳宸。',84,'全唐诗/poet.tang.56000.json','["玉室煥東霞，紫輦浮絳宸。", "華臺何盼目，北宴飛天元。", "清浄太無中，眇眇躡景遷。", "吟詠大洞章，唱此三九篇。", "曲寢大漠內，神王方寸間，寂室思靈暉，何事苦山林。", "須臾變衰翁，廻爲孩中顏。"]'),
('d978ca1b-6d00-4ecd-ad41-1ad9cf2054f3','四真人降魏夫人歌共五章（幷序）','項宗','唐','唐诗','tang','','[]','丹明煥上清，八風鼓太霞。',84,'全唐诗/poet.tang.56000.json','["丹明煥上清，八風鼓太霞。", "廻我神霄輦，遂造玉嶺阿。", "咄嗟天地外，九圍皆吾家。", "上採日中精，下飲黃月華。", "靈觀空無中，鵬路無間邪。", "顧見魏賢安，濁氣傷爾和。", "勤研玄中思，道成更相過。"]'),
('e46d517d-c2a7-4575-87e5-53bd87df24e3','四真人降魏夫人歌共五章（幷序） 方諸青童歌一章','項宗','唐','唐诗','tang','','[]','太霞扇晨暉，九氣無常形。',84,'全唐诗/poet.tang.56000.json','["太霞扇晨暉，九氣無常形。", "玄轡飛霄外，八景乘高清。", "手把玉皇袂，攜我晨中生。", "盼觀七曜房，朗朗亦冥冥。", "超哉魏氏子，有心復有情。", "玄挺自嘉會，金書東華名。", "賢安密所研，相期暘谷汧。"]'),
('faafe114-d60b-48ef-aeda-cacabd38d0f1','四真人降魏夫人歌共五章（幷序） 次扶桑神王歌一章','項宗','唐','唐诗','tang','','[]','晨啓太帝室，超越匏瓜水。',84,'全唐诗/poet.tang.56000.json','["晨啓太帝室，超越匏瓜水。", "碧海飛翠波，連岑赤嶽峙。", "浮輪雲濤際，九龍同轡起。", "虎旂欝霞津，靈風翻然而理。", "華存久樂道，遂致高神擬。", "拔徙三緣外感會乃方始。", "相期陽洛宮，道成攜魏子。"]'),
('c81fb5cc-e62c-4caf-851c-68ee739a29ae','四真人降魏夫人歌共五章（幷序） 一','項宗','唐','唐诗','tang','','[]','駕歘控清虛，徘徊西華館。',84,'全唐诗/poet.tang.56000.json','["駕歘控清虛，徘徊西華館。", "瓊林既神杪，虎旂逐煙散，慧風振丹旍，明燭朗八煥。", "解襟庸房裏，神鈴鳴蒨粲。", "棲景若林柯，九絃玄中彈。", "遺我積世憂，釋此千年歎。", "怡盼無極已，終夜復待旦。"]'),
('7ee9fb83-d5d5-4446-a2b0-e8f2e3b2b47d','四真人降魏夫人歌共五章（幷序） 二','項宗','唐','唐诗','tang','','["\u8861\u5c71"]','紫霞儛玄空，神風無綱領。',576,'全唐诗/poet.tang.56000.json','["紫霞儛玄空，神風無綱領。", "歘然滿八區，祝爾豁虛靜。", "八窗無常朗，有冥亦有炅。", "洞觀三丹田，寂寂生形景。", "凝神挻相遇，雲姿卓鑠整。", "愧無郢石運，蓋彼自然穎。", "勤密攝生道，泄替結災眚。", "靈期自有時，攜袂乃俱上。", "（以上均見《雲笈七籤》卷九六。", "）（按：以上諸詩，《雲笈七籤》未云出處，今考應出《南嶽魏夫人傳》。", "檢顏真卿《文忠集》卷九《晉紫虛元職工領上真司命南嶽夫人魏夫人仙壇碑銘》云：「于是西王母擊節而歌。", "歌畢，馮雙禮珠彈雲璈而答歌，餘真人各歌。", "」《太平廣記》卷五八《魏夫人》條引《集仙錄》及《本傳》云：「于是四真吟唱，各命玉女，彈琴擊鐘吹簫，合節而發歌。", "……是時太極真人命北寒玉女宋聯消，彈九氣之璈，青童命東華玉女煙景珠，擊西盈之鐘。", "暘谷神王命神林玉女賈屈廷，吹鳳唳之簫，青虛真人命飛玄玉女鮮于虛，拊九合玉節。", "太極真人發《排空之歌》，青童吟『太霞』之曲，神王諷『晨啓』之章，清虛詠『駕飈』之詞。", "……王母擊節而，三元夫人彈雲璈而答歌，餘真各歌。", "」魏夫人，傳爲西晉時人，陶弘景《真誥》已載其事，惟較簡略。", "晉范邈撰《南真傳》，今不存。", "《太平廣記》所錄《本傳》，據陳國符先生《道藏源流考》考證，應即《新唐書·藝文志》著錄之項宗《紫虛元君魏夫人內傳》之節文。", "參以顏《碑》所云，其說可信。", "項宗，陳考爲唐人。", "《雲笈七籤》所據，當即項宗之書，《太平廣記》刪去諸詩，猶錄存之，較可寶惜。", "）。"]'),
('63d98979-1da1-4225-97f2-d3bbcb49e25c','申光遜夢張沆手出小佛塔上詩（題擬）','不詳','唐','唐诗','tang','','[]','今生不見故人面，明月高高上翠樓。',118,'全唐诗/poet.tang.56000.json','["今生不見故人面，明月高高上翠樓。", "（見《舊五代史》卷一三一《張沆傳》）（〖1〗《舊五代史》云：「有士人申光遜者，與沆友善。", "沆未病時，夢沆手出小佛塔示光遜，視其上有詩十四字云〖略〗。", "光遜）（既寤，心惡之，俄聞沆卒。", "」張沆卒於廣順二年秋。", "）。"]'),
('12b49371-7122-441d-ab2e-6ffd0c6279da','錢仁伉聞牡丹空中吁歎之辭（題擬）','不詳','唐','唐诗','tang','','[]','一花三百朶，含笑向春風。',322,'全唐诗/poet.tang.56000.json','["一花三百朶，含笑向春風。", "明年三月裏，朶朶斷腸紅。", "（見《增修詩話總龜》卷四八引《洞微志》）（〖1〗《洞微志》：「錢仁伉，尚父之孫也。", "爲元帥府中書檢校司徒，與中軍都虞候金沼鄰居。", "沼所居堂東，植牡丹藿一本，着花三百朶，其色如血，加之金含稜。", "每瓶子頂上有碎金絲，如自然蛺蝶之狀。", "一城以爲殊異。", "每歲花開張宴，仁伉預焉。", "開寶七年春三月花纔一兩朶開。", "仁伉一夕洪飲擊劍，裎服中單，背負大籃，左手攜鋤，腰插六匕首，踰墻而過沼，中外無知者。", "鋤取牡丹置籃中，乃平其地。", "空中聞有吁歎之聲，細微若遊蜂音，辭曰〖略〗。", "仁伉異之，移植於亭後。", "明日，沼覺失花，爲非人力所及。", "來年花盛開乃宴加沼，沼一見無語，得疾以歸。", "至夜憤悶不已，以刀決腸而卒。", "腸皆寸寸斷，果符空中之語。", "」）。"]'),
('92d4dfb8-7993-463c-ae7b-36bfac6bfc08','大曆間五臺山翁贈無著偈（題擬）','不詳','唐','唐诗','tang','','[]','一念淨心是菩提，勝造恒沙七寶塔。',58,'全唐诗/poet.tang.56000.json','["一念淨心是菩提，勝造恒沙七寶塔。", "寶塔究盡碎爲塵，一念淨心成正覺。", "（《宋高僧傳》卷二十《唐代州五臺山華嚴寺無著傳》）。"]'),
('fd879459-d0df-4105-aca4-4a3af8bb4ac1','大曆間五臺山童子贈無著偈（題擬）','不詳','唐','唐诗','tang','','[]','面上無瞋供養具，口裏無瞋吐妙香。',85,'全唐诗/poet.tang.56000.json','["面上無瞋供養具，口裏無瞋吐妙香。", "心裏無瞋是珍寶，無染無垢是真常。", "（同前）（按：《五燈會元》卷九《無著文喜禪師》云此偈爲杭州無著文喜禪師大中初至五臺山華嚴寺見童子說偈。", "）。"]'),
('d212a263-502d-44ca-baa3-d529294c6936','咸通三年文喜在洪州見文殊現身說偈（題擬）','不詳','唐','唐诗','tang','','["\u897f\u6e56"]','苦匏連根苦，甜瓜徹蔕甜。',48,'全唐诗/poet.tang.56000.json','["苦匏連根苦，甜瓜徹蔕甜。", "修行三大劫，却被老僧嫌。", "（《五燈會元》卷九、《西湖游覽志餘》卷十四。", "）。"]'),
('e96f0f08-1153-4266-bb6b-9a475721f91e','于則夢汧陽神紫相公謝供茶贈詩（題擬）','不詳','唐','唐诗','tang','','[]','降酒先生風韻高，攪銀公子更清豪。',48,'全唐诗/poet.tang.56000.json','["降酒先生風韻高，攪銀公子更清豪。", "碎身粉骨功成後，小碾當銜馬脚槽。", "（《說郛》卷六一引《清異錄》）。"]'),
('d901e050-d93a-4e4d-a725-5fcf1da0d0e6','蒲津朱衣人獻范仁恕詩','不詳','唐','唐诗','tang','','[]','欄馬遇孫陽，超光力自強。',80,'全唐诗/poet.tang.56000.json','["欄馬遇孫陽，超光力自強。", "北林花正發，西江彩筆香。", "萬彙須經手，千年事更長。", "感君施大惠，從此佐五皇。", "（《新編分門古今類事》卷六引《脞說》。", "范仁恕爲前、後蜀時人。", "）。"]'),
('2a73e8d3-d8d9-4e93-8aeb-a62fbe4f4802','九嶷邢仙翁詩','不詳','唐','唐诗','tang','','[]','虛皇天詔下仙家，不久星潢借客槎。',105,'全唐诗/poet.tang.56000.json','["虛皇天詔下仙家，不久星潢借客槎。", "壁上風雲三尺劍，牀前龍虎一鑪砂。", "行乘海嶼千年鶴，坐折壸宮四序花。", "爲愛《陰符》問元義，更隨綵仗入煙霞。", "（《三洞羣仙錄》卷十六引《談選》。", "云邢仙翁自唐僖宗時隱九嶷山，宋時尚在世。", "）。"]'),
('a91b158b-5a6c-4d46-bd2b-b7a4ec37cc27','潯陽漁父歌','不詳','唐','唐诗','tang','','[]','竹竿籊籊，河水悠悠。',55,'全唐诗/poet.tang.56000.json','["竹竿籊籊，河水悠悠。", "相忘爲樂，貪餌含鈎。", "非夷非惠，聊以忘憂。", "（同前卷四引《五代逸史》，云潯陽太守孫愐見之。", "）。"]'),
('66baf4bd-4467-49da-bd23-ddbb01589236','僧伽卒後顯形長慶元年夜半於泗州牧蘇公寢室前歌（題擬）','不詳','唐','唐诗','tang','','[]','淮南淮北，自此福焉。',65,'全唐诗/poet.tang.56000.json','["淮南淮北，自此福焉。", "自東自西，無不熟矣。", "（《宋高僧傳》卷十八《廣漠泗州普光王寺僧伽傳》）（按：僧伽卒於中宗景龍四年，年八十三。", "）。"]'),
('89f31add-5ab0-464f-9812-fb0bcab46225','崔球夢妻作詩（題擬）','不詳','唐','唐诗','tang','','[]','數日相望極，須知意思迷。',159,'全唐诗/poet.tang.56000.json','["數日相望極，須知意思迷。", "夢魂不怕險，飛過大江西。", "（見《增修詩話總龜前集》卷三五引李頎《古今詩話》）（〖1〗《古今詩話》云：「池陽崔球爲太學生，苦學不歸。", "一日，晝夢到其家，見其妻正寫字呼之，不應，與之言，不答，眡其所書，乃詩也，曰〖略〗。", "既覺，歷歷記之。", "數日書至，其妻寄此詩，一字不差。", "驗其寫詩日，乃球得夢之日也。", "」）。"]'),
('b252a93d-2fe1-42db-a97b-8d26eaa2191b','邢鳳挑女仙詩','不詳','唐','唐诗','tang','','["\u897f\u6e56"]','意態精神畫亦難，不知何事出仙壇。',138,'全唐诗/poet.tang.56000.json','["意態精神畫亦難，不知何事出仙壇。", "此君堂上雲深處，應與蕭郎駕彩鸞。", "（見《綠窗新話》卷上《邢鳳遇西湖女仙》）（按：此條原注出「商芸《小說》」，顯誤。", "邢鳳事，見《沈下賢文集》卷四、《博異志》、《酉陽雜俎》卷十四及《太平廣記》卷二八二引《異聞錄》。", "《綠窗新話》所載，疑出宋人續擬。", "）。"]'),
('5e978d0c-b903-43cd-92c4-365dc36683d2','李知遙臨化聞空中說偈','不詳','唐','唐诗','tang','','[]','報汝李知遙，成功果自招。',75,'全唐诗/poet.tang.56000.json','["報汝李知遙，成功果自招。", "引君生淨土，將爾上金橋。", "（見《大正新修大藏經》四七冊宋王日休《龍舒增廣淨土文集》卷五。", "）（按：李知遙，唐長安人，善淨土教。", "）。"]'),
('7ba08e7e-96e6-4b60-b701-a6159dfe73c5','青童君別趙旭詩','不詳','唐','唐诗','tang','','[]','與君宿世有仙緣，衾枕交歡豈偶然。',32,'全唐诗/poet.tang.56000.json','["與君宿世有仙緣，衾枕交歡豈偶然。", "十載爲期君記取，洞明山上鶴沖天。"]'),
('f36754b4-d9ae-4250-a423-31ae7bfb8138','趙旭酬青童君詩','不詳','唐','唐诗','tang','','[]','凡庸弱質感天仙，歡合交情僅一年。',33,'全唐诗/poet.tang.56000.json','["凡庸弱質感天仙，歡合交情僅一年。", "十載爲期專在念，莫忘歷歷枕前言。", "。"]'),
('de55ef5c-670f-4ec2-8536-5dabf1121172','後十三年有人於益州見趙旭形容短小如八九歲小兒模樣行歌於市曰','不詳','唐','唐诗','tang','','[]','塵緣盡兮仙緣來，清風冷然入我懷。',211,'全唐诗/poet.tang.56000.json','["塵緣盡兮仙緣來，清風冷然入我懷。", "青童仙君事已諧，洞明山上瑞雲埋。", "九月九日黃花開，仙人招我上天階，凌空雙鶴何快哉。", "（見羅燁《醉翁談錄》己集卷二《趙旭得青童君爲妻》）（按：《太平廣記》卷六五引《通幽錄》載趙旭與青童往來故事，錄詩一首，《全唐詩》卷八六三收入。", "《醉翁談錄》所載故事，較《通幽記》爲詳，不注出處。", "有二種可能：其一，《廣記》所收爲節本。", "其二，宋人在《通幽記》基礎上增益。", "同書全錄唐人傳奇之文甚衆。", "今尚難遽作論斷。", "）。"]'),
('789c9662-eb85-40d8-9a29-c8e18ebaa3b2','賈真人壁間留詩（題擬）','不詳','唐','唐诗','tang','','[]','此後不知誰有分，壁間留得上天梯。',77,'全唐诗/poet.tang.56000.json','["此後不知誰有分，壁間留得上天梯。", "（見《輿地紀勝》卷一八六《巴州》）（〖1〗《輿地紀勝》：「賈真人，唐人，居難江之紫極宮，白晝登仙，留詩壁間云〖略〗。", "」）。"]'),
('81f743fa-923a-45f6-a2b9-4f4f87e8284d','陳七子題臙脂巖詩','不詳','唐','唐诗','tang','','[]','朝遊秦地暮嶓臺，暫向人間獨往來。',158,'全唐诗/poet.tang.56000.json','["朝遊秦地暮嶓臺，暫向人間獨往來。", "家在碧潭深處住，從教清淺化蓬萊。", "（見同書卷一九○《洋州》）（〖1〗《輿地紀勝》：「陳七子，號休復。", "《興元記》謂正元中居褒城，然非定居也。", "嘗有人遇之於嶓臺山，山高而秀，不與衆峯雜，勢如聳臺，上有臙脂巖、水簾洞、石焙拂焙竹、燒藥爐、燒藥臺，下有清河水碧。", "七子嘗題詩於臙脂巖曰〖略〗。", "」）。"]'),
('e0a45fff-24a5-4ed6-8a05-c78b27ce23e9','唐時有人入觀源洞見石室壁間穉川詩','不詳','唐','唐诗','tang','','[]','松門石徑茸芳草，落花滿院香沉沉。',66,'全唐诗/poet.tang.56000.json','["松門石徑茸芳草，落花滿院香沉沉。", "（見《羅浮志》卷四引南宋人鄭介《續葛仙詩序》引）（按：葛洪字稚川，東晉人。", "此二句不可能爲其所作。", "）。"]'),
('c5fa91b3-caba-4ebc-a746-028595d851c2','詠千歲竇掌和尚（題擬）','不詳','唐','唐诗','tang','','[]','勞勞玉齒寒，似迸巖泉急。',47,'全唐诗/poet.tang.56000.json','["勞勞玉齒寒，似迸巖泉急。", "有景中夜坐，堦前神鬼泣。", "（《嘉泰普燈錄》卷二四、《五燈會元》卷二。", "）。"]'),
('d1504c4d-6e12-466f-a726-aa4e82a60c77','千歲竇寶掌和尚逰吳偈（題擬）','不詳','唐','唐诗','tang','','[]','梁城遇導師，參禪了心地。',29,'全唐诗/poet.tang.56000.json','["梁城遇導師，參禪了心地。", "飄零二浙游，更盡佳山水。", "（同前）。"]'),
('33eb6e06-36f9-4d57-baf3-e6ba3613ecf5','千歲寶掌和尚返飛來峰棲石竇題句（題擬）','不詳','唐','唐诗','tang','','[]','行盡支那四百州，此中偏稱道人遊。',21,'全唐诗/poet.tang.56000.json','["行盡支那四百州，此中偏稱道人遊。", "（同前）。"]'),
('8e8d48da-6f19-454a-baa0-2626c9b11017','千歲寶掌和尚題朗禪師壁','不詳','唐','唐诗','tang','','[]','白犬御書至，青猿洗鉢回。',17,'全唐诗/poet.tang.56000.json','["白犬御書至，青猿洗鉢回。", "（同前）。"]'),
('c81eb529-b3a9-4450-8c7d-a9102ec72086','千歲寶掌和尚臨滅示徒慧雲偈','不詳','唐','唐诗','tang','','[]','本來無生死，今亦示生死。',155,'全唐诗/poet.tang.56000.json','["本來無生死，今亦示生死。", "我得去住心，他生復來此。", "（同前）（按：二書云千歲寶掌和尚爲中印度人，生於周威烈王十二年。", "魏晉時東遊至中國，時已六百餘歲。", "梁時曾晤達摩而開悟。", "復遍歷江浙名山，貞觀十五年返飛來。", "顯慶二年卒，他們一千七十二。", "其事顯然出于附會，唐人著作及較早的幾部燈錄亦不載，似只能視爲小說家言，姑錄附此。", "）。"]'),
('135d7e19-6ac8-4193-a9ce-247f2392932d','徐登詩句','不詳','唐','唐诗','tang','','["\u534e\u5c71"]','鳳立煙霄迥，桃香碧澗逢。',91,'全唐诗/poet.tang.56000.json','["鳳立煙霄迥，桃香碧澗逢。", "（見《全閩詩話》卷十一）（〖1〗《全閩詩話》云，徐登，「神仙，兄弟姊妹七人，隱於閩國西嶽名山。", "乾封時來於絶頂，儀封二年化於潭上。", "」儀封，當爲「儀鳳」之誤。", "）。"]'),
('afcfd522-42eb-4b7a-b2ac-a036309cb4fd','陸禹臣贈吳生詩二首 一','不詳','唐','唐诗','tang','','[]','世俗風波險，人情巧智長。',24,'全唐诗/poet.tang.56000.json','["世俗風波險，人情巧智長。", "要知安分處，修性本真常。"]'),
('c0fd57c1-d2de-4580-bda3-7a92a319be45','陸禹臣贈吳生詩二首 二','不詳','唐','唐诗','tang','','[]','露下瑤簪滋，雲生石室寒。',92,'全唐诗/poet.tang.56000.json','["露下瑤簪滋，雲生石室寒。", "星壇鸞鶴舞，丹竃虎龍蟠。", "塵世人情窄，壸中景界寬。", "憑君高著眼，物外試迴觀。", "（見鄭方坤《五代詩話》卷九引《廣遠府志》。", "）（按：《全唐詩》卷八六一收後詩之前四句。", "）。"]'),
('8d976e86-4002-48ba-9d7e-d78d65e6b981','南嶽仙題金牛石壁','不詳','唐','唐诗','tang','','["\u8861\u5c71"]','手持黃鶴來，脚踏金牛背。',87,'全唐诗/poet.tang.56000.json','["手持黃鶴來，脚踏金牛背。", "塵世無人知，白雲久相待。", "（見《沅湘耆舊集》卷十三。", "（按：宋以後著作中託名唐代神仙詩，爲數甚夥，尤以呂巖詩爲最多，就余所見，數在千首以上，今皆不取。", "）。"]'),
('739636a2-ba8c-4c51-8d48-5fa56eb20b7a','鳳凰臺獸相和歌（題擬） 一','不詳','唐','唐诗','tang','','[]','深閨寒鎖難成夢，那得同衾共繍牀。',39,'全唐诗/poet.tang.56000.json','["深閨寒鎖難成夢，那得同衾共繍牀。", "一自與郎江上別，霜天更自覺宵長。", "（婦人歌。", "）。"]'),
('1ca69b70-af1d-4dab-8755-b37efa967ef2','鳳凰臺獸相和歌（題擬） 二','不詳','唐','唐诗','tang','','[]','纖阿斂照窗風起，漸覺霜寒逼玉牀。',39,'全唐诗/poet.tang.56000.json','["纖阿斂照窗風起，漸覺霜寒逼玉牀。", "幽恨從來無早暮，不知宵漏向人長。", "（男人和。", "）。"]'),
('4d8a3d6f-a0a8-43e8-8d3c-733f9a668333','鳳凰臺獸相和歌（題擬） 三','不詳','唐','唐诗','tang','','[]','愁聽黃鶯喚友聲，空閨曙色夢初驚。',37,'全唐诗/poet.tang.56000.json','["愁聽黃鶯喚友聲，空閨曙色夢初驚。", "窗前總有花牋紙，難寄妾心字字明。", "（又歌）。"]'),
('92de5c61-601f-4e43-8d44-e43ed302cc73','鳳凰臺獸相和歌（題擬） 四','不詳','唐','唐诗','tang','','[]','遙知把筆怯禽聲，密語書來屢自驚。',38,'全唐诗/poet.tang.56000.json','["遙知把筆怯禽聲，密語書來屢自驚。", "若道花牋傳不盡，幽情含處已分明。", "（又和。", "）。"]'),
('be15d144-c56e-4b7b-a604-35ca2c5be275','鳳凰臺獸相和歌（題擬） 五','不詳','唐','唐诗','tang','','[]','寂靜璇閨度歲華，並頭蓮葉又如錢。',38,'全唐诗/poet.tang.56000.json','["寂靜璇閨度歲華，並頭蓮葉又如錢。", "愁人獨處那堪此，安得君來共枕眠。", "（又歌。", "）。"]'),
('1b7a50c9-fe03-428b-b2b7-75f13bc8fafe','鳳凰臺獸相和歌（題擬） 六','不詳','唐','唐诗','tang','','[]','愁多四月日如年，金錯囊無買醉錢。',38,'全唐诗/poet.tang.56000.json','["愁多四月日如年，金錯囊無買醉錢。", "滿地落花愁不寐，非關明月夜遲眠。", "（又和。", "）。"]'),
('09160239-e51a-4ec7-b8c4-3b71b3c433f0','鳳凰臺獸相和歌（題擬） 七','不詳','唐','唐诗','tang','','[]','卧病匡牀香屢添，夜深猶有一絲煙。',38,'全唐诗/poet.tang.56000.json','["卧病匡牀香屢添，夜深猶有一絲煙。", "懷君無計能成夢，更恨砧聲到枕邊。", "（又歌。", "）。"]'),
('3768b53f-dbe5-4b41-aef0-f9b1562eabd7','鳳凰臺獸相和歌（題擬） 八','不詳','唐','唐诗','tang','','[]','寒燈未滅夜愁添，輕帳低垂薄似煙。',194,'全唐诗/poet.tang.56000.json','["寒燈未滅夜愁添，輕帳低垂薄似煙。", "忘却閨中病無寐，空教魂夢到君邊。", "（又和。", "見元林坤《誠齋雜記》卷下，元伊世珍《琅環記》卷上引《誠齋雜記》。", "）（〖1〗《誠齋雜記》云：「唐大歷中，有人獨行到鳳凰臺，望見一男子與一婦人相和而歌，聲澈雲際。", "」「歌罷，其人迫而視之，乃二獸焉，一類猪而體特高，蔚有文綵，一類龍而小，遍體純黃色。", "其人驚而走。", "行者問之因語其故，共往觀之，寂然無所見，惟竹書一束在地。", "」）。"]'),
('f7dc2f43-ea3a-4138-b39b-67eb9af3cc70','載初元年沙州歌謠（幷序○題擬。以下歌）','佚名','唐','唐诗','tang','','[]','於昭武王，承天剪商。',300,'全唐诗/poet.tang.56000.json','["於昭武王，承天剪商。", "誰其下武？聖母神皇。", "穆斯九族，綏彼四方。", "遵以禮儀，調以陰陽，三農五穀，萬[庾]（庚）千箱。", "載興文教，載構明堂。", "八窻四闥，上圓下方。", "多士濟濟，流水洋洋。", "明堂文興，百工時揆。", "庶人子來，●鼓不勝。", "肅肅在上，無幽不察，無遠不相。", "千齡所鐘，萬國攸向。", "俗被仁禮，家懷孝讓。", "帝德廣運，聖壽遐延。", "明明在下，於昭於天。", "本枝百代，福祚萬年。", "惟彼洛邑，聖母營之；惟彼河水，神皇清之；穆穆帝子，聖母生之；浩浩海瀆，神皇平之。", "福兮祐兮，在聖母兮；盛兮昌兮，在神皇兮。", "聖母皇皇，撫臨四方。", "東西南北，無思不服。", "禿髮狂瞽，侵我西土。", "皇赫斯怒，爰整其旅。", "荒徼之外，各安其所。", "穆穆聖君，受天之祐。", "聖皇爲誰？神皇聖母。"]'),
('0748324d-e674-423f-bad6-2a636c11250e','鄴下百姓爲張嘉祐歌（題從《古謠諺》卷八一）','佚名','唐','唐诗','tang','','[]','張公張公清且明，蝗蟲避境（闕）成，正（《金石萃編》作「巫」）晴（闕）雨（闕）晴。',108,'全唐诗/poet.tang.56000.json','["張公張公清且明，蝗蟲避境（闕）成，正（《金石萃編》作「巫」）晴（闕）雨（闕）晴。", "（見《全唐文》卷三九六尉遲士良《周太師蜀國公碑陰記》，據《金石萃編》卷八二參校。", "）（按：張嘉祐，事跡附《舊唐書》卷九九兄《嘉貞傳》。", "）。"]'),
('bf1037c9-1ac7-46ae-93f5-aa1ae7034e89','蜀州民爲鄭知賢歌（題擬）','佚名','唐','唐诗','tang','','[]','州有長史，一隅歡喜，調吏如琴，養民如子。',58,'全唐诗/poet.tang.56000.json','["州有長史，一隅歡喜，調吏如琴，養民如子。", "（《千唐誌齋藏誌》聖曆二年《周中大夫行蜀州長史上柱國鄭公〖知賢〗墓誌銘》）。"]'),
('3674d020-d095-44f4-a28d-398ff4186c2f','選人爲崔沔王丘歌（題擬）','佚名','唐','唐诗','tang','','[]','沔人澄明澈底清，丘山介直連天峻。',150,'全唐诗/poet.tang.56000.json','["沔人澄明澈底清，丘山介直連天峻。", "（見三長物齋刊本《顏魯公文集》卷五《通議大夫守太子賓客東都副留守雲騎尉贈尚書左僕射博陵崔孝公宅陋室銘記》引）（記云：「明我〖開元十四年〗，入朝，分掌十銓，公與王丘爲選人所歌曰〖略〗。", "時人韙之。", "」按：《全唐詩》卷八七六女作時人語，二句互乙，文字有數處不同，故重錄之。", "）。"]'),
('5fd26289-6d85-4445-9097-c120068af4c1','揚州民爲杜亞誦（題擬） 一','佚名','唐','唐诗','tang','','[]','膴膴原田，自今發始，歲其豐年。',21,'全唐诗/poet.tang.56000.json','["膴膴原田，自今發始，歲其豐年。", "（野人誦）。"]'),
('5babddc6-de74-4793-a3a5-6a180371a63c','揚州民爲杜亞誦（題擬） 二','佚名','唐','唐诗','tang','','[]','沔彼流水，我邦是紀，鍾美不知。',101,'全唐诗/poet.tang.56000.json','["沔彼流水，我邦是紀，鍾美不知。", "（都人誦。", "均見《文苑英華》卷八一二梁肅《通愛敬陂水門記》引）（按：貞元四年，杜亞爲揚州牧，疏濬邘溝，通愛敬陂，事峻，甚便農商，州民爲之作誦。", "梁肅文述其事甚詳，茲不具錄。", "）。"]'),
('8996dd30-2b2d-4b2f-bc31-ce2d1d09ca6e','濃州人爲刺史歌（題從《古謠諺》卷二七）','佚名','唐','唐诗','tang','','[]','可憐地上樓，百姓不知修。',48,'全唐诗/poet.tang.56000.json','["可憐地上樓，百姓不知修。", "上有清使君，下有清江流。", "（見《全唐文》卷六一九戎昱《濃州新城頌序》引）。"]'),
('4d04f1cd-24eb-40a4-a4d1-5c1d8b43b20b','清源郡人爲薛昱歌（題從《古謠諺》卷二七）','佚名','唐','唐诗','tang','','[]','郡號清源，官有清德。',61,'全唐诗/poet.tang.56000.json','["郡號清源，官有清德。", "（《嘉慶一統志》卷二六四）（〖1〗《嘉慶一統志》：「唐薛昱，天寶中爲清源太守，郡人哀曰〖歌略〗。", "」）。"]'),
('4c879c5b-29bf-45aa-b3e6-0874cac8e672','河南民爲河南尹某公歌（題從《古謠諺》卷八一擬）','佚名','唐','唐诗','tang','','[]','天災流行兮代有，下民昏墊兮時數。',77,'全唐诗/poet.tang.56000.json','["天災流行兮代有，下民昏墊兮時數。", "命無以遠兮諒自嗟，豈將天怒，我尹之慰恤兮，實解予之愁苦。", "夫得耕兮婦織，日出得作兮日入得息。", "此固我君之憂民兮，俾我尹之來即。"]'),
('f00476ba-4052-485f-8a97-b5ea5f6f85e1','又歌','佚名','唐','唐诗','tang','','[]','明明在上兮天子聖，四方取則兮我公令。',364,'全唐诗/poet.tang.56000.json','["明明在上兮天子聖，四方取則兮我公令。", "疲民蘇息兮公之政，一日將去兮，誰泎我之性命。", "（均見《全唐文》卷五一○李方郁《修中嶽廟記》引）（〖1〗《修中嶽廟記》：「上四年，用大司計侍郎爲丞相。", "其明年，以我相秉樞機，我公掌綸誥，宜爲避嫌，遂自閤下拜河南尹。", "將辭，上悄然謂公曰：『前時洛水爲災，洛民大潰，四走無遠，至有沒死者，豈勝其寃耶。", "而公今去，我無東顧之患矣。", "』公既至理事，先以恤民爲寄，活生瘞死，大開廩庾，賑貧乏，飽饑膓，暖寒體，極於畿甸。", "而又蠲逋租，省徭賦，俾安穩其起居，勤強其事業。", "故遠邇之民，相賀而歌曰〖略〗。", "又歌曰〖略〗。", "」杜文瀾《古謠諺》卷八一云：「案《全唐文》稱李方郁爲建中時人。", "今考建中爲德宗年號，而建中之號僅有四年，其明年則爲興元元年，文內敘述，又與時事不其相符。", "惟據連枝臺座之語，知尹河南者爲時相之昆弟耳。", "俟考。", "」）。"]'),
('6cce54cc-b783-4dad-a4b2-7593c386e65c','長道縣人爲王田二公歌','佚名','唐','唐诗','tang','','[]','二公更事，闔境之庇。',173,'全唐诗/poet.tang.56000.json','["二公更事，闔境之庇。", "二公其休，誰其爲嗣。", "（見《文苑英華》卷七九三于邵《田司馬傳》引）（〖1〗《田司馬傳》：「司馬姓田氏，名某，字某。", "……知長道縣事，……在公之勤，歲寒不易，嘉聲美政，益震於曩時。", "……時特進鴻臚卿兼刺史太原王公，勞於取人，逸於用人，前後褒貶，無有不當。", "田公雖讓德有餘，而王公混日不足，遂舉攝司馬仍知縣事。", "……故人歌之曰〖略〗。", "」）。"]'),
('26e16ce0-4213-4841-a367-90dbe14e7ab5','吉州民爲刺史張儇歌（題擬）','佚名','唐','唐诗','tang','','[]','昔吏𧦧𧦧，今吏詹詹，公能馭之，鉛（一作「雄」）亦爲銛，跖（一作「路」）亦爲亷。',281,'全唐诗/poet.tang.56000.json','["昔吏𧦧𧦧，今吏詹詹，公能馭之，鉛（一作「雄」）亦爲銛，跖（一作「路」）亦爲亷。", "始泄而（一作「紲始」）苦，終優以恬。", "昔民嗷嗷，今民咍咍，公能植（一作「撫」）之，鰥寡有怡。", "流亡既來，徭役先具，汙茨盡開。", "響覆官倉，倉無斗糧，公來幾時，積粟埋梁。", "響閱官庫，庫無尺繒，公來幾時，山積層層。", "瑞露溶溶，降味公松，瑞蓮漪漪，合蔕公池。", "公有異政，神之祚之，民歌路謠（一作「陲」），冀聞京師。", "天子明聖（一作「堂」），恩光遠而。", "（見杜文瀾《古謠諺》卷七六引《皇甫持正集》卷五《吉州刺史廳壁記》引，注一作者爲《四部叢刊》本《皇甫持正集》之異文。", "張儇之名，據同人《廬陵縣令廳壁記》補。", "）。"]'),
('d9d4a722-0ba7-4e25-ac2e-ef9064c6f236','果州百姓爲史謙恕歌（題從《古謠諺》卷五三）','佚名','唐','唐诗','tang','','[]','使君來何晚，昔日無儲今有飯。',57,'全唐诗/poet.tang.56000.json','["使君來何晚，昔日無儲今有飯。", "（《海錄碎事》卷十二）（〖1〗《海錄碎事》：史謙恕爲果州刺史，百姓歌之曰〖歌略〗。", "）。"]'),
('014372ed-9302-43b4-b3fe-57ce309aded9','杭州民誦刺史房孺復（題擬）','佚名','唐','唐诗','tang','','[]','雖有饑饉，必有豐年。',46,'全唐诗/poet.tang.56000.json','["雖有饑饉，必有豐年。", "大盜既去，我公來臻。", "（見李觀《李元菜肴文集》卷四《上杭州房使君書》引）。"]'),
('57f3aabb-3eb6-4283-9c76-4d447e7f3030','載筆氏晝百辟之詞','佚名','唐','唐诗','tang','','[]','鬱鬱紛紛，維慶霄之雲。',22,'全唐诗/poet.tang.56000.json','["鬱鬱紛紛，維慶霄之雲。", "古有堯舜，幸得以爲君。"]'),
('61eba76b-16e5-4178-a6be-50899a8079ad','象胥氏譯四夷之歌','佚名','唐','唐诗','tang','','[]','煒煒煌煌，天子之祥。',47,'全唐诗/poet.tang.56000.json','["煒煒煌煌，天子之祥。", "唐有神聖，莫敢不來王。", "（均見《元氏長慶集》卷二七《郊天日五色祥雲賦》引）。"]'),
('1507773a-98fd-425b-b434-68a334933ef8','道州民爲刺史薛伯高毀鼻亭神歌（題擬）','佚名','唐','唐诗','tang','','[]','我有耉老，公燠其饑。',108,'全唐诗/poet.tang.56000.json','["我有耉老，公燠其饑。", "我有病癃，公起其羸。", "髫童之囂，公實智之，鰥孤孔艱，公實遂之。", "孰尊惡德，遠矣自古。", "孰羨（一作「恣」）淫昏，俾我斯瞽。", "千歲之冥，公闢其戶。", "我子洎孫。", "（見柳宗元《柳河東集》卷二八《道州毀鼻亭神記》引）。"]'),
('7d6dccaf-2959-45dd-8318-c4f8140918bb','劉明德墓誌銘末附歌','佚名','唐','唐诗','tang','','[]','哀哉哲人，於何是美。',161,'全唐诗/poet.tang.56000.json','["哀哉哲人，於何是美。", "言滿山川，名揚閭□（疑爲「里」字）。", "上敬而恭，下問不耻。", "直而能謙，和而有禮。", "奈何龍劍，俱沉逝水。", "風樹蕭蕭，荒墳纍纍。", "曾閔攀號，哀情摧毀。", "中外痛咽兮苦深，腸斷絕兮不能已已。", "（見《山右石刻叢編》卷八《唐故校尉守左武衛涇州四門府折衝都尉員外置同正員賜紫金魚袋上柱國劉府君墓誌銘》。", "劉明德字節望，長慶二年卒）。"]'),
('dd8a34a7-c7fc-46c6-ac62-78f0a408f445','鍾陵郡民爲節度使紇干臮歌（題擬）','佚名','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','自公之來，闔境讙咍。',96,'全唐诗/poet.tang.56000.json','["自公之來，闔境讙咍。", "飲公之化，若乳嬰孩。", "（見《文苑英華》卷八一○韋慤《重修滕王閣記》引）（按：記云大中執徐歲「故我雁門公按節廉問」。", "檢《唐方鎮年表》卷五，大中二年紇干臮鎮江西。", "臮封雁門公。", "）。"]'),
('0ce69488-9e3d-4bf0-a893-b6b34a8b2a67','高平野老爲文斤歌（題從《古謠諺》擬）','佚名','唐','唐诗','tang','','[]','我聖君兮德巍巍，擇良牧兮治邊陲。',164,'全唐诗/poet.tang.56000.json','["我聖君兮德巍巍，擇良牧兮治邊陲。", "感神功兮雲雨施，稼穡如梁兮又如茨。", "無階達天真兮，咸願立乎豐碑。", "（見《全唐文》卷七一三潘滔《文公祠記》引）（按：文斤爲區晉高平令，其隱居地後稱文仙山。", "元和三年大旱，州縣爲文斤立碑而獲雨，野老相對佇鍤而歌此歌。", "詳見潘記。", "同治《湖南通志》卷二十《山川》收作尚顏《邵州甘雨歌》，未詳有他據否，今不取。", "）。"]'),
('32dea83a-13e9-46f1-a9f4-b360a3c06a4f','咸通中小兒歌（題擬）','佚名','唐','唐诗','tang','','[]','得節不得節，不過十二月。',31,'全唐诗/poet.tang.56000.json','["得節不得節，不過十二月。", "（見司馬光《資治通鑑考異》卷二十三）。"]'),
('6af9363a-3cfb-4071-aebf-75fc2529e0b3','吳高祖時華姥山童子歌（題撥）','佚名','唐','唐诗','tang','','[]','靈菌長，金刀響。',40,'全唐诗/poet.tang.56000.json','["靈菌長，金刀響。", "（見元劉大彬《茅山志》卷十一、《十國春秋》卷十四《劉得常傳》）。"]'),
('4a768b18-3e34-43bc-a493-cdaf6c23e0f6','華亭君歌','佚名','唐','唐诗','tang','','[]','華亭君，來幾時，免我疾苦療我饑。',76,'全唐诗/poet.tang.56000.json','["華亭君，來幾時，免我疾苦療我饑。", "（《檇李詩繫》卷四二）（〖1〗《檇李詩繫》：「唐末，瑯琊張聿爲嘉興軍華亭令。", "有以干乞至境上者，聞民此歌，不謁而去。", "」）。"]'),
('38b39dcc-a48c-414e-9fea-26a6cf9b2d6c','眉州民爲張琳歌（題擬）','佚名','唐','唐诗','tang','','[]','前有章仇後張公，疏決水利秔稻豐。',51,'全唐诗/poet.tang.56000.json','["前有章仇後張公，疏決水利秔稻豐。", "南陽杜詩不可同，何不用之代天工。", "（見《十國春秋》卷四十《張琳傳》引）。"]'),
('092e5a33-6f30-4a85-84f8-b693ca0ba743','周季年東漢國大雪盛唱（題擬）','佚名','唐','唐诗','tang','','[]','生怕赤真人，都來一夜春。',28,'全唐诗/poet.tang.56000.json','["生怕赤真人，都來一夜春。", "（見《說郛》卷六一《清異錄》）。"]'),
('9effd62d-ed3a-47b9-9ddd-dac90a63e8b7','閩人爲鄭家八虎歌（題擬）','佚名','唐','唐诗','tang','','[]','賈彪之虎兮往代，荀爽八龍兮典載，名不朽兮人不逢，人不逢兮名空在。',130,'全唐诗/poet.tang.56000.json','["賈彪之虎兮往代，荀爽八龍兮典載，名不朽兮人不逢，人不逢兮名空在。", "滎陽八虎今成羣，見之避之走紛紛。", "（見宋趙與泌、黃巖孫纂《仙溪志》卷四，注出《藝文志》、《九國志》、《獨〖疑有誤〗實錄》及《郡志》）（按：唐末詩人鄭良士有子八人，皆善文學，時稱鄭家八虎，爲作歌。", "）。"]'),
('7121b1d1-56f5-468f-a64c-0cc172ba00e6','紇真山神泉歌','佚名','唐','唐诗','tang','','[]','紇真山頭有神井，入地千尺絕骨冷。',35,'全唐诗/poet.tang.56000.json','["紇真山頭有神井，入地千尺絕骨冷。", "（見《太平寰宇記》卷五十一《朔州》）。"]'),
('7bbf70f8-bb5b-4bef-9324-f5163c3d0cf0','秦中兒童戲歌','佚名','唐','唐诗','tang','','[]','顛當顛當牢守門，蠮螉寇汝無處奔。',54,'全唐诗/poet.tang.56000.json','["顛當顛當牢守門，蠮螉寇汝無處奔。", "（見《西陽雜俎前集》卷十七）（按：《全唐詩》卷八七六收此歌不全，今重錄。", "）。"]'),
('7bc149bf-c34a-4db4-a3f9-bbb07ece7c5d','武德二年江東童謠（以下謠）','佚名','唐','唐诗','tang','','[]','江水何泠泠，楊柳何青青。',100,'全唐诗/poet.tang.56000.json','["江水何泠泠，楊柳何青青。", "人今正好樂，已復戍彭城。", "（見唐趙蕤《長短經》卷四《霸圖》）（〖1〗《長短經》：「大唐武德二年，王充殺越王侗於洛陽，僭稱尊號，隨氏滅矣。", "」注云：「今茲三月江東童謠曰〖略〗。", "」）。"]'),
('33d772c3-28b7-41e8-8dd1-54d05857b001','隨日童謠','佚名','唐','唐诗','tang','','[]','●水竭，武井溢，此中當有聖人出。',269,'全唐诗/poet.tang.56000.json','["●水竭，武井溢，此中當有聖人出。", "（見蔣斧《沙州文錄補》錄倫敦博物館藏敦煌出《大雲經疏》）（〖1〗《大雲經疏》：「又幷州太皇陵側，舊有一井，俗稱武井。", "先來有水，後遂乾枯。", "隨末以來，微似有水，自國家之後，水便滿井，至於今日，其水大流闊數丈，流水汾水。", "故隨日童謠云〖略〗。", "即明水流之義，本應神皇，非關人姓劉也。", "至劉武周聞人說決之即流，不決即李，武周無識，不解此語，謂是劉姓，遂起逆心。", "家破身亡，一何謬誤，豈知黑河武水水之流義也。", "」按：《大雲經疏》爲載初元年沙門十人爲武氏纂政而作之僞經。", "此首童謠，亦爲武氏而作，雖稱隨日，似未可信從。", "今收入。", "）。"]'),
('170c02b1-56f3-4a4a-95dd-29e6e036cded','女武王謠（題從《古謠諺》卷十二）','佚名','唐','唐诗','tang','','[]','當有女武王者。',24,'全唐诗/poet.tang.56000.json','["當有女武王者。", "（《舊唐書》卷六九《李君羨傳》）。"]'),
('234bd673-97c7-44ea-acf0-4082afef6f9f','軍中謠','佚名','唐','唐诗','tang','','[]','鄧守嘑，百夫避途。',62,'全唐诗/poet.tang.56000.json','["鄧守嘑，百夫避途。", "（明黃佐《廣州人物傳》卷三《鄧文進傳》，原注：「用《唐書》、《一統志》參修」。", "鄧於唐高祖時仕至韶州刺史）。"]'),
('3a2fdc33-4df8-40a1-905a-7bdd71fbe30e','長安中謠言','佚名','唐','唐诗','tang','','[]','見乞兒，與美酒，以免破屋之咎。',31,'全唐诗/poet.tang.56000.json','["見乞兒，與美酒，以免破屋之咎。", "（見宋馬永卿《實賓錄》卷十四）。"]'),
('795fc785-a5b8-4097-b161-27a01b7c79d8','武后時謠（題擬）','佚名','唐','唐诗','tang','','[]','武后臨朝萬萬年。',29,'全唐诗/poet.tang.56000.json','["武后臨朝萬萬年。", "（見《分門古今類事》卷十四引《紀異錄》）。"]'),
('8d31a0a2-5272-4fe2-87ca-dd3411b6262f','開元末童謠','佚名','唐','唐诗','tang','','[]','山下一羣鹿，大鹿來相逐。',54,'全唐诗/poet.tang.56000.json','["山下一羣鹿，大鹿來相逐。", "嗁殺（一作「死」）澗下羊，却被猪兒觸。", "（見宋劉斧《青瑣高議前集》卷六《驪山記》引）。"]'),
('efcc82a5-842e-463b-b021-b8487b90826d','天寶間謠（題擬）','佚名','唐','唐诗','tang','','[]','揚安史。',57,'全唐诗/poet.tang.56000.json','["揚安史。", "（《貴耳集》卷下）（〖1〗《貴耳集》：「天寶間楊貴妃寵盛，安祿山、史思明之作亂，遂有《楊安史》之謠。", "」）。"]'),
('26306742-1e54-492e-9f93-81278757e2f9','上元元年淮西童謠','佚名','唐','唐诗','tang','','[]','手執金刀起東方。',22,'全唐诗/poet.tang.56000.json','["手執金刀起東方。", "（見《資治通鑑》卷二二一）。"]'),
('2d11c00b-853d-4f9e-8cd3-d04f58c808c0','零陵郡復乳穴謠（題擬）','佚名','唐','唐诗','tang','','[]','甿之熙熙，崔公之來。',53,'全唐诗/poet.tang.56000.json','["甿之熙熙，崔公之來。", "公化所徹，土石蒙烈。", "以爲不信，起視乳穴。", "（見《柳河東集》卷二十八《零陵郡復乳穴記》）。"]'),
('1375ed61-ea85-433a-8d23-2fbc8da97a86','成都人爲新修福成寺謠（題擬）','佚名','唐','唐诗','tang','','[]','昔公去此，福成以燬。',54,'全唐诗/poet.tang.56000.json','["昔公去此，福成以燬。", "今公重還，福成復完。", "民安軍治，亦如此寺。", "（見《劉賓客文集》卷四《成都府新修福成寺記》）。"]'),
('26bde701-85b8-4e74-8bc2-909550df88a2','荆門縣人送裴均入朝謠（題擬）','佚名','唐','唐诗','tang','','[]','起我堙廢而遠之，徠我蕩析而安之。',95,'全唐诗/poet.tang.56000.json','["起我堙廢而遠之，徠我蕩析而安之。", "昔室于墟，風搖雨濡，自公優柔，郛閈盈兮。", "昔飲於洿，夏溷冬枯，自公感通，觱沸生兮。", "淑旂之華兮，四牡之騑。", "傒公之還兮，觴以祝之。", "（見同書卷九《復荆門縣記》引。", "）。"]'),
('2d54c537-2a06-4ad9-bf58-9778b00adcfc','鍾陵民爲李公謠（題從《古謠諺》卷八一擬）','佚名','唐','唐诗','tang','','[]','李公不愉，吾何以居。',44,'全唐诗/poet.tang.56000.json','["李公不愉，吾何以居。", "李公不室，我何以逸。", "（見《文苑英華》卷八二四苻載《鍾陵東湖亭記》）。"]'),
('1b4ed499-8df3-44c0-80be-30b452839a69','峽路謠（題從《古謠諺》卷五八擬）','佚名','唐','唐诗','tang','','[]','朝發白帝，暮徹江陵。',23,'全唐诗/poet.tang.56000.json','["朝發白帝，暮徹江陵。", "（見李肇《國史補》卷下）。"]'),
('4cb13d14-e69b-47a0-893e-29680beb840b','隴亭童謠','佚名','唐','唐诗','tang','','[]','秦隴無人塞草青，將軍一去泣空營。',45,'全唐诗/poet.tang.56000.json','["秦隴無人塞草青，將軍一去泣空營。", "漢家天子車巡狩，行到江南又起兵。", "（《記纂淵海》卷二十五）。"]'),
('75776ec4-9559-4442-996f-27514ff4a8e5','撫州民爲千金陂謠（題從《古謠諺》卷八一擬） 一','佚名','唐','唐诗','tang','','[]','公倅景城，民蘇南皮。',70,'全唐诗/poet.tang.56000.json','["公倅景城，民蘇南皮。", "南皮斗門，厥績今存。", "在昔河流，西走燕魏，民困隄防，日憂理水。", "舟楫壅遏，爲弊仍歲。", "公作斗門，分水之勢，亦不役民，荷公之制。"]'),
('c4c6dd2f-8ed7-48fa-87f4-8c432fe54511','撫州民爲千金陂謠（題從《古謠諺》卷八一擬） 二','佚名','唐','唐诗','tang','','[]','公作千金，撫民惠深。',108,'全唐诗/poet.tang.56000.json','["公作千金，撫民惠深。", "陂水沈沈，樂乎人心。", "我田不荒，我苗如林。", "憂公之去，誰其嗣音？", "（見《全唐文》卷八○五栢虔冉《新創千金陂記》引）（按：據記云：「公指咸通間「撫州刺史渤海李公。", "」郁賢皓先生《唐刺史考》疑李公爲李寂。", "）。"]'),
('e308d535-4b7e-449e-94d9-24f846b44988','咸通初洛中謠 一','佚名','唐','唐诗','tang','','[]','勿雞言，送汝樹上去；勿鴨言，送汝水中去。',20,'全唐诗/poet.tang.56000.json','["勿雞言，送汝樹上去；勿鴨言，送汝水中去。"]'),
('a62ca9da-1495-46eb-beb1-cf8d1e7e7010','咸通初洛中謠 二','佚名','唐','唐诗','tang','','[]','勿笑父母不認汝。',20,'全唐诗/poet.tang.56000.json','["勿笑父母不認汝。", "（均見《唐語林》卷七）。"]'),
('b99514c8-8a59-4e3c-9cc2-7c1d37d303e4','諸軍爲唐末帝謠（題擬）','佚名','唐','唐诗','tang','','[]','去（《續世說》作「除」）却生菩薩，扶起一條鐵。',93,'全唐诗/poet.tang.56000.json','["去（《續世說》作「除」）却生菩薩，扶起一條鐵。", "（見《舊五代史》卷四六《唐末帝紀上》、《續世說》卷七）（按：《全唐詩》卷八七八收此謠，僅作四言二句，似據《通鑑》卷二七九所錄，今重錄之。", "）。"]'),
('f8b18bc2-d1b4-4a95-aa68-591e4d2a523c','楊渥時謠言','佚名','唐','唐诗','tang','','[]','揚老抽嫰鬢，堪作打鐘槌。',34,'全唐诗/poet.tang.56000.json','["揚老抽嫰鬢，堪作打鐘槌。", "（見《知不足齋叢書》本《五國故事》卷上。", "）。"]'),
('a81c5880-0588-4927-9ce4-211782454649','淮南市井小兒唱','佚名','唐','唐诗','tang','','[]','檀來也。',9,'全唐诗/poet.tang.56000.json','["檀來也。", "（同前）。"]'),
('86420450-9bbd-47dd-bc89-f562dc581cb5','武義中童謠（題擬）','佚名','唐','唐诗','tang','','[]','江北桃花作雪飛，江南李樹玉團枝。',42,'全唐诗/poet.tang.56000.json','["江北桃花作雪飛，江南李樹玉團枝。", "李花結子可憐在，不似楊花沒了期。", "（見《釣磯立談》）。"]'),
('7b43f393-eda5-41f2-9196-0f537cb99017','吳越文穆王治世子弘樽府時謠言（題擬）','佚名','唐','唐诗','tang','','[]','何處有鹿脯？（見《吳越備史》卷二）。',18,'全唐诗/poet.tang.56000.json','["何處有鹿脯？（見《吳越備史》卷二）。"]'),
('db32d06c-c28a-4e4d-88e3-0fd2e3962248','長興中人爲張生鐵謠（題擬）','佚名','唐','唐诗','tang','','[]','生鐵打石頭，直待圓即休。',32,'全唐诗/poet.tang.56000.json','["生鐵打石頭，直待圓即休。", "（見《分門古今類事》卷二引《紀異錄》）。"]'),
('91da715b-20ca-469b-98e7-7ac0b777af70','湖南童謠','佚名','唐','唐诗','tang','','[]','湖南有長街，栽柳不栽槐。',82,'全唐诗/poet.tang.56000.json','["湖南有長街，栽柳不栽槐。", "百姓任奔竄，槌芒織草鞵。", "（《十國春秋》卷六九《楚廢王世家》）（按：《全唐詩》卷八七八收此謠爲七言四句，此作五言四句，與前不同，故重收之。", "）。"]'),
('1239bd49-062c-4c51-b78d-64c883cfbd3a','益陽土謠','佚名','唐','唐诗','tang','','[]','長沙益陽，一時相卬。',23,'全唐诗/poet.tang.56000.json','["長沙益陽，一時相卬。", "（杜光庭《錄異記》卷七）。"]'),
('4929c314-2563-494b-b606-b6a9558ae953','盧光稠未舉南康時謠','佚名','唐','唐诗','tang','','[]','盧破黎頭出，李子始花開。',40,'全唐诗/poet.tang.56000.json','["盧破黎頭出，李子始花開。", "潭深魚正聚，楊柳兩邊栽。", "（《九國志》卷二《譚全播傳》）。"]'),
('9de12fdf-bce4-46bc-97c3-2b1c7b038f4e','穀城石人腹讖文','佚名','唐','唐诗','tang','','[]','摩兜鞬，真勿言。',98,'全唐诗/poet.tang.56000.json','["摩兜鞬，真勿言。", "（見宋蘇頌《蘇魏公集》卷五《累年告老恩旨未俞……》詩注引，幷云：「唐劉洎少嘗遇異人，謂之曰：『君當佐太平得富貴，然宜慎兜鞬之戒。", "』洎後爲侍中，以議論不常獲譴。", "」劉洎，唐太宗時人）。"]'),
('1b7d46e0-45e1-4bec-b3a8-3f2acee166c0','白雲先生張約言葬失其地讖','佚名','唐','唐诗','tang','','[]','安龍頭，枕龍角。',37,'全唐诗/poet.tang.56000.json','["安龍頭，枕龍角。", "不三年，自消鑠。", "（《新編分門古今類事》卷十七引《摭遺》）。"]'),
('86f7ad8b-fd1c-4919-9b8d-1ea4a4404adc','崔巽遺言','佚名','唐','唐诗','tang','','[]','安龍頭，枕龍耳。',91,'全唐诗/poet.tang.56000.json','["安龍頭，枕龍耳。", "不三年，萬乘至。", "（同前）（按：《摭遺》云唐明皇獵於溫泉，見一山上有新墳，張約隨行，云葬失其地，引數語。", "詢樵者，知爲崔巽墓。", "巽子告以遵父遺言葬此。", "詔蠲巽子終身徭役。", "）。"]'),
('9a2252fc-c3e6-4d29-bce1-f6d2c8732b55','安慶緒將敗時讖 一','佚名','唐','唐诗','tang','','[]','渡河野狐尾獨速，明年死在十八日。',16,'全唐诗/poet.tang.56000.json','["渡河野狐尾獨速，明年死在十八日。"]'),
('e35c9606-476f-4af5-a632-a100e59f5eff','安慶緒將敗時讖 二','佚名','唐','唐诗','tang','','[]','胡絕其後，死在合河口。',25,'全唐诗/poet.tang.56000.json','["胡絕其後，死在合河口。", "（均見《安祿山事跡》卷下）。"]'),
('f3a352a4-590c-45bc-98fe-fa1fd6790f0a','錫山銘二首 一','佚名','唐','唐诗','tang','','[]','有錫兵，天下爭。',16,'全唐诗/poet.tang.56000.json','["有錫兵，天下爭。", "無錫寧，天下清。"]'),
('ddd56bdf-f93f-4d49-973a-71a41d810da0','錫山銘二首 二','佚名','唐','唐诗','tang','','[]','有錫沴，無錫乂，天下濟。',55,'全唐诗/poet.tang.56000.json','["有錫沴，無錫乂，天下濟。", "（元《無錫縣志》卷四陸羽《慧山寺記》後附，作者署「後世無名人」，原題作「唐錫山銘」）。"]'),
('39064132-d076-450c-8680-d8257d25d02a','牛僧孺讖','佚名','唐','唐诗','tang','','[]','首尾三麟六十年，兩角犢子恣狂顛，龍蛇相鬭血成川。',236,'全唐诗/poet.tang.56000.json','["首尾三麟六十年，兩角犢子恣狂顛，龍蛇相鬭血成川。", "（見《李文饒文集·窮愁志》卷四《周秦行紀論》引）（〖1〗《周秦行紀論》云：「餘嘗聞太牢氏好奇怪其身，險易其行，以其姓應國家受命之讖曰〖略〗。", "」三句爲僧孺自撰，抑爲敵黨誣構，尚不詳。", "宋陳善《捫虱新語》卷十三云「兩角犢子自全忠姓也」，傳璇琮先生《李德裕年譜》據以認爲此讖「本是晚唐五代人譏朱全忠的言辭被用進這篇《周秦行紀論》中去」。", "《後村詩話後集》卷一引朱翌說「夫犢子雙角，殆拆朱字耳」，劉克莊以爲朱泚、朱溫皆「有時而驗」。", "）。"]'),
('ed38c2ad-b728-4010-a834-d55d0d09181e','黃巢將興之讖','佚名','唐','唐诗','tang','','[]','黃蛇獨吼，天下人走。',22,'全唐诗/poet.tang.56000.json','["黃蛇獨吼，天下人走。", "（見《廣卓異記》卷六）。"]'),
('305e359f-891c-4126-a2fa-441a0ef0e3c0','天復初劉道昌得篆書','佚名','唐','唐诗','tang','','[]','八雄爭天下，狫鼠先啾唧。',138,'全唐诗/poet.tang.56000.json','["八雄爭天下，狫鼠先啾唧。", "（自庚子年黃巢見，朱全忠等八人僭號）。", "兔子上天牀，（馬建屬兔，又以卯年開國）猿猴三下失。", "（朱溫三帝屬猴也）李子生狼藉，（昭宗也）乃牛生叛䍽。", "（楊行密王於吳。", "斗牛，吳之分也）羣犬嘶首尾，走上中華國。", "（即六侵中國也。", "見《分門古今類事》卷十四引《賓仙傳》）。"]'),
('2670b169-f175-40bd-b934-2b99dd328117','王建時讖','佚名','唐','唐诗','tang','','[]','數在五樓前。',25,'全唐诗/poet.tang.56000.json','["數在五樓前。", "（見《說郛》卷二十引《洛中紀異錄》）。"]'),
('a354e84b-1dd2-4cc3-9a72-93222a8e6733','天目山讖','佚名','唐','唐诗','tang','','[]','天目山前兩乳長，龍飛鳳舞到錢塘。',185,'全唐诗/poet.tang.56000.json','["天目山前兩乳長，龍飛鳳舞到錢塘。", "海門一點巽山小，五百年間出帝王。", "（見宋錢儼《吳越備史》卷一、元劉一清《清塘遺事》卷一）（〖1〗《吳越備史》云此出郭璞《臨安地志》，然此首平仄工穩，非郭璞之時所宜有，當出唐末人依託爲錢氏開國之讖。", "《銭塘遺事》：「臨安都城，其山肇自天目，讖云〖略〗。", "錢氏有國世，臣事中朝，不欲其說之著，更其末云『異姓王』，以遷就之。", "高宗駐蹕，其說始驗。", "」）。"]'),
('15c209e7-100b-446e-8513-6eaab3c493e3','莆陽古讖','佚名','唐','唐诗','tang','','[]','自湖腰欲斷，莆陽朱紫半。',76,'全唐诗/poet.tang.56000.json','["自湖腰欲斷，莆陽朱紫半。", "水遶壺公山，此時大好看。", "（見宋李俊甫《莆陽比事》卷一）（〖1〗原注云：「《搜神秘覽》云：『壺公山欲斷，莆陽朱紫半。", "』訛矣。", "」）。"]'),
('e2cfd2b7-3a1e-49be-bb00-90e36af64b61','宋齊丘引南唐開國讖（題擬）','佚名','唐','唐诗','tang','','[]','密密作，唐唐得。',95,'全唐诗/poet.tang.56000.json','["密密作，唐唐得。", "（《新編分門古今類事》卷二十引《紀異錄》）（按：《紀異錄》載宋齊丘勸徐知誥即位語云：「又讖曰『密密作』，楊行密開托之初也。", "『唐唐得』，非公而誰？", "天命定矣，願公速副民望。", "」）。"]'),
('9630e1b4-9577-4111-ab5b-e399d0241c66','廣順末京師讖','佚名','唐','唐诗','tang','','[]','小兒剃元首。',92,'全唐诗/poet.tang.56000.json','["小兒剃元首。", "（《說郛》卷二十引秦再思《洛中記異錄》）（按：《洛中記異錄》言此爲「新君之兆也。", "未幾世宗嗣位，即替元首也。", "」《類說》卷十二引《紀異錄》作「識者曰」，「元首」作「光首」。", "）。"]'),
('a307eb68-3b69-433a-b0d2-c0489e5588e8','壺公山古讖','佚名','唐','唐诗','tang','','[]','市連義井歲時半，水遶壺公文物盛。',34,'全唐诗/poet.tang.56000.json','["市連義井歲時半，水遶壺公文物盛。", "（見《輿地紀勝》卷一三五《泉州》）。"]'),
('0165e247-9b15-409d-a0d7-f84e5516774e','唐商客王昌瑾得古鏡銘','佚名','唐','唐诗','tang','','[]','三水中，四維下，上帝降子于辰馬。',194,'全唐诗/poet.tang.56000.json','["三水中，四維下，上帝降子于辰馬。", "先操鷄，後搏鴨，此謂運滿一三甲。", "暗登天，明理地，遇子年中興大事。", "混踪跡，沌名姓，混沌誰知慎與聖。", "振法雷，揮神電，于巳年中二龍見。", "一則藏身青木中，一則現形黑金東。", "智者現，愚者盲，興雲注雨與人征。", "或見盛，或視衰，盛衰爲滅惡塵滓。", "此一龍，子三四，遞代相承元甲子。", "此四維，定滅醜，越海來降須待酉。", "此文若見于明王，國泰人安帝永昌。", "（《高麗史》卷一。", "時當後梁貞明中）。"]'),
('92805604-13a6-434d-84ff-1f6f4cdc1173','患目鼻人互嘲（題擬。以下嘲謔）','佚名','唐','唐诗','tang','','[]','眼能日月盈，爲有陳根委。',59,'全唐诗/poet.tang.56000.json','["眼能日月盈，爲有陳根委。", "（齆人先詠側眼人）不別似蘭斯，都由鴈門紫。", "（患眼人績下句。", "見《太平廣記》卷二五七《啓顏錄》）。"]'),
('f496a23b-58e3-45c0-a7e4-5a2c0a355bd3','謔高渙','佚名','唐','唐诗','tang','','[]','一百二十箇蜣螂，推一箇屎塊不上。',28,'全唐诗/poet.tang.56000.json','["一百二十箇蜣螂，推一箇屎塊不上。", "（見《唐摭言》卷十五）。"]'),
('8ff01541-08c3-46a9-afac-6966098f4838','戲杜審權','佚名','唐','唐诗','tang','','[]','座主審權，門生處權，可謂權不失權。',52,'全唐诗/poet.tang.56000.json','["座主審權，門生處權，可謂權不失權。", "（見《南部新書》卷丁）（按：《全唐詩》卷八七六錄此條不全，今重錄。", "）。"]'),
('c1e7887c-aa18-418d-8f25-5711c2cd939e','楚州好事者題吳堯卿葦棺','佚名','唐','唐诗','tang','','[]','信物一角，附至阿鼻地獄。',40,'全唐诗/poet.tang.56000.json','["信物一角，附至阿鼻地獄。", "請去斜封，送上閻羅大王。", "（見繆荃蓀刊本《廣陵妖亂志》）。"]'),
('530ddcb4-f179-4a29-998b-11d94c9bd068','教坊伶人獻語','佚名','唐','唐诗','tang','','[]','天子不須憂北寇，守貞面上管幽州。',115,'全唐诗/poet.tang.56000.json','["天子不須憂北寇，守貞面上管幽州。", "（見《舊五代史》卷一○九《李守貞傳》）（〖1〗《舊五代史》云：「其年〖指開運二年〗夏，契丹寇邊，以守貞爲北面行營都部署。", "少主開曲宴於內殿，以寵其行，教坊伶人獻語云〖略〗。", "既罷，守貞有自負之色。", "」）。"]'),
('ac352a43-4cf9-4d08-badf-41e8556036c8','詠和凝范質（題擬）','佚名','唐','唐诗','tang','','[]','從此廟堂添故事，登庸衣缽亦相傳。',135,'全唐诗/poet.tang.56000.json','["從此廟堂添故事，登庸衣缽亦相傳。", "（見《邵氏聞見錄》卷七、《澠水燕談錄》卷六）（〖1〗《邵氏聞見錄》云：「范魯公質舉進士，和凝爲主文，愛其文賦，凝自以第十三登第，謂魯公曰：『君之文宜冠多士，屈居第十三者，欲君傳老夫衣鉢耳。", "』魯公以爲榮。", "至先後爲相。", "獻詩者曰〖略〗。", "』」）。"]'),
('4c31e01b-b130-4030-a865-c98c5fce433c','嘲李度登第（題擬）','佚名','唐','唐诗','tang','','[]','主司只誦（《增修詩話總龜》卷三七引作「選」）一聯詩。',38,'全唐诗/poet.tang.56000.json','["主司只誦（《增修詩話總龜》卷三七引作「選」）一聯詩。", "（見《玉壺清話》卷七）。"]'),
('38c6e9b7-1bf0-4535-ab31-7b58613be60e','時爲俳偕語詠天','佚名','唐','唐诗','tang','','[]','高平上監碧翁翁。',57,'全唐诗/poet.tang.56000.json','["高平上監碧翁翁。", "（見《說郛》卷六一《清異錄》）（〖1〗《清異錄》：「晉出帝不善詩。", "時爲俳偕語詠天曰：〖略〗。", "」）。"]'),
('2437d9c3-84e3-4033-9006-f6d2ac5ba988','泰州民刺禇仁規詩','佚名','唐','唐诗','tang','','[]','多求囊白昧蒼蒼，兼取人間第一黃。',99,'全唐诗/poet.tang.56000.json','["多求囊白昧蒼蒼，兼取人間第一黃。", "（同前）（〖1〗《清異錄》：「僞唐贜臣禇仁規竊祿泰州刺史，惡政不可縷舉。", "有智民請吻儒爲二詩，皆隱語，凡寫數千幅，詣金陵粘貼，事乃上聞。", "詩曰〖略〗。", "黃自隱金銀字。", "」）。"]'),
('66a15dc2-281e-4b3a-8889-d5d5363b86be','伶倫改詩嘲陳癩子（題擬）','佚名','唐','唐诗','tang','','[]','三十年來陳癩子，如今始得碧紗幪。',86,'全唐诗/poet.tang.56000.json','["三十年來陳癩子，如今始得碧紗幪。", "（見《太平廣記》卷二五七引《玉堂閑話》）（〖1〗《玉堂閑話》謂二句爲短李相公詩，實誤。", "二句係改王播《題木蘭院》詩。", "王詩見《唐摭言》卷七。", "）。"]'),
('b2c6838b-fccb-4fdb-8404-5de4a37bbd38','嘲蝦蟆','佚名','唐','唐诗','tang','','[]','一跳八尺，再跳丈六。',50,'全唐诗/poet.tang.56000.json','["一跳八尺，再跳丈六。", "從春至夏，裸袒相逐。", "天地取作，掉尾肅肅。", "（見《歷代笑話集》本唐朱揆《諧噱錄》）。"]'),
('9dada24f-4deb-4dda-8532-c1a476396813','顏師古引諺','佚名','唐','唐诗','tang','','[]','賊無歷底中道回。',30,'全唐诗/poet.tang.56000.json','["賊無歷底中道回。", "（《匡謬正俗》卷八，云「內應導引爲歷底」）。"]'),
('09b755b9-3925-4b97-a88f-e86528b08ba6','華壤英主爲神迥諺（題擬）','佚名','唐','唐诗','tang','','[]','大論主，釋迦迥，法界多羅一時領。',34,'全唐诗/poet.tang.56000.json','["大論主，釋迦迥，法界多羅一時領。", "（見《續高僧傳》卷十三《神迥傳》）。"]'),
('753afa51-74ad-47f5-9583-f8d8a81ee562','貞觀時諺（題擬）','佚名','唐','唐诗','tang','','[]','無知之叟，又指禪師，亂識之夫，共歸明德。',48,'全唐诗/poet.tang.56000.json','["無知之叟，又指禪師，亂識之夫，共歸明德。", "返迷皆有大照，隨妄普翳真科。", "（見前書卷二十《僞徹傳》）。"]'),
('d3f11145-a67f-4416-942e-fbb3a7331441','魏徵引諺','佚名','唐','唐诗','tang','','[]','豐年珠玉，儉年穀熟。',22,'全唐诗/poet.tang.56000.json','["豐年珠玉，儉年穀熟。", "（《魏鄭公諫錄》卷三）。"]'),
('73fe9eeb-eb36-44ae-815e-567d6d2399b4','王勃引諺','佚名','唐','唐诗','tang','','[]','禍不入慎家之門。',27,'全唐诗/poet.tang.56000.json','["禍不入慎家之門。", "（見《王子安集》卷十《平臺秘略論》）。"]'),
('4295214a-8ac1-480d-9514-6aad10e12b1f','陳子昂引諺','佚名','唐','唐诗','tang','','[]','欲知其人，觀其所使。',30,'全唐诗/poet.tang.56000.json','["欲知其人，觀其所使。", "（見《陳拾遺集》卷八《上軍圖利害事》）。"]'),
('eecda89b-182d-4262-8b75-29cc308341a0','劉知已引今諺','佚名','唐','唐诗','tang','','[]','季與厥昆，爭知嫂諱。',31,'全唐诗/poet.tang.56000.json','["季與厥昆，爭知嫂諱。", "（見《史通》卷十九《漢書五行志錯誤篇》）。"]'),
('98519f85-6f0d-4943-876a-5e1ae538b4dd','張鷟引諺 一','佚名','唐','唐诗','tang','','[]','官倉喝雀，猶是向公。',31,'全唐诗/poet.tang.56000.json','["官倉喝雀，猶是向公。", "（《施注蘇詩》卷二十一引《朝野僉載》引）。"]'),
('04d314d6-8c26-460d-b021-e728d8cb0c39','張鷟引諺 二','佚名','唐','唐诗','tang','','[]','心欲專，鑿石穿。',16,'全唐诗/poet.tang.56000.json','["心欲專，鑿石穿。", "（《遊仙窟》）。"]'),
('c411bd6e-124f-4796-9257-760f36d66375','張說引諺','佚名','唐','唐诗','tang','','[]','歲在申酉，乞漿得酒。',29,'全唐诗/poet.tang.56000.json','["歲在申酉，乞漿得酒。", "（見《張燕公集》卷九《請置屯田表》）。"]'),
('ba2223df-53ae-4b08-969a-81be4f202129','李邕引諺','佚名','唐','唐诗','tang','','[]','河南照，天下少。',81,'全唐诗/poet.tang.56000.json','["河南照，天下少。", "（見日本《續藏經》第一五○冊收李邕《唐故白馬寺主翻譯惠沼神塔碑》）（按：此諺當即《續高僧傳》所收「河南一遍照，英聲不從召」之語的別一本，詳後。", "）。"]'),
('6ddf5cb5-5dd8-4674-a149-b5d0c0e9b76b','李邕妻溫氏引諺','佚名','唐','唐诗','tang','','[]','士無賢不肖，入朝見疾。',29,'全唐诗/poet.tang.56000.json','["士無賢不肖，入朝見疾。", "（見《新唐書》卷二○二《李邕傳》）。"]'),
('22ea841c-d773-4698-9a05-f30992f7803f','崔仁師引諺','佚名','唐','唐诗','tang','','[]','殺人刖足，亦皆有禮。',28,'全唐诗/poet.tang.56000.json','["殺人刖足，亦皆有禮。", "（見《新唐書》卷九九《崔仁師傳》）。"]'),
