('2d45b422-6c6b-4a9c-ae0b-46c87b937905','舉場舊話 一','佚名','唐','唐诗','tang','','[]','聞多見少，跡靜心勤。',50,'全唐诗/poet.tang.57000.json','["聞多見少，跡靜心勤。", "（省閑遊，事知己也）卷頭有眼，（投謁必其地也）肚裏沒嗔。", "（得失算命，羣居用和）。"]'),
('658345b1-0107-44f9-9f46-fc9690dfcc78','舉場舊話 二','佚名','唐','唐诗','tang','','[]','貌謹氣和，見面少，聞名多。',104,'全唐诗/poet.tang.57000.json','["貌謹氣和，見面少，聞名多。", "（古人有言。", "見多成醜之謂也。", "凡後進遊歷前達之門，或慮進趨揖讓，偶有蹶失，則雖有烜赫之文，終負生疎之謂。", "故文藝既至，第要投謁及時，不必孜孜求見也。", "如其深知己下歲寒之契，師友則不然也）。"]'),
('5fbd0219-d73e-4311-bf47-0ddb456254a5','舉場舊話 三','佚名','唐','唐诗','tang','','[]','上等舉人，應同人舉。',65,'全唐诗/poet.tang.57000.json','["上等舉人，應同人舉。", "（推公共也）中等舉人，應丞郎舉。", "（計通塞也）下等舉人，應宰相舉。", "（均見《唐摭言》卷十五。", "此承湯華泉同志見告）。"]'),
('ac8ab068-999b-4820-b930-4d7ea359e948','四相詩 生相','傅翕','唐','唐诗','tang','','[]','識託浮泡起，生從愛欲來。',48,'全唐诗/poet.tang.57000.json','["識託浮泡起，生從愛欲來。", "昔時曾長大，今日復嬰孩。", "星眼隨人轉，朱脣向乳開。", "爲迷真法性，還却受輪迴。"]'),
('971c3759-9297-4ef8-a2ec-34fe59b4d9c0','老相','傅翕','唐','唐诗','tang','','[]','覽鏡容顏改，登階氣力衰。',48,'全唐诗/poet.tang.57000.json','["覽鏡容顏改，登階氣力衰。", "咄哉今已老，趨拜禮還虧。", "身似臨崖樹，心如念水龜。", "尚猶躭有漏，不肯學無爲。"]'),
('83e900e6-52b1-4122-a134-5fae76753597','病相','傅翕','唐','唐诗','tang','','[]','忽染沈疴疾，因成臥病身。',49,'全唐诗/poet.tang.57000.json','["忽染沈疴疾，因成臥病身。", "妻兒愁不語，朋友厭相親。", "楚痛抽千脈，呻吟徹四鄰。", "不知前路險，猶向恣貪嗔。", "。"]'),
('677b9072-4069-40b8-b85d-04a420715365','死相','傅翕','唐','唐诗','tang','','[]','精魄辭生路，遊魂入死關。',48,'全唐诗/poet.tang.57000.json','["精魄辭生路，遊魂入死關。", "只聞千萬去，不見一人還。", "寶馬空嘶立，庭花永絕攀。", "早求無上道，應免四方山。"]'),
('3117c38b-53e1-4fff-81f1-2a125fd83a2b','頌 一','傅翕','唐','唐诗','tang','','[]','遍參四大海，觀尋五陰山。',60,'全唐诗/poet.tang.57000.json','["遍參四大海，觀尋五陰山。", "如來行道處，靈智甚清閑。", "實殿明珠曜，花座美玉鮮。", "心王明教法，敷揚般若蓮。", "浄土菩提子，蓋得天中天。"]'),
('789febea-62fd-4b95-88b5-d59b74526604','頌 二','傅翕','唐','唐诗','tang','','[]','觀此色身中，心王般若空。',60,'全唐诗/poet.tang.57000.json','["觀此色身中，心王般若空。", "聖智安居處，凡夫路不同。", "出入無門戶，觀尋不見蹤。", "大體寬無際，小心塵不容。", "欲得登彼岸，高張智慧篷。"]'),
('6a8e029f-6c89-404f-8ce7-bb404d47cb6c','頌 三','傅翕','唐','唐诗','tang','','[]','清淨明珠戒，莊嚴佛道塲。',60,'全唐诗/poet.tang.57000.json','["清淨明珠戒，莊嚴佛道塲。", "身作如來相，心爲般若王。", "願早登蓮座，口放大圓光。", "廣照無邊界，爲佛作橋梁。", "開大毘尼藏，名傳戒定香。"]'),
('959c1c55-aedf-447d-bec5-ab057557ac57','頌 四','傅翕','唐','唐诗','tang','','[]','觀達無生智，空中誰往來？永超三界獄，不染四魔胎。',60,'全唐诗/poet.tang.57000.json','["觀達無生智，空中誰往來？永超三界獄，不染四魔胎。", "遊戲蓮華上，安居法性臺。", "天上悉瞻仰，冥空讚善哉！有緣逢廣化，般若妙門開。"]'),
('14001c68-fb08-4944-af48-97d2af35e974','頌 五','傅翕','唐','唐诗','tang','','[]','夜夜抱佛眠，朝朝還共起。',48,'全唐诗/poet.tang.57000.json','["夜夜抱佛眠，朝朝還共起。", "行住鎮相隨，坐臥同居止。", "分毫不相離，如身影相似。", "欲知佛何在，只這語聲是。"]'),
('5070a276-85b5-4b16-b4ac-0d2d3eb82208','頌 六','傅翕','唐','唐诗','tang','','[]','寂是法王根，動是法王苗。',61,'全唐诗/poet.tang.57000.json','["寂是法王根，動是法王苗。", "湼槃既不遠，常住亦非遙。", "迴心名浄土，煩惱應時消。", "欲過三塗海，勤修六度橋。", "定當成正覺，喻若待來潮。", "。"]'),
('897ea8ec-430b-476b-87c3-8875c4a67849','頌 七','傅翕','唐','唐诗','tang','','[]','伏藏不離體，珠在內身中。',24,'全唐诗/poet.tang.57000.json','["伏藏不離體，珠在內身中。", "但向心邊會，莫遠外於空。"]'),
('85f7e4b8-aa1d-49db-ad56-db2e01e7279e','頌 八','傅翕','唐','唐诗','tang','','[]','萬類同真性，千般體一如。',48,'全唐诗/poet.tang.57000.json','["萬類同真性，千般體一如。", "若人解此法，何用苦尋渠。", "四生同一體，六趣會歸余。", "無明即是佛，煩惱不須除。"]'),
('21f39105-2dac-4627-a46b-c0bde3dd040b','貪嗔癡 一','傅翕','唐','唐诗','tang','','[]','不須貪，看取遊魚戲碧潭。',28,'全唐诗/poet.tang.57000.json','["不須貪，看取遊魚戲碧潭。", "只是愛他鈎下餌，一條線向口中含。"]'),
('1e8c4738-2eba-4035-90c6-d248da1d01ec','貪嗔癡 二','傅翕','唐','唐诗','tang','','[]','不須瞋，瞋則能招地獄因。',28,'全唐诗/poet.tang.57000.json','["不須瞋，瞋則能招地獄因。", "但將定力降風火，便是端嚴紫磨身。"]'),
('d6835d01-da7e-4eb6-9ef5-e5143bdc5fdc','貪嗔癡 三','傅翕','唐','唐诗','tang','','[]','不須癡，癡被無明六賊欺。',28,'全唐诗/poet.tang.57000.json','["不須癡，癡被無明六賊欺。", "惡業自身心所造，愚迷披却畜生皮。"]'),
('b956d58b-8c35-429a-a6ac-33e0d7104bf4','十勸 一','傅翕','唐','唐诗','tang','','[]','勸君一，專心常念波羅密。',28,'全唐诗/poet.tang.57000.json','["勸君一，專心常念波羅密。", "勤修六度向菩提，五濁三塗自然出。"]'),
('cedc8460-9e71-4547-8b86-f863314eaf13','十勸 二','傅翕','唐','唐诗','tang','','[]','勸君二，夫人處世莫求利。',28,'全唐诗/poet.tang.57000.json','["勸君二，夫人處世莫求利。", "縱然求得蹔時間，須臾不久歸蒿里。"]'),
('4bdbb88d-75cb-4423-b09e-684690a21bed','十勸 三','傅翕','唐','唐诗','tang','','[]','勸君三，人身難得大須慙。',28,'全唐诗/poet.tang.57000.json','["勸君三，人身難得大須慙。", "晝夜六時常念佛，勤修三寶向伽藍。"]'),
('13c48f5f-6ce0-4e69-a670-7143499c8a10','十勸 四','傅翕','唐','唐诗','tang','','[]','勸君四，努力經營修善事。',28,'全唐诗/poet.tang.57000.json','["勸君四，努力經營修善事。", "莫言少壯好光容，未委前程是何處。"]'),
('ee138d36-7810-4498-b739-87d749858d01','十勸 五','傅翕','唐','唐诗','tang','','[]','勸君五，尋思地獄真成苦。',28,'全唐诗/poet.tang.57000.json','["勸君五，尋思地獄真成苦。", "眼前富貴逞容儀，須臾不久還歸土。"]'),
('1fad426e-e26e-4182-8f37-4d9557926aae','十勸 六','傅翕','唐','唐诗','tang','','[]','勸君六，第一莫喫衆生肉。',28,'全唐诗/poet.tang.57000.json','["勸君六，第一莫喫衆生肉。", "若非菩薩化身來，便是生前親眷屬。"]'),
('4e852543-d049-4461-ab35-83561a2f0610','十勸 七','傅翕','唐','唐诗','tang','','[]','勸君七，萬事無過須的實。',28,'全唐诗/poet.tang.57000.json','["勸君七，萬事無過須的實。", "朝三暮四不爲人，此理安身終不吉。"]'),
('fde694c1-c976-4ef9-ba74-b2cc2f1ec186','十勸 八','傅翕','唐','唐诗','tang','','[]','勸君八，喫肉之人真羅剎。',29,'全唐诗/poet.tang.57000.json','["勸君八，喫肉之人真羅剎。", "今生若也殺他身，來生還被他人殺。", "。"]'),
('ceebdb1e-6ad9-46a6-b910-372bd9110b98','十勸 九','傅翕','唐','唐诗','tang','','[]','勸君九，天堂地獄分明有。',28,'全唐诗/poet.tang.57000.json','["勸君九，天堂地獄分明有。", "莫將酒肉勸僧人，五百生中無脚手。"]'),
('f4eb1ffe-f046-47bd-b943-c1da618d254b','十勸 十','傅翕','唐','唐诗','tang','','[]','勸君十，相勸修行須在急。',28,'全唐诗/poet.tang.57000.json','["勸君十，相勸修行須在急。", "一朝命盡入黃泉，父娘妻子徒勞泣。"]'),
('c3831c0c-b3f1-4512-a3cd-c01cd94c6353','頌二首 一','傅翕','唐','唐诗','tang','','[]','空手把鋤頭，步行騎水牛。',24,'全唐诗/poet.tang.57000.json','["空手把鋤頭，步行騎水牛。", "人從橋上過，橋流水不流。"]'),
('886a5736-c2db-4287-a54b-a7bca43e93e0','頌二首 二','傅翕','唐','唐诗','tang','','[]','有物先天地，無形本寂寥。',37,'全唐诗/poet.tang.57000.json','["有物先天地，無形本寂寥。", "能爲萬象主，不逐四時彫。", "（延壽《心賦注》引此首）。"]'),
('7d65c392-986d-482c-8950-35c89bce536c','還源詩十二章 一','傅翕','唐','唐诗','tang','','[]','還源去，生死湼槃齊。',22,'全唐诗/poet.tang.57000.json','["還源去，生死湼槃齊。", "由心不平等，法性有高低。"]'),
('4e3fea91-b53f-4200-9aa9-dfd7ed570d06','還源詩十二章 二','傅翕','唐','唐诗','tang','','[]','還源去，說易運心難。',22,'全唐诗/poet.tang.57000.json','["還源去，說易運心難。", "般若無形相，教君若爲觀。"]'),
('558230a8-ade4-45af-9c14-17969ab75aaa','還源詩十二章 三','傅翕','唐','唐诗','tang','','[]','還源去，欲求般若易。',22,'全唐诗/poet.tang.57000.json','["還源去，欲求般若易。", "但息是非心，自然成大智。"]'),
('eb60a701-2d8d-48bd-8786-6fb5ed9c6312','還源詩十二章 四','傅翕','唐','唐诗','tang','','[]','還溴去，觸處可幽棲。',22,'全唐诗/poet.tang.57000.json','["還溴去，觸處可幽棲。", "湼槃生死是，煩惱即菩提。"]'),
('79eb6040-0e2b-4d6d-bc59-1a71963a6352','還源詩十二章 五','傅翕','唐','唐诗','tang','','[]','還源去，依理莫隨情。',22,'全唐诗/poet.tang.57000.json','["還源去，依理莫隨情。", "法性無增減，妄說有虧盈。"]'),
('f6e2fa0b-6cfe-4a3e-b4f1-ae4844d610cb','還源詩十二章 六','傅翕','唐','唐诗','tang','','[]','還源去，何須更遠尋。',22,'全唐诗/poet.tang.57000.json','["還源去，何須更遠尋。", "欲求真解脫，端坐自觀心。"]'),
('125741b1-60dc-4901-a31f-c3eaf6b5da42','還源詩十二章 七','傅翕','唐','唐诗','tang','','[]','還源去，心性不思議。',22,'全唐诗/poet.tang.57000.json','["還源去，心性不思議。", "志小無爲大，芥子納須彌。"]'),
('539ed122-d457-4e88-8b59-df6634074c70','還源詩十二章 八','傅翕','唐','唐诗','tang','','[]','還源去，解脫無邊際。',22,'全唐诗/poet.tang.57000.json','["還源去，解脫無邊際。", "和光與物同，如空不染世。"]'),
('ca374e33-3165-46d9-ac0d-750d103b19f5','還源詩十二章 九','傅翕','唐','唐诗','tang','','[]','還源去，何須次第求。',36,'全唐诗/poet.tang.57000.json','["還源去，何須次第求。", "法性無前後，一念一時修。", "（此首見《宗鏡錄》卷十四）。"]'),
('fc425ace-d76a-4895-8445-54c6555b26a5','還源詩十二章 十','傅翕','唐','唐诗','tang','','[]','還源去，心性不沈浮。',37,'全唐诗/poet.tang.57000.json','["還源去，心性不沈浮。", "安住三（《宗鏡錄》卷二七作「王」）三昧，萬行悉圓收。", "。"]'),
('5b1b86c2-b96d-4d0f-9be6-6e688e843b66','還源詩十二章 十一','傅翕','唐','唐诗','tang','','[]','還源去，生死本紛淪。',22,'全唐诗/poet.tang.57000.json','["還源去，生死本紛淪。", "橫計虛爲實，六情常自昏。"]'),
('c2d96093-9997-4257-9e63-af289709ee0c','還源詩十二章 十二','傅翕','唐','唐诗','tang','','[]','還源去，般若酒澄清。',22,'全唐诗/poet.tang.57000.json','["還源去，般若酒澄清。", "能治煩惱病，自飲勸衆生。"]'),
('1047d611-f354-4533-bf3c-e5e008ae6007','浮漚歌','傅翕','唐','唐诗','tang','','[]','君不見驟雨近着庭際流，水上隨生無數漚。',147,'全唐诗/poet.tang.57000.json','["君不見驟雨近着庭際流，水上隨生無數漚。", "一滴初成一滴破，幾回銷盡幾回浮。", "浮漚聚散無窮已，大小殊形色相似。", "有時忽起名浮漚，銷盡還同本來水。", "浮漚自有還自無，象空象實總名虛。", "究竟還同幻化影，愚人喚作半邊珠。", "此時感歎閑居士，一見浮漚悟生死。", "皇皇人世總名虛，蹔借浮漚以相比。", "念念人間多盛衰，逝水東注永無期。"]'),
('f6c45d47-7819-439a-bbd1-479ce71d0760','獨自詩二十章 一','傅翕','唐','唐诗','tang','','[]','獨自山，茅茨草屋安。',22,'全唐诗/poet.tang.57000.json','["獨自山，茅茨草屋安。", "熊羆撩人戲，飛鳥共來飱。"]'),
('08416fb9-40df-4689-a99a-5e477eba75f7','獨自詩二十章 二','傅翕','唐','唐诗','tang','','[]','獨自居，何意此勤劬。',22,'全唐诗/poet.tang.57000.json','["獨自居，何意此勤劬。", "翹心尋本性，節志服真如。"]'),
('ef2bfa7f-43ee-495e-9e04-ff1826f0dd86','獨自詩二十章 三','傅翕','唐','唐诗','tang','','[]','獨自眠，寂寞好思玄。',22,'全唐诗/poet.tang.57000.json','["獨自眠，寂寞好思玄。", "休息攀緣境，不著有無邊。"]'),
('62f2742b-e9d4-408b-96a4-d910250beed9','獨自詩二十章 四','傅翕','唐','唐诗','tang','','[]','獨自坐，靜思觀無我。',22,'全唐诗/poet.tang.57000.json','["獨自坐，靜思觀無我。", "調直箇身心，慈悲成薩埵。"]'),
('bcb4d180-761f-48b6-aec3-06dbd3f0cccf','獨自詩二十章 五','傅翕','唐','唐诗','tang','','[]','獨自處，本誓如應語。',22,'全唐诗/poet.tang.57000.json','["獨自處，本誓如應語。", "示道在經中，扣破無明主。"]'),
('57233cb5-3472-4da5-9588-bf55be512d89','獨自詩二十章 六','傅翕','唐','唐诗','tang','','[]','獨自行，見色恰如盲。',22,'全唐诗/poet.tang.57000.json','["獨自行，見色恰如盲。", "輕軀同類化，蠕動未曾驚。"]'),
('2f04ac5c-13ce-4606-b5ed-db2ed38c1e3a','獨自詩二十章 七','傅翕','唐','唐诗','tang','','[]','獨自戲，問我心中有何爲？',28,'全唐诗/poet.tang.57000.json','["獨自戲，問我心中有何爲？", "若見無記在心中，急斷令還般若義。"]'),
('706acacb-4996-4ea4-bc4b-5bba140da979','獨自詩二十章 八','傅翕','唐','唐诗','tang','','[]','獨自往，觸處隨緣皆妄想。',29,'全唐诗/poet.tang.57000.json','["獨自往，觸處隨緣皆妄想。", "妄想心內富馳求，即此馳求亦非往。", "。"]'),
('eaa94de8-ab68-4358-963c-f754b1df8eca','獨自詩二十章 九','傅翕','唐','唐诗','tang','','[]','獨自歸，登山度嶺何所依。',28,'全唐诗/poet.tang.57000.json','["獨自歸，登山度嶺何所依。", "比至所依無定實，熟觀此境竟何為。"]'),
('e60deebd-2a89-46e5-913c-a376db1b4784','獨自詩二十章 十','傅翕','唐','唐诗','tang','','[]','獨自作，問我心中何所著？推檢四運併無生，千端萬緒何能縛？',28,'全唐诗/poet.tang.57000.json','["獨自作，問我心中何所著？推檢四運併無生，千端萬緒何能縛？"]'),
('1127e5df-3f80-42e0-9945-4b0f62123779','獨自詩二十章 十一','傅翕','唐','唐诗','tang','','[]','獨自語。問我心中何所取？',28,'全唐诗/poet.tang.57000.json','["獨自語。問我心中何所取？", "照了巧說並皆空，咽喉唇舌誰為主。"]'),
('69bace86-eecb-4051-8d18-1df196947947','獨自詩二十章 十二','傅翕','唐','唐诗','tang','','[]','獨自精，其實離聲名。',26,'全唐诗/poet.tang.57000.json','["獨自精，其實離聲名。", "三觀一心融萬品，荊蕀叢林何處生？"]'),
('d6d65e85-d7ec-4b28-aec7-d4bec6976451','獨自詩二十章 十三','傅翕','唐','唐诗','tang','','[]','獨自美，迢迢棄朝市。',26,'全唐诗/poet.tang.57000.json','["獨自美，迢迢棄朝市。", "追昔本願證無生，不得無生終不止。"]'),
('6660fac1-4747-4528-ad1a-8d08c4cea681','獨自詩二十章 十四','傅翕','唐','唐诗','tang','','[]','獨自佳，禪味朝飱不同蝦。',28,'全唐诗/poet.tang.57000.json','["獨自佳，禪味朝飱不同蝦。", "弊此摶食如應與，假借五陰以爲家。"]'),
('0a61fd56-01cd-4879-ab29-37a23b534246','獨自詩二十章 十五','傅翕','唐','唐诗','tang','','[]','獨自樂，但欲求無學。',22,'全唐诗/poet.tang.57000.json','["獨自樂，但欲求無學。", "急斷三界繩，得免泥犂惡。"]'),
('a68159d7-08fa-472f-a30f-9d650639bafd','獨自詩二十章 十六','傅翕','唐','唐诗','tang','','[]','獨自好，決求菩薩道。',22,'全唐诗/poet.tang.57000.json','["獨自好，決求菩薩道。", "萬行爲衆生，未取泥洹寶。"]'),
('721cf007-a113-4f74-a0af-9dfb830f5aa0','獨自詩二十章 十七','傅翕','唐','唐诗','tang','','[]','獨自歡，試取世緣看。',22,'全唐诗/poet.tang.57000.json','["獨自歡，試取世緣看。", "捉此無常境，一理向心觀。"]'),
('9a4be5f7-ec29-4b99-89f3-c904ecfd3ff2','獨自詩二十章 十八','傅翕','唐','唐诗','tang','','[]','獨自奇，正是學無爲。',22,'全唐诗/poet.tang.57000.json','["獨自奇，正是學無爲。", "迴首多許念，運向湼槃池。"]'),
('9a8db7ba-686b-474e-aace-5f5b6c411fbb','獨自詩二十章 十九','傅翕','唐','唐诗','tang','','[]','獨自足，願心無限局。',26,'全唐诗/poet.tang.57000.json','["獨自足，願心無限局。", "怨親法界語圓真，始得應身化羣育。"]'),
('d023ae12-3540-42cd-ab8e-0c98c765a34e','獨自詩二十章 二十','傅翕','唐','唐诗','tang','','[]','獨自宿，意裏心儲蓄。',26,'全唐诗/poet.tang.57000.json','["獨自宿，意裏心儲蓄。", "爲作良友繫衣珠，歷劫彌生根會熟。"]'),
('9502ffc2-3fc8-4880-a3b7-ff8b9ae6123f','爾時大士語諸弟子晝夜思維觀察自心生而不生滅而不滅止息攀緣人法相寂是爲解脫乃作五章詞曰 一','傅翕','唐','唐诗','tang','','[]','一更始，心香遍界起。',22,'全唐诗/poet.tang.57000.json','["一更始，心香遍界起。", "敬禮無上尊，心心已無已。"]'),
('1b21aa4b-9300-4c1f-b5e6-6ca1de3ba4a1','爾時大士語諸弟子晝夜思維觀察自心生而不生滅而不滅止息攀緣人法相寂是爲解脫乃作五章詞曰 二','傅翕','唐','唐诗','tang','','[]','二更至，跏趺靜禪思。',22,'全唐诗/poet.tang.57000.json','["二更至，跏趺靜禪思。", "通達無彼我，真如一不二。"]'),
('599c27ce-f091-4948-bcbe-1b2d687be92b','爾時大士語諸弟子晝夜思維觀察自心生而不生滅而不滅止息攀緣人法相寂是爲解脫乃作五章詞曰 三','傅翕','唐','唐诗','tang','','[]','三更中，觀法空不空。',22,'全唐诗/poet.tang.57000.json','["三更中，觀法空不空。", "無起無生滅，體一真如同。"]'),
('e7bb867a-0c68-4dde-8f14-3c6bbd941109','爾時大士語諸弟子晝夜思維觀察自心生而不生滅而不滅止息攀緣人法相寂是爲解脫乃作五章詞曰 四','傅翕','唐','唐诗','tang','','[]','四更前，觀法緣無緣。',22,'全唐诗/poet.tang.57000.json','["四更前，觀法緣無緣。", "真如四句絕，百非寧復煎。"]'),
('c1269120-c901-43a6-8ed8-e674cc08424d','爾時大士語諸弟子晝夜思維觀察自心生而不生滅而不滅止息攀緣人法相寂是爲解脫乃作五章詞曰 五','傅翕','唐','唐诗','tang','','[]','五更初，稽首禮如如。',22,'全唐诗/poet.tang.57000.json','["五更初，稽首禮如如。", "歸依無新故，不實亦不虛。"]'),
('e45de93d-7643-44ab-9344-88e445988952','行路難二十篇（幷序） 第一章明心非斷常','傅翕','唐','唐诗','tang','','[]','君不見自心非斷亦非常，普在諸方不入方。',207,'全唐诗/poet.tang.57000.json','["君不見自心非斷亦非常，普在諸方不入方。", "亦復不依前後際，又復非圓非短長。", "湛然無生亦無滅，非白非黑非青黃。", "雖復念慮知諸法，而實不住念中央。", "衆生入而無所入，雖取六境無所傷。", "智者分明了知此，是故號曰法中王。", "自悟知此非知法，因爾智慧等金剛。", "不藉外緣資內府，戒定慧品自閑防。", "安住普超三昧頂，憶想顛倒永消亡。", "覺諸煩惱真如相，稱此空名爲道塲。", "爲衆班宣演常教，如此妙義未曾彰。", "行路難，路難微妙甚難行。", "若以無知照知法，現前證得本無生。"]'),
('91379edf-08ad-4922-8783-f752fbb560fd','行路難二十篇（幷序） 第二章明真照無照','傅翕','唐','唐诗','tang','','[]','君不見真照分明性無照，通鑒坦蕩復無平。',207,'全唐诗/poet.tang.57000.json','["君不見真照分明性無照，通鑒坦蕩復無平。", "安住無明知明照，了達明照之無明。", "一心永斷於諸行，始復勤行於不行。", "一心非心亦非一，無一無心行不生。", "識心即是無生法，非離生法有無生。", "若知諸緣性無起，隨心顛倒任縱橫。", "解了空心無隔礙，世間言論不庸爭。", "若復苦欲爭言論，方爲貪癡之所盲。", "是故經說樂知見，五陰塵勞隨復生。", "若能專心復本際，自得正道坦然平。", "性正心平無有正，假設平正引羣生。", "行路難，路難常居五陰山。", "湼槃虛玄不爲寂，雖有生死獨清閑。"]'),
('27606767-0134-4c4c-a767-a67e068598ac','行路難二十篇（幷序） 第三章明心相實相','傅翕','唐','唐诗','tang','','[]','君不見心相微細最奇精，非作非緣非色名。',206,'全唐诗/poet.tang.57000.json','["君不見心相微細最奇精，非作非緣非色名。", "雖復恬然非有相，若凡若聖己之靈。", "此靈無形而常應，雖復常應實無形。", "心性無來亦無去，緣慮流轉實無停。", "正覺此之（《宗鏡錄》卷二九作「覺此」）真常覺，方便鹿苑制尊經。", "爲度妄想諸邪見，令知寂滅得安甯。", "廣說菩提與諸行，而此二法即音聲。", "了達音聲處非處，三毒煩惱不虧盈。", "又達五陰皆空寂，正慧無生制六情。", "於茲六情隨念滅，即是真了湼槃城。", "行路難，路難無往復無還。", "貪嗔不在於內外，亦復的不在中間。"]'),
('b2b9facc-bf9a-4004-b6eb-f630b8682f91','行路難二十篇（幷序） 第四章明無相虛融','傅翕','唐','唐诗','tang','','[]','君不見決定法中無決定，虛妄顛倒是菩提。',175,'全唐诗/poet.tang.57000.json','["君不見決定法中無決定，虛妄顛倒是菩提。", "若心分別菩提法，分別菩提還復迷。", "若了此迷無分別，迷與分別即菩提。", "分別菩提非一異，恒一同體不相離。", "安住性空真實性，空性無空亦不齊。", "同體大悲含一切，故知真性不乖迷。", "只此昏迷即無性，亦復不論齊不齊。", "若捨塵勞更無法，喻若蓮花生淤泥。", "如來法身無別處，普通三界苦泥犁。", "三界泥犁本非有，微妙誰復得見蹊？", "行路難，路難本自是泥洹。"]'),
('2fbb4847-d7be-48b4-930f-ccccaa0fa314','行路難二十篇（幷序） 第五章明凡聖非一非二','傅翕','唐','唐诗','tang','','[]','君不見煩惱茫然非是一，雖復非一亦非多。',143,'全唐诗/poet.tang.57000.json','["君不見煩惱茫然非是一，雖復非一亦非多。", "若能照知其本際，即是真身盧舍那。", "入於微塵亦無礙，無礙體寂遍娑婆。", "凡聖兩途非二處，生死涅槃常共和。", "雖復強立名和字，只箇愛癡真佛陀。", "般若深空智非智，以無心意制衆魔。", "余既誠心學此術，聊抽拙抱作斯歌。", "行路難，路難心性實極寬。", "貪欲本來常寂滅，智者於此可盤桓。"]'),
('050e1428-a89e-45f5-9d72-46249d375657','行路難二十篇（幷序） 第六章明心性無染','傅翕','唐','唐诗','tang','','[]','君不見智人求心不求佛，諸法寂滅即貪淫。',191,'全唐诗/poet.tang.57000.json','["君不見智人求心不求佛，諸法寂滅即貪淫。", "愛欲貪淫從心起，我亦徵心於無心。", "若也求心復不得，自然無處起貪淫。", "貪淫無起亦無滅，顛倒非淺亦非深。", "又亦不得非貪欲，無得不得妙難尋。", "三毒性中恒如此，具足常同堅固林。", "余事貪淫爲佛事，更無三毒橫相侵。", "若求出離還沉沒，分別出沒還復沈。", "諸佛善得於三毒，衆生虛妄不能任。", "我亦勤修三毒性，更不願求諸佛心。", "行路難，路難心中本無物。", "無物即是淨菩提，無見心中常見佛。"]'),
('7dab5692-0485-40d1-857b-19401cb9e4d0','行路難二十篇（幷序） 第七章明般若無諍','傅翕','唐','唐诗','tang','','[]','君不見般若真源本常淨，生死根際自虛微。',183,'全唐诗/poet.tang.57000.json','["君不見般若真源本常淨，生死根際自虛微。", "即此生死真般若，離斯外覓反相違。", "心若分別於生死，諸苦毒難竟相追。", "今若事之爲功匠，虛妄顛倒不能歸。", "而此但假空言語，淨穢兩邊俱不依。", "無心捨離於生死，涅槃無心即生死，生死無心般若暉。", "般若無心明照用，無照無用斷言辭。", "亦復不欲有諸見，即是法王無上醫。", "善解於此無心藥，三有諸病盡能治。", "行路難，路難遣之而復遣。", "識此遣性本來空，無心終是摩訶衍。"]'),
('79478f29-a9ba-4676-824e-25d59edeecf9','行路難二十篇（幷序） 第八章明本際不可得','傅翕','唐','唐诗','tang','','[]','君不見本際之中無復本，無本真際無人知。',190,'全唐诗/poet.tang.57000.json','["君不見本際之中無復本，無本真際無人知。", "若人無知了斯際，清淨妙不爲奇。", "知與無知常自爾，苦樂等同於大悲。", "三界衆生乃迷騖，於其實錄是無爲。", "亦復無此無爲法，強自生心是苦疲。", "苦疲皆空如炎響，生平不住不分離。", "能知此心無隔礙，生死虛妄不能羈。", "而此一心皆悉具，八萬四千諸律儀。", "亦復不墮過人法，嶮巇絕危而不危。", "一切法中無有法，世人遑遽欲何爲？", "行路難，路難心中無可看。", "昔日謂言諸佛遠，今知貪嗔是涅槃。"]'),
('65deb155-852a-4157-aa82-0364fbae8114','行路難二十篇（幷序） 第九章明無斷煩惱','傅翕','唐','唐诗','tang','','[]','君不見文殊妙德非爲遠，三障三毒即二空。',175,'全唐诗/poet.tang.57000.json','["君不見文殊妙德非爲遠，三障三毒即二空。", "五分法身纏五陰，六人無知爲六通。", "四倒四果何曾異，八邪八正體還同。", "七覺菩提性無別，七識流浪會真宗。", "一切煩惱皆空寂，諸佛法藏在心胸。", "恒將法忍相隨逐，只自差舛不相逢。", "諸佛如來住何所，併在貪淫愛欲中。", "今勸斷貪淫愛欲，但是方便化童蒙。", "貪欲本相真清淨，假說空名名亦空。", "行路難，路難心中非是心。", "寄語真修無念士，慎勿分別毀貪淫。"]'),
('3e0888ed-955c-45df-9a97-c7eca6afa276','行路難二十篇（幷序） 第十章明寂滅無心常行精進','傅翕','唐','唐诗','tang','','[]','君不見寂滅性中無寂滅，真實覺中無覺和。',223,'全唐诗/poet.tang.57000.json','["君不見寂滅性中無寂滅，真實覺中無覺和。", "亦復無有無知覺，清虛寂寞離方規。", "法性自爾無因致，憶想顛倒性無爲。", "正使飄流遍三界，於其心中實不移。", "無去無來亦無住，善達無住亦無虧。", "諸佛世雄非尊大，三毒四倒亦非卑。", "却尋緣心無所得，無緣心中緣復彌。", "若欲速去無上道，無知三毒性能資。", "三毒生於三解脫，七識還生七覺支。", "倒心去來無有實，去來無急亦無遲。", "覺諸煩惱觀前境，但自懲心而却推。", "心本無根何有本，六塵五欲不能拘。", "行路難，路難微妙甚希奇。", "昔日殷勤勇精進，不知精進背無爲。"]'),
('ea51a55e-930d-48e2-854a-d90f0d26b5a3','行路難二十篇（幷序） 第十一章明法身體用自在','傅翕','唐','唐诗','tang','','[]','君不角大士自觀身中法，身是如來淨法身。',192,'全唐诗/poet.tang.57000.json','["君不角大士自觀身中法，身是如來淨法身。", "虛空往還最迅速，獨脫自在不由人。", "出入毛孔而無礙，愛取塵時不染塵。", "現處凡情等諸聖，離斯求道更無真。", "建立諸法而無法，即是真如無上真。", "億劫本有而非故，於今現覺亦非新。", "成就大我而無我，具足大人無有人。", "聖體無明不可說，爲復方便名心神。", "即此心是真常法，亦是涅槃之上珍。", "願諸學人同此悟，各自守門而禁津。", "行路難，路難名異理無分。", "若能了於無生死，便得除消生死雲。", "。"]'),
('9692e0bb-b1ec-49aa-afd6-b59ac1d31341','行路難二十篇（幷序） 第十二章明金剛解脫','傅翕','唐','唐诗','tang','','[]','君不見金剛語句非真實，萬象森羅同一無。',191,'全唐诗/poet.tang.57000.json','["君不見金剛語句非真實，萬象森羅同一無。", "而此空無爲佛母，復是真如無上珠。", "世人不知求此寶，貧窮怱怱六趣奴。", "不事身中法身佛，冗冗向外禮浮圖。", "乍看而欲似精進，檢責身中皆併麄。", "用箇麄心逞言語，不了真源由是愚。", "隨情憶想而分別，五陰六賊競來誅。", "不肯尋求無上道，但知虛妄取名譽。", "口雖唱善還生惡，空言真實反成虛。", "余今反虛持作實，亦不證實入無餘。", "行路難，路難舉世皆虛妄。", "十纏五陰性無知，愚人於中自生障。"]'),
('59fa97c8-1e06-4dc0-8170-f3df329d7390','行路難二十篇（幷序） 第十三章明寂靜無照無得','傅翕','唐','唐诗','tang','','[]','君不見諸法但假空施設，寂靜無門爲法門。',191,'全唐诗/poet.tang.57000.json','["君不見諸法但假空施設，寂靜無門爲法門。", "一切法中心爲主，余今不復得心源。", "究檢心源既不得，豈知諸法併無根。", "用此無根心照境，照之分明彌復惛。", "即此惛心還自照，正照之理未曾存。", "照之與境俱差異，是故智士不能論。", "世人往往強分別，無中照見亂精魂。", "若能智照亡非照，分別智照復還奔。", "諸法本爾誰人作，寂靜無寂亦無喧。", "故知衆生顛倒想，還是衆生無上尊。", "行路難，路難捨癡而非癡。", "飛禽走獸我能伏，只箇心賊獨難治。"]'),
('9b93ba4e-0c95-4eae-8efc-58a0dbeadbcf','行路難二十篇（幷序） 第十四章明三空無性','傅翕','唐','唐诗','tang','','[]','君不見諸佛聖人心無礙，爲通道化說三無。',207,'全唐诗/poet.tang.57000.json','["君不見諸佛聖人心無礙，爲通道化說三無。", "雖說三無實無說，心爲萬境所由居。", "正使顛倒造五逆，隨情所作併歸如。", "抱檏澄神念無念，亦不分別滅無餘。", "所以安心不擇處，了知真俗體非殊。", "息慮心空不捨事，名理言行不相扶。", "不依六塵心搖動，真如無作順空虛。", "無去無來常不住，心神竭盡亦非無。", "不壞於身隨一相，不斷貪淫而不居。", "若謂無差還自縛，言其體異轉傷軀。", "猶如夢幻無真實，本來非有若爲除。", "行路難，路難頓爾難料理。", "凡夫妄見有差殊，真實凝心無彼此。"]'),
('b725c594-b90e-49bf-bee3-ce39aed693a1','行路難二十篇（幷序） 第十五章明空有不違','傅翕','唐','唐诗','tang','','[]','君不見邪見非邊不離邊，顛倒分別亦非緣。',191,'全唐诗/poet.tang.57000.json','["君不見邪見非邊不離邊，顛倒分別亦非緣。", "自心非心念非念，常來常去實無遷。", "猶若金剛難沮壞，諸佛用此作金堅。", "世人稱譽涅槃妙，余道生死最深玄。", "即是無生之上忍，又是摩訶無礙禪。", "正士由心於是定，不爲八風之所牽。", "天樂之在無心戀，小小財色豈能纏。", "隨逢苦樂心無變，永別憶想忘憂煎。", "虛心無人無我所，任性浮沈如似顛。", "實照常法知無定，知法無性號爲賢。", "行路難，路難非空亦非有。", "有無雙遺兩俱存，俱存無遺亦無受。"]'),
('c515d624-5a17-45b6-8eb2-4b672c542101','行路難二十篇（幷序） 第十六章明魔怨','傅翕','唐','唐诗','tang','','[]','君不見大道寂寞叵思尋，通融萬象盡皆深。',142,'全唐诗/poet.tang.57000.json','["君不見大道寂寞叵思尋，通融萬象盡皆深。", "一切恬然無起滅，顛倒分別併從心。", "智者求心無處所，茫然絶相離貪活。", "了了分明何所見，猶如病眼覩空針。", "若人體知顛倒想，不爲妄苦所浦沈。", "世間諸法如陽焰，行者慎莫致怨嫌。", "恒以空心而照，無上佛道亦能任。", "行路難，路難微妙實無雙。", "若識六情空非有，衆魔結賊自然降。"]'),
('f01c3850-484d-4a4b-baaa-babb193d9ace','行路難二十篇（幷序） 第十七章明法性平等','傅翕','唐','唐诗','tang','','[]','君不見法性無知不可說，有漏無漏幷虛通。',127,'全唐诗/poet.tang.57000.json','["君不見法性無知不可說，有漏無漏幷虛通。", "雖復乖差作諸地，尋其本際盡皆同。", "亦復無同可同法，亦不以空持作宗。", "若欲知斯殊妙道，但自窮搜五陰叢。", "如實無來亦無去，亦不的在六情中。", "即是無原真法界，湛然常存無始終。", "行路難，路難苦樂何未央。", "時往西方無量壽，或復託化現東方。"]'),
('52a4c036-db09-4d3f-8d4d-62c1a09e9101','行路難二十篇（幷序） 第十八章明不思議佛母','傅翕','唐','唐诗','tang','','[]','君不見愛欲貪淫諸佛母，諸佛世尊貪欲兒。',159,'全唐诗/poet.tang.57000.json','["君不見愛欲貪淫諸佛母，諸佛世尊貪欲兒。", "從來菩提爲我匠，今使我爲衆匠師。", "昔日千端外求佛，佛在衣中今始知。", "無量癡心本是道，三毒四倒不思議。", "虛妄行慈愍衆苦，不知衆苦是慈悲。", "嗔恚無明最微妙，世間智者不能思。", "昔日辛勤學知見，不知知見自無知。", "四趣三塗悉非有，三障三脫不分離。", "行路難，路難無有俱併忘。", "了知煩惱無生相，即是如來坐道塲。"]'),
('dcdc6269-bb9e-4de0-92a0-3ec5e8614f74','行路難二十篇（幷序） 第十九章明無覺精進','傅翕','唐','唐诗','tang','','[]','君不見正心修行諸佛子，以見非心故不憂。',207,'全唐诗/poet.tang.57000.json','["君不見正心修行諸佛子，以見非心故不憂。", "知心非心意非意，八風傷逼豈懷愁。", "隨風東西無我所，獨脫逍遙不繫舟。", "設使住時終非住，走遍十方而不流。", "不見我時於無我，善哉設性任沈浮。", "世間妄想無真實，吾於此中何所求？", "只用非心覺非學，亦復正修於不修。", "若人不知如此處，不應稱名作比丘。", "爲箇癡心作奴僕，愛結纏之不自由。", "而此更增諸苦惱，永劫長塗三界囚。", "生死相連彌復甚，盼不能得永長休。", "行路難，路難無令過諸念。", "無念之念乃爲真，真念無真還自炎。"]'),
('cbc286bc-0079-474b-97f5-439ab8afc67e','行路難二十篇（幷序） 第二十章明菩提微妙','傅翕','唐','唐诗','tang','','[]','君不見無上菩提最爲近，四大五陰皆深奧。',191,'全唐诗/poet.tang.57000.json','["君不見無上菩提最爲近，四大五陰皆深奧。", "其實清淨妙難知，不悟此心真卒暴。", "和合性中無有實，是故稱爲諸法要。", "於中無妄亦無真，只用無爲作微妙。", "尋其體寂不應言，假爲衆生立名號。", "若知名號即非名，解了衆生知佛教。", "覺知無因之正因，當得無因無果報。", "善達貪愛得無生，無名去來無動搖。", "不見聖果異凡情，分別聖凡還復倒。", "若人無願齊無修，必定當爲世間導。", "行路難，路難非穢亦非淨。", "是非雙泯復還存，泯存叵測見真性。"]'),
('010dc188-bfec-414e-a2c0-653e24bb5abc','行路易十五首 一','傅翕','唐','唐诗','tang','','[]','佛生具一體，生佛本地同。',46,'全唐诗/poet.tang.57000.json','["佛生具一體，生佛本地同。", "觸目皆如此，無心自性中。", "行路易，路易不修行。", "有無心永息，只箇是無生。"]'),
('07f07083-25b9-46a9-8e0c-8e3867cc8854','行路易十五首 二','傅翕','唐','唐诗','tang','','[]','衆生是佛祖，佛是衆生翁。',46,'全唐诗/poet.tang.57000.json','["衆生是佛祖，佛是衆生翁。", "三寶不相離，菩提皆共同。", "行路易，路易真無作。", "持經不動口，坐禪終日臥。"]'),
('63b78f23-0a27-4a49-bec4-76f7781b1623','行路易十五首 三','傅翕','唐','唐诗','tang','','[]','無生無處所，無處是無生。',46,'全唐诗/poet.tang.57000.json','["無生無處所，無處是無生。", "若覓無生處，無生無處生。", "行路易，路易坦然平。", "無心真解脫，自性任縱橫。"]'),
('b498e7d7-f071-44f3-93b1-1b542d161022','行路易十五首 四','傅翕','唐','唐诗','tang','','[]','菩提無處所，無處是菩提。',46,'全唐诗/poet.tang.57000.json','["菩提無處所，無處是菩提。", "若覓菩提處，終身累劫迷。", "行路易，路易真不虛。", "善惡無分別，此則是真如。"]'),
('75d05e17-9477-44de-ae9a-8776c7266455','行路易十五首 五','傅翕','唐','唐诗','tang','','[]','有無皆解脫，累息在無生。',46,'全唐诗/poet.tang.57000.json','["有無皆解脫，累息在無生。", "菩提是顛倒，生死最爲精。", "行路易，路易人莫疑。", "解我如此語，修道不須師。"]'),
('ec893975-33a8-4e52-b2a9-204b678dd29f','行路易十五首 六','傅翕','唐','唐诗','tang','','[]','東山水上浮，西山行不住。',59,'全唐诗/poet.tang.57000.json','["東山水上浮，西山行不住。", "北斗下閻浮，是真解脫處。", "行路易，路易人不識。", "半夜日頭明，不悟真疲劇（《宗鏡錄》卷六作「極」）。"]'),
('2fd40386-22ed-4492-b25a-83320f402ad5','行路易十五首 七','傅翕','唐','唐诗','tang','','[]','猛風不動樹，打鼓不聞聲。',47,'全唐诗/poet.tang.57000.json','["猛風不動樹，打鼓不聞聲。", "日出樹無影，牛從水上行。", "行路易，路易真可憐。", "修道解此意，長伸兩脚眠。", "。"]'),
('2c6d94a7-01c6-4260-94aa-103e63d712b1','行路易十五首 八','傅翕','唐','唐诗','tang','','[]','佛心與衆生，是三終不移。',46,'全唐诗/poet.tang.57000.json','["佛心與衆生，是三終不移。", "虛空合真理，人我在無爲。", "行路易，路易真難測。", "寄語行路人，大應須努力。"]'),
('9473415d-ebcf-4a15-af15-1d04b47381c2','行路易十五首 九','傅翕','唐','唐诗','tang','','[]','人道行路難，我道行路易。',46,'全唐诗/poet.tang.57000.json','["人道行路難，我道行路易。", "入山十二年，長伸兩脚睡。", "行路易，路易莫思量。", "剎那心不二，終日是天堂。"]'),
('2cf6638a-0d28-48d1-aae2-0503c54c112f','行路易十五首 十','傅翕','唐','唐诗','tang','','[]','須彌芥子父，芥子須彌爺。',46,'全唐诗/poet.tang.57000.json','["須彌芥子父，芥子須彌爺。", "山海平坦地，燒冰將煮茶。", "行路易，路易真寂寞。", "菩提在心中，世人元不覺。"]'),
('5189585a-3078-4cc5-80e7-bd6e29ac820a','行路易十五首 十一','傅翕','唐','唐诗','tang','','[]','有無來去心永息，內外中間心總無。',54,'全唐诗/poet.tang.57000.json','["有無來去心永息，內外中間心總無。", "欲覓如來真佛處，但看石牛生象兒。", "行路易，路易須及早。", "不用學多聞，無言真是道。"]'),
('5913146c-d7f6-4b53-a318-f18861456349','行路易十五首 十二','傅翕','唐','唐诗','tang','','[]','無明是無作，無作是無心。',46,'全唐诗/poet.tang.57000.json','["無明是無作，無作是無心。", "若見無心處，楊花水底沈。", "行路易，路易真無得。", "講說千般論，不如少時默。"]'),
('91b309c0-59b1-4feb-a656-2c26466d40f2','行路易十五首 十三','傅翕','唐','唐诗','tang','','[]','無情正是道，木石盡真如。',46,'全唐诗/poet.tang.57000.json','["無情正是道，木石盡真如。", "達時遍處是，不悟永乖疎。", "行路易，路易真可樂。", "剎那登正覺，不用披三教。"]'),
('d480d67a-2acb-4d10-8385-866af9a1d80f','行路易十五首 十四','傅翕','唐','唐诗','tang','','[]','無心真無事，無事少人知。',46,'全唐诗/poet.tang.57000.json','["無心真無事，無事少人知。", "無爲無處所。", "無處是無爲。", "行路易，路易人莫驚。", "無有無爲事，空有無爲名。"]'),
('c2830202-93c5-4b8b-a748-abcc00e8b915','行路易十五首 十五','傅翕','唐','唐诗','tang','','[]','無我無人真出家，何須剃髮染袈裟。',54,'全唐诗/poet.tang.57000.json','["無我無人真出家，何須剃髮染袈裟。", "欲識逍遙真解脫，但看水牛生象牙。", "行路易，路易君諦聽。", "無覺無菩提，無垢亦無淨。"]'),
('2a50a2b7-d54f-453d-b259-d6d3e13d9d5f','率題六章 第一章歎佇歸珠至今獲','傅翕','唐','唐诗','tang','','[]','攜明是今日，感應在明陽。',96,'全唐诗/poet.tang.57000.json','["攜明是今日，感應在明陽。", "想思深洞盡，企子實難當。", "朝憶生眷戀，夕望動心傷。", "若期靈樹下，度脫不相忘。", "忍見孤憔悴，惧願普趨蹡。", "雙飛白日頂，出氣紫雲光。", "神龍左右梵，散花來芬芳。", "菲菲常樂境，藹藹昇金堂。"]'),
('15afc83f-e4ae-414b-bc9a-d1fd5995f6b4','率題六章 第二章歎高遂背元志','傅翕','唐','唐诗','tang','','[]','近背天宮樂，念苦暫羈斯。',60,'全唐诗/poet.tang.57000.json','["近背天宮樂，念苦暫羈斯。", "舒散金來抱，流緇布交知。", "唯仰相隨善，依令使忘疲。", "同登八位境，共樂寶蓮池。", "肉身變金體，妙果遂衆奇。"]'),
('8945cc58-8eda-421c-8734-ebc06c409d06','率題六章 第三章勸修無上道','傅翕','唐','唐诗','tang','','[]','改緇素容轉，體淨得金蘭。',36,'全唐诗/poet.tang.57000.json','["改緇素容轉，體淨得金蘭。", "從修無上道，常樂自然完。", "拂拭明珠瑩，光發遍界看。"]'),
('df52f424-287f-49fa-9d18-b50f0beb0b06','率題六章 第四章歎世人不厭苦任自纏嬰','傅翕','唐','唐诗','tang','','[]','肯入七寶車，寧歸地獄所。',60,'全唐诗/poet.tang.57000.json','["肯入七寶車，寧歸地獄所。", "刀山已傷形，劍樹方應處。", "日更痛難當，年年無暫弭。", "流洩三塗中，憔悴玉容毀。", "不聽余今訓，爾時仙步阻。"]'),
('128c8b6d-244b-409f-a444-0baba7f5a568','率題六章 第五章勸請仁賢背苦就樂','傅翕','唐','唐诗','tang','','[]','願子從爲善，名價身爲呈。',48,'全唐诗/poet.tang.57000.json','["願子從爲善，名價身爲呈。", "諸天散花下，飛梵來相迎。", "同昇珍寶殿，處處皆光明。", "共居常樂境，齊悅證無生。"]'),
('1fcb1c55-39b0-46fb-b135-6e95fbd92ef6','率題六章 第六章勸同趣至真解因緣縛','傅翕','唐','唐诗','tang','','[]','唯願趣真道，研慮蕩衆緣。',24,'全唐诗/poet.tang.57000.json','["唯願趣真道，研慮蕩衆緣。", "累盡超妙國，逍遙無畏天。"]'),
('86c6c249-3a23-4405-839c-4cc311cae26b','有沙門問大士那不出家答曰不敢住家不敢出家爾時又爲東鄉侯率題二章略說理要云','傅翕','唐','唐诗','tang','','[]','脫中如不如，縛中莫如相。',48,'全唐诗/poet.tang.57000.json','["脫中如不如，縛中莫如相。", "乃會三菩提，如如等無上。", "法相並無雙，恒乖未曾各。", "沈浮隨不隨，搖漾泊無泊。"]'),
('e9501aec-a407-4ec4-bb2d-50707cca6896','勸諭詩三首 一','傅翕','唐','唐诗','tang','','[]','持戒如天日，能明本有軀。',48,'全唐诗/poet.tang.57000.json','["持戒如天日，能明本有軀。", "照見家中寶，兼聞額上珠。", "直超三有海，徑到薩雲衢。", "並會等無等，齊證拘無拘。"]'),
('744b59dd-ce4a-4fa2-b21f-37ca12a858a7','勸諭詩三首 二','傅翕','唐','唐诗','tang','','[]','破戒如船浛，沒溺大江海。',72,'全唐诗/poet.tang.57000.json','["破戒如船浛，沒溺大江海。", "臨窮方喚佛，志操不能改。", "命如風中燈，迅滅寧相待。", "身死罪猶存，牽向司鼻門。", "千苦俱時至，萬痛切神魂。", "獨嬰燒煑炙，困劇事難論。"]'),
('9e3e02f2-a4a5-4064-b437-f4046981115b','勸諭詩三首 三','傅翕','唐','唐诗','tang','','[]','修空截三有，精進作醫王。',48,'全唐诗/poet.tang.57000.json','["修空截三有，精進作醫王。", "共弘調御法，甘雨注無方。", "澤潤羣生等，慧解悉芬芳。", "普會三菩室，齊證真如房。"]'),
('1df250fc-4bde-46de-8bd6-c89bf46b9f02','率題兩章 一','傅翕','唐','唐诗','tang','','[]','罷世還本源，離有絕名相。',24,'全唐诗/poet.tang.57000.json','["罷世還本源，離有絕名相。", "栖神不二境，體一上無上。"]'),
('d8ff4204-9735-4e68-b6e4-9af145fe97d8','率題兩章 二','傅翕','唐','唐诗','tang','','[]','性狎無彼此，心由不去歸。',55,'全唐诗/poet.tang.57000.json','["性狎無彼此，心由不去歸。", "逍遙空寂苑，悅竟境忘依。", "（以上均見《傅大士語錄》〖復日大學圖書館藏清佚名校本〗卷三）。"]'),
('7dfeb827-d061-465f-9347-fcbf11423f12','三諫歌','傅翕','唐','唐诗','tang','','[]','捨世榮，捨世榮華道理長。',328,'全唐诗/poet.tang.57000.json','["捨世榮，捨世榮華道理長。", "努力殷勤學三諫，諫我身心還本鄉。", "諫意意根莫令起，諫口口根莫說彰。", "諫手手根莫鞭杖，三諫三王王自香。", "（此間似脫一句）虛空自得到仙堂。", "仙堂不近亦不遠，徘徊只是衆中央。", "若欲行住仙堂裏，不用匍匐在他鄉。", "若欲求念彌陀佛，東西南北是西方。", "西方彌陀觸處是，面前背後七重行。", "或黃或赤或紅白，或大或小或短長。", "天蓋正是彌陀屋，木孔木穿彌陀房。", "天上空中彌陀路，草木正是彌陀鄉。", "日夜前後嘈嘈閙，正是彌陀口放光。", "若欲禮拜彌陀佛，不用思想強干忙。", "若不誑人是禮拜，若不求人是道場。", "努力自使三功作，殷勤肆力種衣糧。", "山河是家無盡藏，草木是人常滿倉。", "泥水是人常滿庫，藤蘿是人無底囊。", "多作功夫自成就，自行手脚熟嚴裝。", "若欲往生安樂國，只是箇物是西方。", "（見《宗鏡錄》卷二九）。"]'),
('863deda9-8806-4fa9-b38c-fbcdad2ce0ee','歌','傅翕','唐','唐诗','tang','','[]','諸佛村鄉在世界，四海三田遍滿生。',229,'全唐诗/poet.tang.57000.json','["諸佛村鄉在世界，四海三田遍滿生。", "佛共衆生同一體，衆生是佛之假名。", "若欲見佛看三郡，田宅園林處處停。", "或飛虛空中擾擾，或擲山水口轟轟。", "或結羣朋往來去，或復孤單而獨行。", "或使白日東西走，或使暗夜巡五更。", "或烏或赤而復白，或紫或黑而黃青。", "或大或小而新養，或老或少舊時生。", "或身腰上有燈火，或羽翼上有琴箏。", "或游虛空亂上下，或在草石亂縱橫。", "或無言行自出宅，或入土抗暫寄生。", "或攅木孔爲鄉貫，或遍草木或窠城。", "或轉羅網爲樹巷，或臥土石作階廳。", "諸佛菩薩家如是，只箇名爲舍衛城。", "（同前）。"]'),
('d2789bde-e9e7-4a23-b03b-aae284e4f7c1','頌 一','傅翕','唐','唐诗','tang','','[]','佛亦不離心，心亦不離佛。',56,'全唐诗/poet.tang.57000.json','["佛亦不離心，心亦不離佛。", "心寂即涅槃，心能即有物。", "物則變成魔，無物即見佛。", "若能如是用，十八從何出？", "（同前卷十九）。"]'),
('f8eb220a-7455-4c53-9482-6b8455a3de92','頌 二','傅翕','唐','唐诗','tang','','[]','能知此心無隔礙，生死虛妄不能覊。',40,'全唐诗/poet.tang.57000.json','["能知此心無隔礙，生死虛妄不能覊。", "而此一心皆悉具，八萬四千諸律儀。", "（同前卷二九）。"]'),
('e1ac9f66-72e1-4718-b937-c96706aa590f','頌 三','傅翕','唐','唐诗','tang','','[]','凡地修聖道，果地習凡因。',24,'全唐诗/poet.tang.57000.json','["凡地修聖道，果地習凡因。", "恒行無所踐，常度無度人。"]'),
('15573ae8-5eb8-48b9-89a5-0c6f7256ec05','大乘讚十首 一','寶誌','唐','唐诗','tang','','[]','大道常在目前，雖在目前難覩。',154,'全唐诗/poet.tang.57000.json','["大道常在目前，雖在目前難覩。", "若欲悟道真體，莫除色聲言語。", "言語即是大道，不假斷除煩惱。", "煩惱本來空寂，妄情遞相纏繞。", "一切如影如響，不知何惡何好。", "有心取相爲寶，定知見性不了。", "若欲作業求佛，業是生死大兆。", "生死業常隨身，黑闇獄中未曉。", "悟理本來無異，覺後誰晚誰早。", "法界量同太虛，衆生智心自小。", "但能不起吾我，湼槃法食常飽。"]'),
('0bd1ae9d-d808-406e-8d03-edc6a6c13892','大乘讚十首 二','寶誌','唐','唐诗','tang','','[]','妄身臨鏡照影，影與妄身不殊。',182,'全唐诗/poet.tang.57000.json','["妄身臨鏡照影，影與妄身不殊。", "但欲去影留身，不知身本同虛。", "身本與影不異，不得一有一無。", "若欲存一捨一，永與真理相踈。", "更若愛聖憎凡，生死海裏沉浮。", "煩惱因心有故，無心煩惱何居？", "不勞分別取相，自然得道須臾。", "夢時夢中造作，覺時覺境都無。", "飜思覺時與夢，顛倒二見不殊。", "改迷取覺求利，何異販賣商徒？", "動靜兩亡常寂，自然契合真如。", "若言衆生異佛，迢迢與佛常踈。", "佛與衆生不二，自然究竟無餘。"]'),
('72935e51-8062-4370-8ae2-c9d4dd35a61e','大乘讚十首 三','寶誌','唐','唐诗','tang','','[]','法性本來常寂，蕩蕩無有邊畔。',98,'全唐诗/poet.tang.57000.json','["法性本來常寂，蕩蕩無有邊畔。", "安心取捨之閒，被他二境迴換。", "斂容入定坐禪，攝境安心覺觀。", "機關木人修道，何時得達彼岸？", "諸法本空無著，境似浮雲會散。", "忽悟本性元空，恰似熱病得汗。", "無智人前莫說，打你色身星散。"]'),
('05c1aea0-7cbb-4fe9-a31d-566002d75a3d','大乘讚十首 四','寶誌','唐','唐诗','tang','','[]','報你衆生直道，非有即是非無。',140,'全唐诗/poet.tang.57000.json','["報你衆生直道，非有即是非無。", "非有非無不二，何須對有論虛？", "有無妄心立號，一破一個不居。", "兩名由爾情作，無情即本真如。", "若欲存情覔佛，將網山上羅魚。", "徒費功夫無益，幾許枉用功夫。", "不解即心即佛，真似騎驢覔驢。", "一切不憎不愛，遮個煩惱須除。", "除之則須除身，除身無佛無因。", "無佛無因可得，自然無法無人。"]'),
('68ad4c1f-baab-4dd4-80c9-7e5400c82f1e','大乘讚十首 五','寶誌','唐','唐诗','tang','','[]','大道不由行得，說行權爲凡愚。',112,'全唐诗/poet.tang.57000.json','["大道不由行得，說行權爲凡愚。", "得理返觀於行，始知枉用功夫。", "未悟圓通大理，要須言行相扶。", "不得執他知解，迴光返本全無。", "有誰解會此說，教君向己推求。", "自見昔時罪過，除却五欲瘡疣。", "解脫逍遙自在，隨方賤賣風流。", "誰是發心買者，亦得似我無憂。"]'),
('008bfa52-d369-4ed2-8515-6b0b68f108c9','大乘讚十首 六','寶誌','唐','唐诗','tang','','[]','內見外見緫惡，佛道魔道俱錯。',140,'全唐诗/poet.tang.57000.json','["內見外見緫惡，佛道魔道俱錯。", "被此二大波旬，便即厭苦求樂。", "生死悟本體空，佛魔何處安著？", "只由妄情分別，前身後身孤薄。", "輪迴六道不停，結業不能除却。", "所以流浪生死，皆由橫生經略。", "身本虛無不實，返本是誰斟酌？", "有無我自能爲，不勞妄心卜度。", "衆生身同太虛，煩惱何處安著？", "但無一切希求，煩惱自然消落。"]'),
('da356ae5-1a5c-4058-9863-a41295d7e0df','大乘讚十首 七','寶誌','唐','唐诗','tang','','[]','可笑衆生蠢蠢，各執一般異見。',98,'全唐诗/poet.tang.57000.json','["可笑衆生蠢蠢，各執一般異見。", "但欲傍鏊求餅，不岇返本觀麵。", "麵是正邪之本，由人造作百變。", "所須任意縱橫，不假偏耽愛戀。", "無著即是解脫，有求又遭羅罥。", "慈心一切平等，真如菩提自現。", "若懷彼我二心，對面不見佛面。"]'),
('7c9ff872-8e5c-4a85-be75-f25e489b7270','大乘讚十首 八','寶誌','唐','唐诗','tang','','[]','世間幾許癡人，將道復欲求道。',140,'全唐诗/poet.tang.57000.json','["世間幾許癡人，將道復欲求道。", "廣尋諸義紛紜，自救己身不了。", "專尋他文亂說，自稱至理妙好。", "徒勞一生虛過，永劫沈淪生老。", "濁愛纏心不捨，清淨智心自惱。", "真如法界叢林，返作荆棘荒草。", "但執黃葉爲金，不悟棄金求寶。", "所以失念狂走，強力裝持相好。", "口內誦經誦論，心裏尋常枯槁。", "一朝覺本心空，具足真如不少。"]'),
('7348ad7c-d750-48e2-b972-96e86acdc972','大乘讚十首 九','寶誌','唐','唐诗','tang','','[]','聲聞心心斷惑，能斷之心是賊。',154,'全唐诗/poet.tang.57000.json','["聲聞心心斷惑，能斷之心是賊。", "賊賊遞相除遣，何時了本語默。", "口內誦經千卷，體上問經不識。", "不解佛法圓通，徒勞尋行數黑。", "頭陁阿練苦行，希望後身功德。", "希望即是隔聖，大道何由可得？", "譬如夢裏度河，船師度過河北。", "忽覺牀上安眠，失却度船軌則。", "船師及彼度人，兩個本不相識。", "衆生迷倒羇絆，往來三界疲極。", "覺悟生死如夢，一切求心自息。"]'),
('d080ac51-82fb-48d2-8ab3-ee4457ee3dc7','大乘讚十首 十','寶誌','唐','唐诗','tang','','[]','悟解即是菩提，了本無有階梯。',140,'全唐诗/poet.tang.57000.json','["悟解即是菩提，了本無有階梯。", "堪嘆凡夫軀僂，八十不能跋蹄。", "徒勞一生虛過，不覺日月遷移。", "向上看他師口，恰似失妳孩兒。", "道俗崢嶸聚集，終日聽他死語。", "不觀己身無常，心行貪如狼虎。", "堪嗟二乘狹劣，要須摧伏六府。", "不食酒肉五辛，邪眼看他飲咀。", "更有邪行猖狂，修氣不食鹽醋。", "若悟上科至真，不假分別男女。"]'),
('5c283829-3dc4-44e2-93f4-2ed4eb8fafb6','十二時頌 一','寶誌','唐','唐诗','tang','','[]','平旦寅，狂機內有道人身。',60,'全唐诗/poet.tang.57000.json','["平旦寅，狂機內有道人身。", "窮苦已經無量劫，不信常擎如意珍。", "若捉物，入迷津，但有纖豪即是塵。", "不住舊時無相貌，外求知識也非真。"]'),
('cec8b549-1448-460b-972c-89bf1d1d11c4','十二時頌 二','寶誌','唐','唐诗','tang','','[]','日出卯，用處不須生善巧。',44,'全唐诗/poet.tang.57000.json','["日出卯，用處不須生善巧。", "縱使神光照有無，起意便遭魔事撓。", "若施功，終不了，日夜被他人我拗。"]'),
('eeb139bc-1e62-4204-862d-84410c8624be','十二時頌 三','寶誌','唐','唐诗','tang','','[]','食時辰，無明本是釋迦身。',61,'全唐诗/poet.tang.57000.json','["食時辰，無明本是釋迦身。", "坐臥不知元是道，只麽忙忙受苦辛。", "認聲色，不覔踈親，只是他家染污人。", "若擬將心求佛道，問取虛空始出塵。"]'),
('51fff32f-5e38-4c28-8c62-eea52830da87','十二時頌 四','寶誌','唐','唐诗','tang','','[]','禺中巳，未了之人教不至。',60,'全唐诗/poet.tang.57000.json','["禺中巳，未了之人教不至。", "假使通達祖師言，莫向心頭安了義。", "只守玄，沒文字，認著依前還不是。", "暫時自肯不追尋，曠劫不遭魔境使。"]'),
('b97d85b9-d12d-4727-b9c9-1ae7c8f22d16','十二時頌 五','寶誌','唐','唐诗','tang','','[]','日南午，四大身中無價寶。',60,'全唐诗/poet.tang.57000.json','["日南午，四大身中無價寶。", "陽焰空華不肯拋，作意修行轉辛苦。", "不曾迷，莫求悟，任你朝陽幾迴暮。", "有相身中無相身，無明路上無生路。"]'),
('6a773625-c9a4-4660-985c-c47cc68c893e','十二時頌 六','寶誌','唐','唐诗','tang','','[]','日昳未，心地何曾安了義？',116,'全唐诗/poet.tang.57000.json','["日昳未，心地何曾安了義？", "他家文字沒親踈，莫起功夫求的意。", "任縱橫，絕忌諱，長在人間不居止。", "運用不離聲色中，歷劫何曾暫拋棄？", "（《宗鏡錄》卷十五引此首，「沒」作「有」，「居止」作「居世」，「不離」作「元來」，末句作「凡夫不了爭爲計」。", "）。"]'),
('388b6043-a9d1-4ecd-9061-4e442f26ed14','十二時頌 七','寶誌','唐','唐诗','tang','','[]','晡時申，學道先須不厭貧。',75,'全唐诗/poet.tang.57000.json','["晡時申，學道先須不厭貧。", "有相本來權積聚，無形何用要安真。", "作淨潔，却勞神，莫認愚癡作近鄰。", "言下不求無處所，暫時喚作出家人。", "（《宗鏡錄》卷二四引末二句）。"]'),
('ab5c1575-0c06-4325-8a07-7651ace4d8f7','十二時頌 八','寶誌','唐','唐诗','tang','','[]','日入酉，虛幻聲音終不久。',60,'全唐诗/poet.tang.57000.json','["日入酉，虛幻聲音終不久。", "禪悅珍羞尚不飱，誰能更飲無明酒。", "沒可拋，無物守，蕩蕩逍遙不曾有。", "縱你多聞達古今，也是癡狂外邊走。"]'),
('f424e6b1-0fca-47b8-88ff-40a6273fc55f','十二時頌 九','寶誌','唐','唐诗','tang','','[]','黃昏戌，狂子興功投暗室。',60,'全唐诗/poet.tang.57000.json','["黃昏戌，狂子興功投暗室。", "假使心通無量時，歷劫何曾異今日。", "擬商量，却啾唧，轉使心頭黑如漆。", "畫夜舒光照有無，癡人喚作波羅蜜。"]'),
('e8d27b05-6a19-4da4-9b92-9c14a3b17464','十二時頌 十','寶誌','唐','唐诗','tang','','[]','人定亥，勇猛精進成懈怠。',60,'全唐诗/poet.tang.57000.json','["人定亥，勇猛精進成懈怠。", "不起纖豪修學心，無相光中常自在。", "超釋迦，越祖代，心有微塵還窒閡。", "廓然無事頓清閑，他家自有通人愛。"]'),
('fda2719e-2688-4dac-a4cf-3ea5c8e2728e','十二時頌 十一','寶誌','唐','唐诗','tang','','[]','夜半子，心住無生即生死。',98,'全唐诗/poet.tang.57000.json','["夜半子，心住無生即生死。", "生死何曾屬有無，用時便用沒文字。", "祖師言，外邊事，識取起時還不是。", "作意搜求實沒蹤，生死魔來任相試。", "（《宗鏡錄》卷二九引末五句，「識取起時」作「取著元來」，「沒」作「勿」。", "）。"]'),
('27b18a9d-355e-4e6b-a612-8abb9d55b789','十二時頌 十二','寶誌','唐','唐诗','tang','','[]','雞鳴丑，一顆圓珠明已久。',61,'全唐诗/poet.tang.57000.json','["雞鳴丑，一顆圓珠明已久。", "內外推尋覔揔無，境上施爲渾大有。", "不見頭，又無手，世界壞時終不朽。", "未了之人聽一言，只遮如今誰動口。", "。"]'),
('e198497a-644a-485d-977d-f45ec6c9811f','十四科頭 菩提煩惱不二','寶誌','唐','唐诗','tang','','[]','衆生不解修道，便欲斷除煩惱。',98,'全唐诗/poet.tang.57000.json','["衆生不解修道，便欲斷除煩惱。", "煩惱本來空寂，將道更欲覔道。", "一念之心即是，何須別處尋討。", "大道曉在目前，迷倒愚人不了。", "佛性天真自然，亦無因緣修造。", "不識三毒虛假，妄執浮沈生老。", "昔時迷日爲晚，今日始覺非早。"]'),
('7e608dfa-2be9-4342-9370-12866b93613a','十四科頭 持犯不二','寶誌','唐','唐诗','tang','','[]','丈夫運用無礙，不爲戒律所制。',144,'全唐诗/poet.tang.57000.json','["丈夫運用無礙，不爲戒律所制。", "持犯本自無生，愚人被他禁繫。", "智者造作皆空，互聞觸途爲滯。", "大士肉眼圓通，二科天眼有翳。", "空中妄執有無，不達色心無礙。", "菩薩與俗同居，清淨曾無染世。", "愚人貪著湼槃，智者生死實際。", "法性空無言說，緣起略無些子。", "百歲無智小兒，小兒有智百歲。", "（《宗鏡錄》卷八十引「大士」二句）。"]'),
('15580aff-d1b8-4998-877e-798b941d50a8','十四科頭 佛與衆生不二','寶誌','唐','唐诗','tang','','[]','衆生與佛無殊，大智不異於愚。',84,'全唐诗/poet.tang.57000.json','["衆生與佛無殊，大智不異於愚。", "何須向外求寶，身田自有明珠。", "正道邪道不二，了知凡聖同途。", "迷悟本無差別，湼槃生死一如。", "究竟攀緣空寂，惟求意想清虛。", "無有一法可得，翛然自入無餘。"]'),
('27df5d4e-e4fe-4449-b3e4-c057f4666417','十四科頭 事理不二','寶誌','唐','唐诗','tang','','[]','心王自在翛然，法性本無十纏。',98,'全唐诗/poet.tang.57000.json','["心王自在翛然，法性本無十纏。", "一切無非佛事，何須攝念坐禪。", "妄想本來空寂，不用斷除攀緣。", "智者無心口得，自然無爭無喧。", "不識無爲大道，何時得證幽玄。", "佛與衆生一種，衆生即是世尊。", "凡夫妄生分別，無中執有迷奔。"]'),
('073fcf37-b487-41c1-8148-a65779023be8','十四科頭 靜亂不二','寶誌','唐','唐诗','tang','','[]','聲聞厭喧求靜，猶如棄麵求餅。',98,'全唐诗/poet.tang.57000.json','["聲聞厭喧求靜，猶如棄麵求餅。", "餅即從來是麵，造作隨人百變。", "煩惱即是菩提，無心即是無境。", "生死不異湼槃，貪嗔如焰如影。", "智者無心求佛，愚人執邪執正。", "徒勞空過一生，不見如來妙頂。", "了達淫慾性空。", "鑊湯鑪炭自冷。"]'),
('4fd6dc96-7d1c-4595-a9df-c08550aeb99a','十四科頭 善惡不二','寶誌','唐','唐诗','tang','','[]','我自身心快樂，翛然無善無惡。',127,'全唐诗/poet.tang.57000.json','["我自身心快樂，翛然無善無惡。", "法身自在無方，觸目無非正覺。", "六塵本來空寂，凡夫妄生執著。", "湼槃生死太平，四海阿誰厚薄？", "無爲大道自然，不用將心畫度。", "故菩薩散誕靈通，所作常含妙覺。", "聲聞執法坐禪，如蠶吐絲自縛。", "法性本來圓明，病愈何須執藥。", "了知諸法平等，翛然清虛快樂。"]'),
('25a4c2b0-4d93-4246-9c61-822ee22184f0','十四科頭 色空不二','寶誌','唐','唐诗','tang','','[]','法性本無青黃，衆生謾造六神。',140,'全唐诗/poet.tang.57000.json','["法性本無青黃，衆生謾造六神。", "吾我說他止觀，自意擾擾顛狂。", "不識圓通妙理，何時得會真常？", "自疾不能治療，却教他人藥方。", "外看將爲是善。", "心內猶若豺狼。", "愚人畏其地獄，智者不異天堂。", "對境心常不起，舉足皆是道場。", "佛與衆生不二，衆生自作分張。", "若欲除却三毒，迢迢不離災殃。", "智者知心是佛，愚人樂往西方。"]'),
('89301de0-9ced-41d7-8187-8acc3942fdca','十四科頭 生死不二','寶誌','唐','唐诗','tang','','[]','世間諸法如幻，生死猶若雷電。',154,'全唐诗/poet.tang.57000.json','["世間諸法如幻，生死猶若雷電。", "法身自在圓通，出人山河無間。", "顛倒妄想本空，般若無迷無亂。", "三毒本自解脫，何須攝念禪觀。", "只爲愚人不了，從地戒律決斷。", "不識寂滅真如，何時得登彼岸？", "智者無惡可斷，運用隨心合散。", "法性本來空寂，不爲生死所絆。", "若欲斷除煩惱，此是無明癡漢。", "煩惱即是菩提，何用別求禪觀？", "實際無佛無魔，心體無形無段。"]'),
('3f3f3894-08d6-4630-885c-9e2c3f478e20','十四科頭 斷除不二','寶誌','唐','唐诗','tang','','[]','丈夫運用堂堂，逍遙自在無妨。',210,'全唐诗/poet.tang.57000.json','["丈夫運用堂堂，逍遙自在無妨。", "一切不能爲害，堅固猶若金剛。", "不著二邊中道，翛然非斷非常。", "五欲貪嗔是佛，地獄不異天堂。", "愚人妄生分別，流浪生死猖狂。", "智者達色無礙，聲聞無不恛惶。", "法性本無瑕翳，衆生妄執青黃。", "如來引接迷愚，或說地獄天堂。", "彌勒身中自有，何須別處思量。", "棄却真如佛像，此人即是顛狂。", "聲聞心中不了，唯只趁逐言章。", "言章本非真道，轉加鬭爭剛強。", "心裏蚖蛇蝮蝎，螫著便即遭傷。", "不解文中取義，何時得會真常？", "死入無間地獄，神識枉受災殃。"]'),
('b18771cf-e490-4fb9-b44f-aaeb7e2f1fe2','十四科頭 真俗不二','寶誌','唐','唐诗','tang','','[]','法師說法極好，心中不離煩惱。',111,'全唐诗/poet.tang.57000.json','["法師說法極好，心中不離煩惱。", "口談文字化他，轉更增他生老。", "真妄本來不二，凡夫棄妄覔道。", "四衆雲集聽講，高座論義浩浩。", "南座北座相爭，四衆爲言爲好。", "雖然口談甘露，心裏尋常燥。", "自己元無一錢，日夜數他珍寶。", "恰似無智愚人，棄却真金擔草。"]'),
('1c515906-08ae-4daa-8f26-d3d02d098db4','十四科頭 解縛不二','寶誌','唐','唐诗','tang','','[]','律師持律自縛，自縛亦能縛他。',140,'全唐诗/poet.tang.57000.json','["律師持律自縛，自縛亦能縛他。", "外作威儀恬靜，心內恰似洪波。", "不駕生死船筏，如何度得愛河？", "不解真宗正理，邪見言辭繁多。", "有二比丘犯律，便却往問優波。", "優波依律說罪，轉增比丘網羅。", "方丈室中居士，維摩便即來呵。", "優波默然無對，淨名說法無過。", "而彼戒性如空，不在內外娑婆。", "勸除生滅不肯，忽悟還同釋迦。"]'),
('5b752ffa-470e-4944-876f-630851d556f0','十四科頭 境照不二','寶誌','唐','唐诗','tang','','[]','禪師體離無明，煩惱從何處生？',112,'全唐诗/poet.tang.57000.json','["禪師體離無明，煩惱從何處生？", "地獄天堂一相，湼槃生死空名。", "齊無貪嗔可斷，亦無佛道可成。", "衆生與佛平等，自然聖智惺惺。", "不爲六塵所染，句句獨契無生。", "正覺一念玄解，三世坦然皆平。", "非法非律自制，翛然真入圓成。", "絶此四句百非，如空無作無依。"]'),
('624376b9-44ac-455e-9ec3-32dc9b20ee6b','十四科頭 運用無礙','寶誌','唐','唐诗','tang','','[]','我今滔滔自在，不羨公王卿宰。',84,'全唐诗/poet.tang.57000.json','["我今滔滔自在，不羨公王卿宰。", "四時猶若金剛，昔樂今常不改。", "法寶喻於須彌，智慧廣於澎湃。", "不爲八風所牽，亦無精進懈怠。", "任性浮沈若顛，散誕蹤橫自在。", "遮莫刀劒臨頭，我自安然不采。"]'),
('9b8ee60b-7d87-4295-bb8c-69c80ded9987','十四科頭 迷悟不二','寶誌','唐','唐诗','tang','','[]','迷時以空爲色，悟即以色爲空。',115,'全唐诗/poet.tang.57000.json','["迷時以空爲色，悟即以色爲空。", "迷悟本無差別，色空究竟還同。", "愚人喚南作北，智者達無西東。", "欲覓如來妙理，常在一念之中。", "陽焰本非其水，渴鹿狂趁忩忩。", "自身虛假不實，將空更欲覓空。", "世人迷倒至甚，如犬吠雷叿叿。", "（以上皆見《景德傳燈錄》卷二九）。"]'),
('4908c8e4-721e-4331-bed8-d45bbc7e2f55','偈','寶誌','唐','唐诗','tang','','[]','頓悟心源開寶藏，隱顯靈蹤現真相。',91,'全唐诗/poet.tang.57000.json','["頓悟心源開寶藏，隱顯靈蹤現真相。", "獨行獨坐常巍巍，百億化身無數量。", "縱令畐塞滿虛空，看時不見微塵相。", "可笑物空無比況，口吐明珠光晃晃。", "尋常見說不思議，一語標宗言下當。", "（《宗鏡錄》卷九八）。"]'),
('3265ffd9-7c96-47f9-bc82-72bb97b6bc2e','預言 一','寶誌','唐','唐诗','tang','','["\u9ec4\u6cb3"]','五馬從南來，燕趙起三災。',171,'全唐诗/poet.tang.57000.json','["五馬從南來，燕趙起三災。", "□□勤修善，得見化城開。", "兔子亂三州，萬惡自然收。", "東弱西強阿誰愁，欲得世燕南頭。", "武安川裏白鷄鳴，百姓遼亂心不寧。", "四月八日起鬼兵，冀州城東起長城。", "爾來君士面奄青，五月十日滅你名。", "冀州城頭君子遊，折尾苟子亂中州，欲得避世黃河頭。", "今年天下是亂世，但勤修善自防身。", "得安樂，無憂愁，不肯看經心羅錯。", "天下遼亂真可留，若得盡門斬賊頭。"]'),
('56fb19b2-e8e9-4c7e-b7e9-35a7df5410a0','預言 二','寶誌','唐','唐诗','tang','','[]','四月八日游，鬭鷄臺上樗蒲盧。',85,'全唐诗/poet.tang.57000.json','["四月八日游，鬭鷄臺上樗蒲盧。", "正見笑，兵不輸，阻雉正見喚兵人人死室粟麥無□□犢合河北脫却角白血五之間遼亂推搭，聖人之間天運迎。", "（此篇首有「寶公曰」三字。", "中間一段難以點斷）。"]'),
('7b72bfa4-ba4f-48b3-a017-96d502924e1b','預言 三','寶誌','唐','唐诗','tang','','[]','禿人今日已定，不須卜於長安。',29,'全唐诗/poet.tang.57000.json','["禿人今日已定，不須卜於長安。", "天坐住汝男津，百官大會千斤肫。"]'),
('4f1c02bf-0a45-47b3-9e58-902c61b813db','預言 四','寶誌','唐','唐诗','tang','','[]','一斗穀夜餉，一疋絹二丈，丁車大牛西南上。',393,'全唐诗/poet.tang.57000.json','["一斗穀夜餉，一疋絹二丈，丁車大牛西南上。", "若不信吾語，看先烏東飛，雉北走，空虛匡上見猪狗。", "□□□□□□□，日無光，月無影，星辰遼亂入（下缺）。", "（以上皆見《沙州文錄》，原題《寶公預言》，據上虞羅氏藏敦煌殘卷。", "）（按：寶誌詩，《先秦漢魏晉南北朝詩·梁詩》卷三僅據《南史》、《隋書》收讖詩四則，漏收二則，即《洛陽伽藍記》所載：「大竹箭，不需羽。", "東箱屋，急手作。", "」《南史》卷六三《王神念傳》載其天臨中讖：「太歲龍，將無理。", "蕭經霜，草應死。", "餘人散，十八子。", "」本書前錄諸詩偈讖言，是否出於唐前，無從確定。", "如其《十二時》，《洛陽伽藍記》稱寶公「造《十二辰歌》」，但其真僞，今人頗有爭論，多傾向於非六朝時之作。", "〖詳參王重民《敦煌遺書論文集》附錄〗但前錄諸作，即出依託，至遲亦應爲五代以前的作品，故錄收於此。", "另《太平廣記》卷一六三引《劉賓客嘉話錄》引「兩角女子」讖一則，《全唐詩》卷八七五已收，不重錄。", "）。"]'),
('21a736b9-2ee8-40c9-8207-0c0a95355b2c','讖 一','菩提達摩','唐','唐诗','tang','','[]','路行跨水復逢羊，（路行者，來也。',263,'全唐诗/poet.tang.57000.json','["路行跨水復逢羊，（路行者，來也。", "跨水者，過海也。", "稱逢羊者，洛陽也。", "達摩大師從南天竺國過海而來，初到廣州，次普通八年丁未歲人梁國）獨自恓恓（《天聖廣燈錄》、《五燈會元》作「栖栖」）暗渡江。", "（獨自者，無伴侶也。", "恓恓者，苦恓也。", "暗渡江者，梁武帝不悟大理，變容不言。", "師知機不契，則潛過江向北魏國也。", "）日下可憐雙象馬，（日下者，京都也。", "可憐者，好。", "雙象馬者，志公傳大士也。", "）兩株懶桂（《天聖廣燈錄》、《五燈會元》作「二株嫩桂」）久昌昌。", "（兩株者，二木也，二木是林字也。", "嫩桂者，少也。", "則是少林寺也。", "久昌昌者，九年面壁，而出大行佛法也。", "）。"]'),
('4a5373c2-2509-4546-b42c-4635bea1ae98','讖 二','菩提達摩','唐','唐诗','tang','','[]','心中雖吉外頭凶，（心中者，周字也。',159,'全唐诗/poet.tang.57000.json','["心中雖吉外頭凶，（心中者，周字也。", "外頭凶者，周王無道滅佛法也）川下僧房名不中。", "（川下僧房者，俗號僧房爲邑，川下邑爲邕字也。", "後周文帝〖陳按：應作武帝〗姓字文，名泰邕。", "不中者，後周沙汰滅佛法。", "）爲遇毒龍生武子，（毒龍者，武帝父王也。", "生武子者，生武帝也）忽逢小鼠寂無窮。", "（小鼠者，庚子也。", "周武帝庚子崩。", "寂無窮者，盡滅無也）。"]'),
('62b0465c-a40c-439c-8ed1-3e639a9eac4a','讖 三','菩提達摩','唐','唐诗','tang','','[]','路上忽逢深處水，（路上者，李字也。',328,'全唐诗/poet.tang.57000.json','["路上忽逢深處水，（路上者，李字也。", "深水者，淵字也。", "唐高祖神堯皇帝姓李名淵也）等閑見虎又逢猪。", "（等閑見虎者，寅也，唐高祖戊寅年登位也。", "又逢猪者，亥也，高祖丁亥年崩）小小牛兒雖有角，（小小牛兒者，高祖武德四年九月日，有前道士太史令傳奕，先是黃巾黨其所習，遂上表廢佛法事十有一條。", "大略而云：釋經是損國破家，未聞益世，請胡佛邪教退還天竺，凡是沙門放歸桑梓，則國家昌泰，李孔教行矣。", "高祖納奕奏書，乃下詔問諸沙門曰：「棄父母鬚髭，去君臣花服，利在何間，益在何情？", "損益二宜，請動妙釋。", "」時有琳法師，上表得延五年。", "高祖崩，太宗登位，再興佛法矣。", "具如別傳。", "言半角者，正當挃觸，而無害即是）清溪龍出總須輸。", "清溪者，山名也。", "龍者，琳法師護法之龍，能令傳奕等邪見之徒總須伏也。", "）。"]'),
('0131c30b-8a3c-4c82-aafb-c9205da8df5f','讖 四','菩提達摩','唐','唐诗','tang','','[]','震旦雖闊無別路，（震旦者，唐國也。',216,'全唐诗/poet.tang.57000.json','["震旦雖闊無別路，（震旦者，唐國也。", "無別路者，唯有一心之法，讓大師化導如此也。", "）要假姪（《古尊宿語錄》、《五燈會元》作「兒」）孫脚下（《天聖廣燈錄》作「上」）行。", "（姪孫者，今時傳法弟子也）金雞解銜一顆米（《古尊宿語錄》、《五燈會元》作「一粒粟」，金雞者，金州也，讓師是金州人也。", "一顆米者，意取道一，江西馬祖名道一。", "）供養十方（《古尊宿語錄》）作「什邡」）羅漢僧。", "（讓和尚付與道一，故言供養。", "十方者，馬和尚是漢州十方縣羅漢寺出家也。", "）。"]'),
('707d69d9-9e28-4c17-8dfe-b97e05956111','讖 五','菩提達摩','唐','唐诗','tang','','[]','尊勝今藏古，（尊勝者，妙智也。',172,'全唐诗/poet.tang.57000.json','["尊勝今藏古，（尊勝者，妙智也。", "古者，可大師，本有妙高之性，性被煩惱覆之，未現了，故言藏也。", "）無肱亦（《天聖廣燈錄》作「又」）有肱。", "（肱者，手也，可大師求法斷臂也。", "）龍來方受（《天聖廣燈錄》作「授」）寶，（龍來者，初祖西來也。", "方受寶者，二傳法。", "）捧物復（《天聖廣燈錄》作「奉物伏」）嫌名。", "（捧者，惠也。", "本名神光，復過達摩，嫌之，改名言爲惠可。", "）。"]'),
('6adb4800-ac46-4db2-a39b-1f0a9b5fab26','讖 六','菩提達摩','唐','唐诗','tang','','[]','初首不稱名，（後周第三主己卯之歲，有一居士，不稱姓名，故言不稱名）風狂又有聲。',119,'全唐诗/poet.tang.57000.json','["初首不稱名，（後周第三主己卯之歲，有一居士，不稱姓名，故言不稱名）風狂又有聲。", "（風狂者，三祖有風病。", "有聲者，遠近皆知有病，故言有聲也。", "）人來不喜見，（人來不喜見，患風之形狀）白寶初平平。", "（白寶者，玉也。", "玉邊作祭，璨字也。", "三祖名璨大師。", "）。"]'),
('a02c6219-0247-456c-86a7-a89fccf2d921','讖 七','菩提達摩','唐','唐诗','tang','','[]','起自求無（《天聖廣燈錄》作「不」）碍，（有一沙彌，年十四，名道信，來禮拜問：「唯願和尚，教某甲解脫法門。',154,'全唐诗/poet.tang.57000.json','["起自求無（《天聖廣燈錄》作「不」）碍，（有一沙彌，年十四，名道信，來禮拜問：「唯願和尚，教某甲解脫法門。", "」故言求無碍）師傅我沒繩。", "（師者，三通也。", "我沒繩者，既無人縛汝，即是解脫）路上逢僧禮，（路上者，道也。", "禮者，信也。", "四祖大師名道信）脚下六枝分。", "（脚下者，門下也。", "四祖下橫出一宗，六枝者，牛頭融禪師等六祖）。"]'),
('7f4edd0f-ff45-4a38-9c02-28a532562ac8','讖 八','菩提達摩','唐','唐诗','tang','','[]','三四全無我，（三四者，七也。',109,'全唐诗/poet.tang.57000.json','["三四全無我，（三四者，七也。", "五祖七歲遇道信大師，無人我出家也）隔水受心燈。", "（隔水者，五祖於蘄州蘄水得傳四祖心印，故言受心燈。", "）尊號過諸量，（過量者，弘字也）逢嗔不起曾（《天聖廣燈錄》作「從嗔不起增」。", "不起者，忍字也）。"]'),
('3941802a-6574-41ed-8061-3e2a6f5a3ba0','讖 九','菩提達摩','唐','唐诗','tang','','[]','捧（《天聖廣燈錄》作「奉」）物何曾捧，（捧者，惠字）言懃又不懃。',290,'全唐诗/poet.tang.57000.json','["捧（《天聖廣燈錄》作「奉」）物何曾捧，（捧者，惠字）言懃又不懃。", "（懃者，能也。", "六祖名能）唯書四句偈，（唯書四句偈者，神秀和尚呈四句偈，□能和尚亦呈四句偈，故言四句偈）將（《天聖廣燈錄》作「爲」）對瑞田人。", "（瑞田人者，神秀和尚南陽嘉禾縣瑞田人）心裏能藏事，（能藏者懷，則懷信也）說向漢江濱。", "（說向者，說法也。", "漢江濱者，馬大師漢州人也。", "馬大師求佛心印，讓和尚說向道一也）湖波探水月，（湖波者，曹溪也。", "探水月者，得也。", "讓大師於六祖身邊得傳心印）將照二三人。", "（二三者，六。", "讓大師傳法弟子六人，言六人者，一道一得心，二智遠得眼，三常浩得眉，四神照得鼻，五坦然得耳，六嚴峻得耳，是爲六人也）。"]'),
('9a3c2e56-9703-44ea-89fd-193b381fbde1','讖 十','菩提達摩','唐','唐诗','tang','','[]','領得[彌勒]（珍勤）（從《天聖廣燈錄》改）語，（領得者，馬大師於讓大師處領語也）離鄉日日敷。',195,'全唐诗/poet.tang.57000.json','["領得[彌勒]（珍勤）（從《天聖廣燈錄》改）語，（領得者，馬大師於讓大師處領語也）離鄉日日敷。", "（離鄉者，南方也。", "日日者，昌字也。", "敷者，演也。", "馬大師歸至洪州南昌寺，敷演大教是也）移梁來（《天聖廣燈錄》作「來梁移」）近路，（移梁者，梁都也。", "近路者，深州觀察使姓路，遂請大師自虔州南康縣，移入洪州開元寺，故言來近路）余算脚天徒。", "（余者，我字也。", "從馬大師二十年外，契道者千萬，遍行天下，故言脚天徒）。"]'),
('412cdf1c-72cc-4697-8edb-2d0d555f97dc','讖 十一','菩提達摩','唐','唐诗','tang','','[]','艮地生玄旨，（艮地者，東北也。',148,'全唐诗/poet.tang.57000.json','["艮地生玄旨，（艮地者，東北也。", "神秀和尚從五祖下傳一枝法，在北自爲立宗旨也）通尊媚亦尊。", "（通尊者，謚號大通禪師也。", "媚者，秀也。", "亦尊者，三帝所尊敬，故亦尊也）比肩三九（《天聖廣燈錄》作「吼」）族，（比肩者，同學也。", "三九族者，十二人也。", "秀大師同學十二人）足下一有分。", "（從秀和尚足下各分宗旨，南北有異）。"]'),
('ab09ee3d-4568-43c9-8d55-011f6f616ba3','讖 十二','菩提達摩','唐','唐诗','tang','','[]','靈集媿天恩，（靈者，神。',211,'全唐诗/poet.tang.57000.json','["靈集媿天恩，（靈者，神。", "集者，會也。", "媿者，荷也。", "天恩者，澤也。", "神會大師住洛京荷澤寺）生{牙丿=丶}二六人。", "（生{牙丿=丶}者，師資也。", "二六者，會大師弟子十二人也）法中無氣味，（法中者，佛法也。", "會大師傳佛知見，甚深法也。", "無氣味者，緣北宗秀大師弟子普寂，於京盛行，通其經教。", "當此之時，曹溪宗旨，於彼未而行，故言無氣味也）石上有功勳。", "（石上者，秀大師弟子，磨却南宗碑，神秀欲爲六代，何其天之不從，乃得會大師重立實錄，故有功勳）。"]'),
('c145f6ac-d13b-4175-8a5e-1dd39b8f857f','讖 十三','菩提達摩','唐','唐诗','tang','','[]','本是大蟲勇，（印宗法師本是小乘，喻如大蟲，不是師子）迴（《天聖廣燈錄》作「翻」）成師子談。',141,'全唐诗/poet.tang.57000.json','["本是大蟲勇，（印宗法師本是小乘，喻如大蟲，不是師子）迴（《天聖廣燈錄》作「翻」）成師子談。", "（迴者，傳也。", "迴小作大，印宗法師禮六祖便悟上乘，是成師子吼）官家封馬嶺，（封者，印也。", "馬嶺者，宗也。", "印宗曾爲講經法師也）同詳三十三。", "（同詳者，同學也。", "六祖弟子祥岑等三十三人，祥禪師住於峽山）。"]'),
('dad958aa-3e94-4300-9495-21691b214772','讖 十四','菩提達摩','唐','唐诗','tang','','[]','八（《天聖廣燈錄》作「九」）女出人倫，（八女者，安字也。',167,'全唐诗/poet.tang.57000.json','["八（《天聖廣燈錄》作「九」）女出人倫，（八女者，安字也。", "出人倫者，爲國師也。", "）八箇絕婚姻。", "（個箇者，安字。", "絕婚姻者，安徒難爲紹繼之）杇床（《天聖廣燈錄》作「將」）添六脚，（杇床者，老字也。", "六脚者，則天、中宗，騰騰坦然圓寂，百五十五年住世，破竈墮和尚六住嵩山，是爲六脚也）心祖衆中尊。", "（心祖者，姓也。", "安和尚頓悟禪理爲國師，故衆中尊也）。"]'),
('7a99a4ae-a07a-4ac5-8a32-b3e363b6a64f','讖 十五','菩提達摩','唐','唐诗','tang','','[]','走戊與朝鄰，（走戊者，越字，忠國師是越州人也。',126,'全唐诗/poet.tang.57000.json','["走戊與朝鄰，（走戊者，越字，忠國師是越州人也。", "與朝鄰者，爲國師）鵝烏子出身。", "（鵝者，鵝州也，今越州是。", "烏者，鳴鶴縣也，今諸暨縣是，國師生此縣也）二天雖有感，（二天者，肅宗、代宗二帝也。", "有感者，帝禮爲師也）三化寂無塵。", "（三化寂無塵者，二帝與國師俱寂也）。"]'),
('cedbcd1e-ef76-404d-84e9-ad02c0afb413','讖 十六','菩提達摩','唐','唐诗','tang','','[]','說小何曾小（《天聖廣燈錄》作「說少何曾少」，希字是也）言流又不流。',132,'全唐诗/poet.tang.57000.json','["說小何曾小（《天聖廣燈錄》作「說少何曾少」，希字是也）言流又不流。", "（遷字是也）草若除其首，（石頭無草）三四繼門修。", "（傳法弟子人數，準其傳法人數，應云十七繼門修也。", "○以上十七首，均見《祖堂集》卷二。", "《五燈會元》卷一錄其一、其二、其四三首。", "《古尊宿語錄》卷一引二首）。"]'),
('ef055837-558d-4f08-af0a-c5b72c5ed4f8','讖 十七','菩提達摩','唐','唐诗','tang','','[]','八月商尊飛有聲，巨福來羣（《天聖廣燈錄》作「祥」）鳥不驚。',59,'全唐诗/poet.tang.57000.json','["八月商尊飛有聲，巨福來羣（《天聖廣燈錄》作「祥」）鳥不驚。", "懷抱一鷄來赴（《天聖廣燈錄》作「重起」）會，手把龍蛇在兩楹。"]'),
('2306a7eb-8c7f-4fcb-b65c-6247c12f98c0','讖 十八','菩提達摩','唐','唐诗','tang','','[]','寄公席[帽]（脫）（從《天聖廣燈錄》改）權時脫，蚊子之蟲慚小（《天聖廣燈錄》作「足去」）形。',76,'全唐诗/poet.tang.57000.json','["寄公席[帽]（脫）（從《天聖廣燈錄》改）權時脫，蚊子之蟲慚小（《天聖廣燈錄》作「足去」）形。", "東海象歸披右服（《天聖廣燈錄》作「石脹」），二處蒙恩總不輕。"]'),
('1804d776-fc19-4b6c-a1fa-135cb1390bae','讖 十九','菩提達摩','唐','唐诗','tang','','[]','日月幷行君（《天聖廣燈錄》作「若」）不動，即無冠子上山行。',45,'全唐诗/poet.tang.57000.json','["日月幷行君（《天聖廣燈錄》作「若」）不動，即無冠子上山行。", "更惠一峯添翠岫，玉教人識始知名。"]'),
('ec8f2545-295b-4df9-bfba-9ec50dadf563','讖 二十','菩提達摩','唐','唐诗','tang','','[]','高峰（《天聖廣燈錄》作「嶺」）逢人又脫衣，小蛇雖毒不能爲。',103,'全唐诗/poet.tang.57000.json','["高峰（《天聖廣燈錄》作「嶺」）逢人又脫衣，小蛇雖毒不能爲。", "可中井底看（《天聖廣燈錄》作「着」）天近，小是沙彌善大機。", "大浪雖高不足知，百年凡木長乾枝。", "一鳥南飛却歸北，二人東往却（《天聖廣燈錄》作「復」）還西。"]'),
('f652893d-7934-403e-b2db-cf2c896f27ff','讖 二十一','菩提達摩','唐','唐诗','tang','','[]','可憐明月獨當天，四箇龍兒各自遷。',32,'全唐诗/poet.tang.57000.json','["可憐明月獨當天，四箇龍兒各自遷。", "東西南北奔波去，日頭平上照無邊。"]'),
('e0d18f30-9148-4d79-8c47-f01b864415cc','讖 二十二','菩提達摩','唐','唐诗','tang','','["\u8861\u5c71"]','鳥來上高堂欲興（《天聖廣燈錄》作「驚」），白雲入地色還青。',388,'全唐诗/poet.tang.57000.json','["鳥來上高堂欲興（《天聖廣燈錄》作「驚」），白雲入地色還青。", "天上金龍日月明，東陽海水清不清。", "首捧朱（《天聖廣燈錄》作「珠」）輪重復輕，雖無心眼轉惺惺（《天聖廣燈錄》作「醒醒」）。", "不見（《天聖廣燈錄》作「具」）耳目善觀聽，身體元無空有形。", "不說姓字但驗（《天聖廣燈錄》作「籤」）名，意尋書卷錯開（《天聖廣燈錄》作「看」）經。", "口談（《天聖廣燈錄》作「說」）恩幸心無情，或去或來身不停。", "（以上七首見《卍續藏經》本《祖庭事苑》卷八，原注：「未見注八首。", "」「路上忽逢深處水」一首已見《祖堂集》。", "《天聖廣燈錄》卷六收二十三首，缺「初首不稱名」一首，各首均無注）（按：以上諸讖，云爲菩提達磨所作，顯爲依托。", "其作者，應爲南宗禪僧，較大的可能爲南嶽懷讓、馬祖道一一系的禪僧。", "諸讖中所述事，以石頭希遷、馬祖道一爲最遲，因知作者應爲德宗以後人。", "《祖堂集》成書於南唐間，諸讖僞托之下限，疑不遲於唐末。", "）。"]'),
('e7735c90-b3e9-428a-b956-6e41b7a6c598','付法頌','菩提達摩','唐','唐诗','tang','','[]','吾本來唐國（《景德傳燈錄》作「茲土」），傳教（《景德傳燈錄》作「法」）救迷情。',101,'全唐诗/poet.tang.57000.json','["吾本來唐國（《景德傳燈錄》作「茲土」），傳教（《景德傳燈錄》作「法」）救迷情。", "一花開五葉，結果自然成。", "（《南宗頓教最上大乘摩訶般若波羅密經六祖慧能大師於韶州大梵寺施法壇經》）（按：此首亦出唐人依託。", "）。"]'),
('2b7fc8cc-92b9-4071-b316-3395b4c6b1be','黑兒賦','朱彥時','唐','唐诗','tang','','[]','世有非常人，實惟彼玄士。',244,'全唐诗/poet.tang.57000.json','["世有非常人，實惟彼玄士。", "稟茲至緇色，內外皆相似。", "臥如驪[馬]（牛）（司義祖校記云：「似應作『驪馬』」。", "今從《事文類聚》改）𩥇，立似烏牛跱。", "忿如鸜鵒鬭，樂似鸕鷀喜。", "（下缺。", "見中華書局校排本《初學記》卷十九。", "宋祝穆《事文類聚後集》卷十八作「朱彥時賦黑兒詩」）（按：彥時時代不明，要爲開元前人。", "《新唐書·宰相世系表》有朱彥時，約中唐人，非是。", "嚴可均輯《先唐文》收入彥時此篇及劉思真《醜婦賦》，並無確據。", "王重民先生《敦煌變文研究》〖刊《中華文史論叢》一九八一年第二輯〗以爲初唐時作，或得其實。", "）。"]'),
('3529d886-454b-44cd-adb6-24c31bd82609','寶金篇','徐成','唐','唐诗','tang','','[]','三十二相眼爲先，次觀頭面要方圓。',320,'全唐诗/poet.tang.57000.json','["三十二相眼爲先，次觀頭面要方圓。", "相馬不看先代本，一似愚人信口傳。", "眼似垂鈴紫色鮮，滿廂凸出不驚然。", "白縷貫晴行五百，斑如撒豆勿同看。", "面若側墼如鐮背，鼻如金盞可藏拳。", "口叉須深牙齒遠，舌如垂劍色如蓮。", "口無黑黶須長命，唇似垂廂蓋一般。", "食槽寬淨顋無肉，咽尖平而筋有攔。", "耳如楊葉裁杉竹，嚥骨高而軟不堅。", "八肉分而彎左右，龍會高在上古傳。", "項長如鳳須彎曲，鬃毛茸細要如綿。", "鬐高膊濶搶風小，臆高胸濶脚前寬。", "膝要高而圓似椈，骨細筋麄節要攢。", "蹄要圓實須卓立，身形棄闡要平寬。", "筋骨彎而須堅密，排鞍肉厚穩金鞍。", "三峯穩壓須藏骨，臥如猿落重如山。", "鵝鼻曲直須停穩，尾似流星散不連。", "膏筋大小須勻壯，下節攢筋緊一錢。", "羊髭有距如雞距，能奔解走可行千。", "已前貴相三十二，萬中難選一俱全。"]'),
('51714459-b0b0-4fa2-af10-920c59be3a29','寶金歌','徐成','唐','唐诗','tang','','[]','三十二相眼爲珍，次觀頭面要停勻。',400,'全唐诗/poet.tang.57000.json','["三十二相眼爲珍，次觀頭面要停勻。", "相馬不看先代本，亦似盲人信步行。", "眼似垂鈴紫色浸，睛如徹豆要分明。", "白縷貫晴行五百，瞳生五彩壽多齡。", "鼻紋有字須長壽，如火如公四十春。", "壽旋頂門高過眼，鬃毛茸細萬絲分。", "面如剝兔腮無肉，鼻如金盞食槽橫。", "耳如楊葉根一握，頂長如鳳似雞鳴。", "口叉須深牙齒遠，舌如垂劍色蓮形。", "口無黑靨須長命，唇似垂箱兩合停。", "四大三高兼二小，雙長兩短一灣平。", "瘦見肉而肥見骨，視而不懼聽無驚。", "八肉彎而分耳後，龍會高而上古聞。", "牝騮不欲偏多驟，驊驂蹄嚙善能奔。", "首鈎項曲三峯穩，筋麄骨細四蹄輕。", "鬐高臆廣平弓手，胸寬膊濶小搶風，頭長腰短雙鳧大，腹垂臁小逆毛生。", "踠停寸緊蹄堅實，膝高節近骨筋分。", "肋骨彎而須緊密，排鞍肉厚穩鞍輪。", "腎代小藏如吊殻，裏囊垂大若懸鈴。", "燕骨隱微三山小，胯似琵琶後犬蹲。", "尾似流星須放細，鵝鼻曲直汗溝深。", "骨筋大小須勻壯，身形棄闡要寬平。", "已上毛骨皆是駿，還將駑逸細推尋。", "腰凹脊弓焉致遠，麄蹄捺踠豈能奔。"]'),
('1de3e99b-3726-4ba3-85fe-01d7a6888898','王良百一歌 略相 一','徐成','唐','唐诗','tang','','[]','耳小根一握，頭長鼻要寬。',24,'全唐诗/poet.tang.57000.json','["耳小根一握，頭長鼻要寬。", "能行三百里，解立四蹄攢。"]'),
('b69f6004-2e2d-41e3-98ce-4f57568cd280','王良百一歌 略相 二','徐成','唐','唐诗','tang','','[]','臆前雖濶備，眼曠腹須平。',24,'全唐诗/poet.tang.57000.json','["臆前雖濶備，眼曠腹須平。", "項長筋骨促，尾骨短爲精。"]'),
('f5992961-c420-47c6-9a09-cd023cde8097','王良百一歌 略相 三','徐成','唐','唐诗','tang','','[]','鹿耳天然快，獐頭第一強。',24,'全唐诗/poet.tang.57000.json','["鹿耳天然快，獐頭第一強。", "蹄輕腰又短，伯樂亦稱良。"]'),
('8abf892e-01dd-4a24-9f0b-a1212df6b561','王良百一歌 略相 四','徐成','唐','唐诗','tang','','[]','鼻上紋王字，目中青暈侵。',24,'全唐诗/poet.tang.57000.json','["鼻上紋王字，目中青暈侵。", "雖然有筋骨，更要汗溝深。"]'),
('75d1cdbc-36e6-4968-b8f9-16b3012be156','王良百一歌 略相 五','徐成','唐','唐诗','tang','','[]','初生無毛者，伯樂號龍駒。',24,'全唐诗/poet.tang.57000.json','["初生無毛者，伯樂號龍駒。", "七朝方始起，千匹也應無。"]'),
('043cfa29-1433-4dfd-ac54-7fdb96203a58','王良百一歌 略相 六','徐成','唐','唐诗','tang','','[]','近者雖似小，遠望却成高。',24,'全唐诗/poet.tang.57000.json','["近者雖似小，遠望却成高。", "要知深有力，腹上逆生毛。"]'),
('4af0a2c4-6d1b-4617-beb6-66f7fcbb846a','王良百一歌 略相 七','徐成','唐','唐诗','tang','','[]','蹄大蹄又軟，腹濶更腰長。',25,'全唐诗/poet.tang.57000.json','["蹄大蹄又軟，腹濶更腰長。", "行時無步驟，何必問孫陽。", "。"]'),
('9618b0b6-d79a-4fb7-9c58-87443790764b','王良百一歌 略相 八','徐成','唐','唐诗','tang','','[]','口淺不能食，眼深多咬人。',24,'全唐诗/poet.tang.57000.json','["口淺不能食，眼深多咬人。", "猪膝難任重，焉堪致遠行。"]'),
('9b0a5cc3-0c60-47b9-bb8a-c93d44f1ead8','王良百一歌 略相 九','徐成','唐','唐诗','tang','','[]','要知有壽馬，唇慢口方停。',24,'全唐诗/poet.tang.57000.json','["要知有壽馬，唇慢口方停。", "好是如羊目，驆良壽亦長。"]'),
('32b5c61f-73e0-4dda-a54f-0f39378c59fe','王良百一歌 略相 十','徐成','唐','唐诗','tang','','[]','不在如龍狀，追風號古來。',24,'全唐诗/poet.tang.57000.json','["不在如龍狀，追風號古來。", "目前毛骨駿，未可比駑駘。"]'),
('ed6946d1-c246-4b8d-96fa-2c43238c4846','王良百一歌 毛病 一','徐成','唐','唐诗','tang','','[]','項上如生旋，有之不用誇。',24,'全唐诗/poet.tang.57000.json','["項上如生旋，有之不用誇。", "環緣不利長，金以號螣蛇。"]'),
('e424f822-a3b4-4e22-aa02-634a0492c07c','王良百一歌 毛病 二','徐成','唐','唐诗','tang','','[]','後有喪門旋，前兼有挾屍。',24,'全唐诗/poet.tang.57000.json','["後有喪門旋，前兼有挾屍。", "即君不用蓄，無事亦須疑。"]'),
('9fd90799-fef7-45bd-9620-6fe241b00182','王良百一歌 毛病 三','徐成','唐','唐诗','tang','','[]','牛額並銜禍，非常害長多。',24,'全唐诗/poet.tang.57000.json','["牛額並銜禍，非常害長多。", "古人如是說，比事不須歌。"]'),
('d77e880f-7143-4a03-81b9-b1004bce1b95','王良百一歌 毛病 四','徐成','唐','唐诗','tang','','[]','帶劍渾小事，喪門不可當。',24,'全唐诗/poet.tang.57000.json','["帶劍渾小事，喪門不可當。", "滴淚如入口，有福也須防。"]'),
('72fb02c0-8e23-4a15-826d-60e9fa207e99','王良百一歌 毛病 五','徐成','唐','唐诗','tang','','[]','黑色耳金白，從來號孝頭。',24,'全唐诗/poet.tang.57000.json','["黑色耳金白，從來號孝頭。", "假饒千里走，奉勸不須留。"]'),
('6155ebdc-e45e-45c4-bb4f-474f813ac7b4','王良百一歌 毛病 六','徐成','唐','唐诗','tang','','[]','背上毛生旋，驢騾亦有之。',24,'全唐诗/poet.tang.57000.json','["背上毛生旋，驢騾亦有之。", "只惟鞍貼下，比者是駞屍。"]'),
('6d869fae-eccf-4521-bea5-da8f197f69c3','王良百一歌 毛病 七','徐成','唐','唐诗','tang','','[]','銜禍口邊衝，時間禍必逢。',24,'全唐诗/poet.tang.57000.json','["銜禍口邊衝，時間禍必逢。", "古人稱是病，焉敢不言凶。"]'),
('f0e41276-9b6d-4439-94e5-74896af30f24','王良百一歌 毛病 八','徐成','唐','唐诗','tang','','[]','眼下毛生旋，遙看似淚痕。',24,'全唐诗/poet.tang.57000.json','["眼下毛生旋，遙看似淚痕。", "假饒福也病，無禍亦妨人。"]'),
('eaa26ae1-0607-4481-916c-e672b8d406a1','王良百一歌 毛病 九','徐成','唐','唐诗','tang','','[]','毛病深知害，妨人在不占。',24,'全唐诗/poet.tang.57000.json','["毛病深知害，妨人在不占。", "大都如此類，無禍也宜嫌。"]'),
('9fa9c19d-1c6a-4475-8bcf-f1160651e70d','王良百一歌 毛病 十','徐成','唐','唐诗','tang','','[]','擔耳駞鬃項，雖然毛病殊。',24,'全唐诗/poet.tang.57000.json','["擔耳駞鬃項，雖然毛病殊。", "更若兼鰲尾，有實不如無。"]'),
('89366072-7de9-42e6-a57b-a4f54eab9474','王良百一歌 雜忌 一','徐成','唐','唐诗','tang','','[]','騎來未得飲，汗解是爲強。',25,'全唐诗/poet.tang.57000.json','["騎來未得飲，汗解是爲強。", "卸鞍面向北，此事最招殃。", "。"]'),
('1e3eb187-7ac2-4941-abca-cef64b4a1364','王良百一歌 雜忌 二','徐成','唐','唐诗','tang','','[]','欲出須知此，籠頭莫掛垂。',24,'全唐诗/poet.tang.57000.json','["欲出須知此，籠頭莫掛垂。", "雖然無大患，驚懼事防爲。"]'),
('e828b6aa-6fa8-45cf-a8e7-2d005cb31736','王良百一歌 雜忌 三','徐成','唐','唐诗','tang','','[]','面北朝朝餧，形軀漸漸傷。',24,'全唐诗/poet.tang.57000.json','["面北朝朝餧，形軀漸漸傷。", "其中忽有患，有患悔難當。"]'),
('bc62e2b1-935c-4a91-a93b-3ac4a1dd0617','王良百一歌 雜忌 四','徐成','唐','唐诗','tang','','[]','遠來亦忌飽，出去不妨饑。',24,'全唐诗/poet.tang.57000.json','["遠來亦忌飽，出去不妨饑。", "向水莫許驟，偏傷肺與脾。"]'),
('0072dc82-8975-4501-a3e4-6e178ff3f8a8','王良百一歌 雜忌 五','徐成','唐','唐诗','tang','','[]','濁水休教飲，多饒毛色焦。',24,'全唐诗/poet.tang.57000.json','["濁水休教飲，多饒毛色焦。", "時間雖不覺，日內不生臕。"]'),
('f892c65f-84eb-4112-a7e9-72abce990c7c','王良百一歌 雜忌 六','徐成','唐','唐诗','tang','','[]','偏怕腥膻物，仍嫌土作槽。',24,'全唐诗/poet.tang.57000.json','["偏怕腥膻物，仍嫌土作槽。", "鼠穿成大穢，更忌艸中毛。"]'),
('fb87dda5-938c-4304-8824-457e952802fc','王良百一歌 雜忌 七','徐成','唐','唐诗','tang','','[]','上山猶許驟，不嶺不宜騎。',24,'全唐诗/poet.tang.57000.json','["上山猶許驟，不嶺不宜騎。", "必定傷筋骨，能令日漸羸。"]'),
