('5e2f50cf-5bec-4368-936c-5496a6474c7a','王良百一歌 療風 十','徐成','唐','唐诗','tang','','[]','有風切忌驚，角耳最爲精。',24,'全唐诗/poet.tang.57000.json','["有風切忌驚，角耳最爲精。", "漢椒並附子，相合耳中傾。"]'),
('2bbea1bd-500a-4b38-a953-69dbda6587e8','王良百一歌 筋骨 一','徐成','唐','唐诗','tang','','[]','膊痛緣騎苦，蹄傷敗血攻。',24,'全唐诗/poet.tang.57000.json','["膊痛緣騎苦，蹄傷敗血攻。", "痛時鍼且妙，蹄損火能通。"]'),
('959876ec-ce4c-40f0-aa1f-aef151bc7f5b','王良百一歌 筋骨 二','徐成','唐','唐诗','tang','','[]','膝骨難任痛，行時脚失多。',24,'全唐诗/poet.tang.57000.json','["膝骨難任痛，行時脚失多。", "無端鍼脈血，得效也蹉跎。"]'),
('3fd967ec-c5b7-452d-b491-ed701cbfff7c','王良百一歌 筋骨 三','徐成','唐','唐诗','tang','','[]','子骨連蹄痛，多應是物傷。',24,'全唐诗/poet.tang.57000.json','["子骨連蹄痛，多應是物傷。", "烙蹄蹄不發，漸漸骨開張。"]'),
('a087378c-7575-43b6-94f4-ee293a3aeec5','王良百一歌 筋骨 四','徐成','唐','唐诗','tang','','[]','失節莫交頻，鹿節黃水成。',24,'全唐诗/poet.tang.57000.json','["失節莫交頻，鹿節黃水成。", "假饒用火烙，滑石鎮長盈。"]'),
('0c377b21-3435-4dcc-81a9-fa0dd26adbe7','王良百一歌 筋骨 五','徐成','唐','唐诗','tang','','[]','但是筋骨痛，皆因傷損爲。',24,'全唐诗/poet.tang.57000.json','["但是筋骨痛，皆因傷損爲。", "於中硯子骨，末後不通醫。"]'),
('de74ac7d-866f-466d-8bcc-d527a325a5aa','王良百一歌 筋骨 六','徐成','唐','唐诗','tang','','[]','食槽脹雖烙，多緣腑病生。',24,'全唐诗/poet.tang.57000.json','["食槽脹雖烙，多緣腑病生。", "胃翻加止沫，何藥效能成。"]'),
('31701e52-5212-4341-9be4-fbede55f3998','王良百一歌 筋骨 七','徐成','唐','唐诗','tang','','[]','小胯骨若痛，牽連雁翅疼。',24,'全唐诗/poet.tang.57000.json','["小胯骨若痛，牽連雁翅疼。", "從鍼須得穴，用藥更持鋒。"]'),
('5fbfcd7c-be87-43cf-b728-65ab1d3349ae','王良百一歌 筋骨 八','徐成','唐','唐诗','tang','','[]','曲池鵝鼻骨，脹時不在鍼。',24,'全唐诗/poet.tang.57000.json','["曲池鵝鼻骨，脹時不在鍼。", "芸臺並紫葛，巴豆最功深。"]'),
('3d7cfb19-bfe0-49b4-a598-1868caf1288d','王良百一歌 筋骨 九','徐成','唐','唐诗','tang','','[]','附骨侵於膝，走驟多饒失。',24,'全唐诗/poet.tang.57000.json','["附骨侵於膝，走驟多饒失。", "火烙意還粗，藥消爲第一。"]'),
('700dbc34-8f7b-45b9-9064-8b2e25e52113','王良百一歌 筋骨 十','徐成','唐','唐诗','tang','','[]','筋脹用猪腦，冷藥用蛇牀。',25,'全唐诗/poet.tang.57000.json','["筋脹用猪腦，冷藥用蛇牀。", "細辛並藁木，米醋及生薑。", "。"]'),
('d5932f85-936b-4915-a1ea-322760fe7b7d','王良百一歌 療黃 一','徐成','唐','唐诗','tang','','[]','頭悶忽啣韁，此即是心黃。',24,'全唐诗/poet.tang.57000.json','["頭悶忽啣韁，此即是心黃。", "先須用火烙，時下得安康。"]'),
('ea91169d-376c-48b0-a598-7321265f38dc','王良百一歌 療黃 二','徐成','唐','唐诗','tang','','[]','胸黃忽腫硬，未可用鍼鍼。',24,'全唐诗/poet.tang.57000.json','["胸黃忽腫硬，未可用鍼鍼。", "須使消黃藥，無令痛所侵。"]'),
('ec61c3ef-a19a-4cd1-88cb-6d34ec9cccca','王良百一歌 療黃 三','徐成','唐','唐诗','tang','','[]','偏次黃雖少，還緣積熱成。',24,'全唐诗/poet.tang.57000.json','["偏次黃雖少，還緣積熱成。", "嘗聞連五臟，根向肺中生。"]'),
('919f7776-d31c-45d9-8ebd-f701dcd1e56a','王良百一歌 療黃 四','徐成','唐','唐诗','tang','','[]','喉內若生黃，此病實難當。',24,'全唐诗/poet.tang.57000.json','["喉內若生黃，此病實難當。", "藥鍼但少效，向裏結成囊。"]'),
('562ad68e-9307-46bc-8235-ff2acb1c237e','王良百一歌 療黃 五','徐成','唐','唐诗','tang','','[]','急慢腸黃候，患時俱一般。',24,'全唐诗/poet.tang.57000.json','["急慢腸黃候，患時俱一般。", "慢時一月多，急則當時間。"]'),
('611f7248-0fa8-4b11-a757-51cbcfa64e61','王良百一歌 療黃 六','徐成','唐','唐诗','tang','','[]','腎黃腎脈腫，積冷致如然。',24,'全唐诗/poet.tang.57000.json','["腎黃腎脈腫，積冷致如然。", "還須熁腰上，以此出頑涎。"]'),
('0cb59d25-e4bf-4d48-b6a7-17e9dd4b111b','王良百一歌 療黃 七','徐成','唐','唐诗','tang','','[]','水黃連帶脈，虛腫在皮膚。',24,'全唐诗/poet.tang.57000.json','["水黃連帶脈，虛腫在皮膚。", "先用火鍼治，消時膿出餘。"]'),
('874e0f98-98c5-4e7e-86a9-50119c7226ba','王良百一歌 療黃 八','徐成','唐','唐诗','tang','','[]','膁黃不用鍼，塗藥妙能深。',24,'全唐诗/poet.tang.57000.json','["膁黃不用鍼，塗藥妙能深。", "涓石並葶藶，橘皮使蔚金。"]'),
('2276c6fe-5210-4043-8ddc-932352d5e257','王良百一歌 療黃 九','徐成','唐','唐诗','tang','','[]','騾馬緣風熱，因此作妳黃。',24,'全唐诗/poet.tang.57000.json','["騾馬緣風熱，因此作妳黃。", "塗藥教駒匝，切恐結成囊。"]'),
('46bd0d68-dbc5-4b66-a531-e53265368475','王良百一歌 療黃 十','徐成','唐','唐诗','tang','','[]','一切黃虛腫，多緣積熱生。',24,'全唐诗/poet.tang.57000.json','["一切黃虛腫，多緣積熱生。", "宜抽喉脉血，諸毒不能成。"]'),
('19c4eafe-10a3-4793-a2dc-3074e8b095d7','王良百一歌 瘡痍 一','徐成','唐','唐诗','tang','','[]','竹節療膊瘡，骨鑽亦難當。',24,'全唐诗/poet.tang.57000.json','["竹節療膊瘡，骨鑽亦難當。", "若塗先用洗，欲使洗鹽湯。"]'),
('0e3b3ec6-2d93-4a9f-bce1-df2e26b7cce3','王良百一歌 瘡痍 二','徐成','唐','唐诗','tang','','[]','貼瘡須用藥，艾炙且令焦。',24,'全唐诗/poet.tang.57000.json','["貼瘡須用藥，艾炙且令焦。", "乾姜將入內，根出始方消。"]'),
('11a6c3fa-3444-4d48-9ae5-a8f01cb05a81','王良百一歌 瘡痍 三','徐成','唐','唐诗','tang','','[]','疳瘡生眼畔，疳血化爲蟲。',24,'全唐诗/poet.tang.57000.json','["疳瘡生眼畔，疳血化爲蟲。", "即漸侵於腦，和睛變作膿。"]'),
('c9f0496c-8501-4c3d-bdaa-269667cbea87','王良百一歌 瘡痍 四','徐成','唐','唐诗','tang','','[]','口內忽生涎，心臟熱如然。',25,'全唐诗/poet.tang.57000.json','["口內忽生涎，心臟熱如然。", "有瘡須用藥，包藥使綿纏。", "。"]'),
('c57a0651-27a5-451f-9216-5d40d515da71','王良百一歌 瘡痍 五','徐成','唐','唐诗','tang','','[]','肺毒若生瘡，醫之要肺涼。',24,'全唐诗/poet.tang.57000.json','["肺毒若生瘡，醫之要肺涼。", "貼藥雖宜洗，可用甘草湯。"]'),
('3b2331dc-0727-462c-a002-733c2cba6628','王良百一歌 瘡痍 六','徐成','唐','唐诗','tang','','[]','斷踠緣風血，燥蹄亦一般。',24,'全唐诗/poet.tang.57000.json','["斷踠緣風血，燥蹄亦一般。", "麝香葶藶子，貫衆及黃丹。"]'),
('4d0c11af-52d3-4895-9018-3a2e546b3110','王良百一歌 瘡痍 七','徐成','唐','唐诗','tang','','[]','冷病緣草結，膿多瘡口寒。',24,'全唐诗/poet.tang.57000.json','["冷病緣草結，膿多瘡口寒。", "乳香幷附子，貼此始應看。"]'),
('7be38a1d-1c6e-4eee-941a-c71ae8b536f3','王良百一歌 瘡痍 八','徐成','唐','唐诗','tang','','[]','疥癬深秋旺，爪瘡盛夏多。',24,'全唐诗/poet.tang.57000.json','["疥癬深秋旺，爪瘡盛夏多。", "都緣風血聚，忙療莫蹉跎。"]'),
('f2acc028-83a0-4cfb-ac02-5e364ef3e564','王良百一歌 瘡痍 九','徐成','唐','唐诗','tang','','[]','血躁連蹄腫，筋風血作膿。',24,'全唐诗/poet.tang.57000.json','["血躁連蹄腫，筋風血作膿。", "蕪荑鶴風妙，能殺此般蟲。"]'),
('701bb829-860d-4b88-b54f-a6733e11a3b2','王良百一歌 瘡痍 十','徐成','唐','唐诗','tang','','[]','一切破損瘡，勿令口自傷。',24,'全唐诗/poet.tang.57000.json','["一切破損瘡，勿令口自傷。", "㿉瘡難治療，客風須是防。"]'),
('9e4ff2a6-30a1-4a77-82a9-48f9bdbcff82','王良百一歌 齒歲 一','徐成','唐','唐诗','tang','','[]','齒有數般蒼，教伊識不妨。',24,'全唐诗/poet.tang.57000.json','["齒有數般蒼，教伊識不妨。", "莫言爲小事，識得大賢良。"]'),
('d5222910-66e0-4dc1-b3d9-f6512576f315','王良百一歌 齒歲 二','徐成','唐','唐诗','tang','','[]','黑白一齊全，生來始八年。',24,'全唐诗/poet.tang.57000.json','["黑白一齊全，生來始八年。", "中間初似破，十二歲無偏。"]'),
('42db40f4-5a08-48aa-82ca-07a6a8b7759c','王良百一歌 齒歲 三','徐成','唐','唐诗','tang','','[]','齒如十二月，𮪃牙象四時。',24,'全唐诗/poet.tang.57000.json','["齒如十二月，𮪃牙象四時。", "二十四氣足，伯樂視爲規。"]'),
('7bc562ff-3230-4dd0-8441-de65c3142459','王良百一歌 齒歲 四','徐成','唐','唐诗','tang','','[]','四齒不曾退，年已只似駒。',24,'全唐诗/poet.tang.57000.json','["四齒不曾退，年已只似駒。", "但看邊畔者，咬得臼還殊。"]'),
('37a57e4a-870a-440e-823f-563ff15c2093','王良百一歌 齒歲 五','徐成','唐','唐诗','tang','','[]','向南馬齒口，野放咬山多。',24,'全唐诗/poet.tang.57000.json','["向南馬齒口，野放咬山多。", "區臼雖先破，莫言齒歲過。"]'),
('7d97365e-0e91-4a20-b139-26b5f9292588','王良百一歌 齒歲 六','徐成','唐','唐诗','tang','','[]','黃區將欲盡，黑白以全無。',24,'全唐诗/poet.tang.57000.json','["黃區將欲盡，黑白以全無。", "上下齒更展，十二歲應餘。"]'),
('a5b2d4b5-b251-469b-8a78-e946cd340e8a','王良百一歌 齒歲 七','徐成','唐','唐诗','tang','','[]','𮪃牙初出肉，俗言五六春。',479,'全唐诗/poet.tang.57000.json','["𮪃牙初出肉，俗言五六春。", "至老或不生，須憑區臼真。", "（以上均見宛委山堂本《說郛》弓一○七徐成《相馬書》）（〖1〗《舊唐書·經籍志》子部農家類著錄：「《相馬經》，又二卷，徐成等撰。", "」）（〖2〗《新唐書·藝文志》子部農家類著錄：「徐成等《相馬經》二卷。", "」〖3〗《太平御覽》卷八九六引《伯樂相馬經》云：「江淮津督徐成字子長，兄弟蒙寵於府君，治馬方以報，千金不傳，號《淮津方》。", "」〖4〗今人王毓瑚《中國農學書錄》云：「據現有的線索推測，〖徐成〗極可能是唐代人。", "《說郛》收的有一種徐咸的《相馬書》，『咸』、『成』二字字形相近，或者就是此書。", "」今按：《鄭堂讀書記補逸》謂徐咸爲宋人，今人編《中國叢書綜錄》從之。", "核以文獻，尚無明證。", "《說郛》收此書於陸龜蒙《耒耜經》、傅肱《蟹譜》之間，卷首署「代郡徐咸」，不言時代。", "「代郡」非宋時地名。", "兩《唐志》既已著錄此書，其時代當在開元以前。", "《伯樂相馬經》見載於《隋書·經籍志》五行類，《舊唐志》錄此書於隋諸葛穎之前，據此二證，頗疑成爲隋前人。", "但《隋志》不錄此書，至《舊唐志》始見收，終不能排除其爲唐人的可能性。", "今收入先宋詩，以俟考定。", "）。"]'),
('cd8715e4-abc8-4c5b-897b-f692d7c26561','還丹歌','陰真君','唐','唐诗','tang','','[]','北方正氣爲河車，東方甲乙爲金砂。',313,'全唐诗/poet.tang.57000.json','["北方正氣爲河車，東方甲乙爲金砂。", "兩情含養歸一體，朱省調養生金華。", "金華生出天地寶，人會此言真正道。", "子稱虎，卯爲龍，龍虎相生自合同。", "龍居震位當其八，虎數元生在一宮。", "採有日，取有時，世人用之而不知。", "收取氣候若差錯，萬般工力徒勞施。", "至神至聖極容易，先向宮中求鼎器。", "溫養火候審陰陽，安排鑪室須擇地。", "不得地，莫妄爲，切須隱密審護持。", "保守莫洩天地機，此藥變化不思議。", "陽真砂，陰真汞，時人求之莫妄動。", "無質生質是還丹，凡汞凡砂不勞弄。", "（見《道藏·洞真部·玉訣類》陳摶《陰真君還丹歌注》）（按：陰真君即陰長生，爲漢時神仙，詳《太平廣記》卷八引《引仙傳》。", "此首當發依託。", "宋董逌《廣川書跋》卷八載李貽孫書陰真人詩，當即此首，知其應爲中唐以前之作。", "）。"]'),
('42d3e232-2dd1-4d79-b2df-16d1f7b3c2fc','登天台','葛玄','唐','唐诗','tang','','[]','高就山上山，山中白雲閑。',112,'全唐诗/poet.tang.57000.json','["高就山上山，山中白雲閑。", "瀑布低頭看，青天舉手扳。", "石橋橫海外，風笛落人間。", "不見紅塵客，時時鶴往還。", "（見《四庫珍本初集》本《天台集·拾遺》）（按：葛諦晉前神仙，見《太平廣記》卷七十一引《神仙傳》。", "此首五律顯爲齊梁以後人依託。", "）。"]'),
('61e2fcde-729e-4660-94b3-0269a3931e48','醜婦賦','劉思真','唐','唐诗','tang','','[]','人皆得令室，我命獨何[咎]（吝）（從安刻本改）。',209,'全唐诗/poet.tang.57000.json','["人皆得令室，我命獨何[咎]（吝）（從安刻本改）。", "不遇姜任德，正值醜惡婦。", "才質陋且儉，姿容劇嫫母。", "鹿頭獼猴面，推額復出口。", "折頞靨樓鼻，兩眼䫜（一交切）如臼。", "膚如老桑皮，耳如側兩手。", "頭如研米槌，髮如掘掃帚。", "惡觀醜儀容，不媚似鋪首。", "闇鈍拙梳髻，刻畫又更醜。", "妝頰如狗舐，額上獨偏厚。", "朱脣如踏血，畫眉如鼠負。", "傅粉堆頤下，面中不徧有。", "領如鹽豉囊，袖如常拭釜。", "履中如和泥，爪甲長有垢。", "脚皸可容箸，熟視今人嘔。", "（見《初學記》卷十九）。"]'),
('a7ec552d-9a14-42b5-9c1b-882a209febfc','失父零丁','戴良','唐','唐诗','tang','','[]','敬白諸君行路者，敢告重罪自爲積。',236,'全唐诗/poet.tang.57000.json','["敬白諸君行路者，敢告重罪自爲積。", "惡致災交天困我，今月七日失阿爹。", "念此酷毒可痛傷，當以重幣（重）用相賞，請爲諸君說事狀。", "我父軀體與衆異，脊背傴僂捲如胾。", "脣吻參差不相值，此其庶形何能備。", "請復重陳其面目，鴟頭鵠頸獦狗啄，眼淚鼻涕相追逐，吻中含納無牙齒，食不能嚼左右蹉。", "[□]似西域[□]駱駞。", "請復重陳其形骸，爲人雖長甚細材。", "面目芒蒼如死灰，眼眶臼陷如（米）羹柸。", "（見《太平御覽》卷五九八）（按：戴良時代不明，或作東漢人，非，詳王重民《敦煌變文研究》。", "今從王說收入並據以校改。", "）。"]'),
('58909ec2-1a14-4d5d-bff1-513eba0c8500','道藏歌詩 一','無名氏','唐','唐诗','tang','','[]','王龜七寶林，唱讚願同舟。',24,'全唐诗/poet.tang.57000.json','["王龜七寶林，唱讚願同舟。", "丹景曜目精，令我心踟蹰。"]'),
('b292c341-f1ca-4b6d-9644-5e34d428298d','道藏歌詩 二','無名氏','唐','唐诗','tang','','[]','解帶天皇寢，停駕高上兵。',24,'全唐诗/poet.tang.57000.json','["解帶天皇寢，停駕高上兵。", "玉真造角節，翊衞自相扶。"]'),
('89b866a9-e9fc-4003-90d5-14b056387175','道藏歌詩 三','無名氏','唐','唐诗','tang','','[]','玉皇命真王，飛軒浪天陔。',24,'全唐诗/poet.tang.57000.json','["玉皇命真王，飛軒浪天陔。", "諸天驩且悅，瓊音自瑲淒。"]'),
('14220335-3b8a-4b92-9a1d-2e912e6b6837','道藏歌詩 四','無名氏','唐','唐诗','tang','','[]','重萌鬱以赫，朱風引鳴鳩。',24,'全唐诗/poet.tang.57000.json','["重萌鬱以赫，朱風引鳴鳩。", "既忘榮曜契，何不寶僊居。"]'),
('71bb8c79-4c82-4075-9f04-85b174d35f17','道藏歌詩 五','無名氏','唐','唐诗','tang','','[]','不見九靈母，北真道相遒。',24,'全唐诗/poet.tang.57000.json','["不見九靈母，北真道相遒。", "九龍運東井，天馬發西嵎。"]'),
('d9d4a02d-8489-41a9-8ba7-5a60844cbf0f','道藏歌詩 六','無名氏','唐','唐诗','tang','','[]','仰翕長庚井，練胎反嬰孩。',24,'全唐诗/poet.tang.57000.json','["仰翕長庚井，練胎反嬰孩。", "太一保命籍，南陵拔夜居。"]'),
('cbf9f092-4958-47da-9118-01deaa408056','道藏歌詩 七','無名氏','唐','唐诗','tang','','[]','同歡舞雲華，衆真欣誰喻。',24,'全唐诗/poet.tang.57000.json','["同歡舞雲華，衆真欣誰喻。", "丹景曜目精，令我心踟蹰。"]'),
('07465a39-0eb9-498a-9be3-56cef9a47097','道藏歌詩 八','無名氏','唐','唐诗','tang','','[]','日月粲華暉，迴光照真符。',25,'全唐诗/poet.tang.57000.json','["日月粲華暉，迴光照真符。", "憶兆不同劫，千載莫之尤。", "。"]'),
('10624b0f-b0b8-45f5-868d-790b04532fff','道藏歌詩 九','無名氏','唐','唐诗','tang','','[]','白帝行炁道當新，名書紫府得其篇，西龜定錄位真人。',39,'全唐诗/poet.tang.57000.json','["白帝行炁道當新，名書紫府得其篇，西龜定錄位真人。", "（以上均見吳械《韻補》卷一）。"]'),
('3b3d3d49-beeb-40c6-883c-4fb24649d787','道藏歌詩 十','無名氏','唐','唐诗','tang','','[]','遊雲落太陽，飈景淩三天。',24,'全唐诗/poet.tang.57000.json','["遊雲落太陽，飈景淩三天。", "千秋似清旦，萬歲猶日半。"]'),
('f2b0d0b8-fde2-48e7-bd13-cf2146486432','道藏歌詩 十一','無名氏','唐','唐诗','tang','','[]','玄挺（一作「庭」）自嘉會，金書東華名。',69,'全唐诗/poet.tang.57000.json','["玄挺（一作「庭」）自嘉會，金書東華名。", "賢安密所戒，相期陽洛汧。", "（按：《孟東野詩集》卷九《列仙文·方諸青童君》末四句與此首相似，詳附按。", "）。"]'),
('0fee5465-7172-46a7-852a-cec4c4d5097c','道藏歌詩 十二','無名氏','唐','唐诗','tang','','[]','觀見學仙客，蹊路放炎煙。',24,'全唐诗/poet.tang.57000.json','["觀見學仙客，蹊路放炎煙。", "陽光不復朗，陰精不復明。"]'),
('18bd4469-8ec7-440b-a29c-01d8df9eab6f','道藏歌詩 十三','無名氏','唐','唐诗','tang','','[]','終劫復[始]（姑）劫，愈覺靈顏新。',29,'全唐诗/poet.tang.57000.json','["終劫復[始]（姑）劫，愈覺靈顏新。", "道林蔚天京，下光諸地仙。"]'),
('14287657-2afd-4311-9c73-2b65c198477b','道藏歌詩 十四','無名氏','唐','唐诗','tang','','[]','推校千精，熱馘雷震。',20,'全唐诗/poet.tang.57000.json','["推校千精，熱馘雷震。", "五帝秉鉞，神公吐煙。"]'),
('475efa5f-b081-4db5-b001-9c79c2610b59','道藏歌詩 十五','無名氏','唐','唐诗','tang','','[]','徘徊二元際，內觀自纏綿。',24,'全唐诗/poet.tang.57000.json','["徘徊二元際，內觀自纏綿。", "靈胎運九霞，永保億萬椿。"]'),
('ce9c2699-5059-42de-9d9b-6afb91533b3d','道藏歌詩 十六','無名氏','唐','唐诗','tang','','[]','齊（一作「躋」）景西那東，肆歡（一作「觀」）善因緣。',38,'全唐诗/poet.tang.57000.json','["齊（一作「躋」）景西那東，肆歡（一作「觀」）善因緣。", "常融無地官，皆是聖皇臣。"]'),
('0ba6022f-3d81-4e85-8d8c-d67247a0cadd','道藏歌詩 十七','無名氏','唐','唐诗','tang','','[]','今日慶元吉，億（一作「憶」）曾狀曲泉。',31,'全唐诗/poet.tang.57000.json','["今日慶元吉，億（一作「憶」）曾狀曲泉。", "法師及弟子，至德自然勳。"]'),
