('9cc9d1d2-b622-469e-82a3-bd4b18bca0a7','道藏歌詩 二十一','無名氏','唐','唐诗','tang','','[]','冥化自有數，我真法自然。',24,'全唐诗/poet.tang.57000.json','["冥化自有數，我真法自然。", "妙曲發空洞，宮商結仙靈。"]'),
('307ec42b-3977-45cc-be3c-79d8df12567f','道藏歌詩 二十二','無名氏','唐','唐诗','tang','','[]','今日度（一作「慶」）元吉，憶曾狀曲泉。',31,'全唐诗/poet.tang.57000.json','["今日度（一作「慶」）元吉，憶曾狀曲泉。", "萬神同斯和，億劫豈知淪。"]'),
('38199282-1126-486d-a95e-162d1c035e2e','道藏歌詩 二十三','無名氏','唐','唐诗','tang','','[]','椿齡會足衰，劫往豈足遼。',25,'全唐诗/poet.tang.57000.json','["椿齡會足衰，劫往豈足遼。", "虛刀揮至空，鄙滯五神愁。", "。"]'),
('e7155ad9-af52-43f4-a11e-68137234be85','道藏歌詩 二十四','無名氏','唐','唐诗','tang','','[]','迴舞太空嶺，六氣運重幽。',24,'全唐诗/poet.tang.57000.json','["迴舞太空嶺，六氣運重幽。", "我際豈能尋，使爾終不彫。"]'),
('a2a09e46-026c-4bb2-b86e-b65e423f5312','道藏歌詩 二十五','無名氏','唐','唐诗','tang','','[]','仙童掇朱實，神女獻玉瓜。',24,'全唐诗/poet.tang.57000.json','["仙童掇朱實，神女獻玉瓜。", "浴身丹浥池，濯髮甘泉波。"]'),
('f5b99f70-6e70-40c6-bdc3-d3b0ed6b7c7c','道藏歌詩 二十六','無名氏','唐','唐诗','tang','','[]','宴景玉京上，遊輪蹲玄都。',24,'全唐诗/poet.tang.57000.json','["宴景玉京上，遊輪蹲玄都。", "逍遙大明中，長燈煥翠羅。"]'),
('12f9eeac-f8eb-45d8-89cf-e0f23edebfce','道藏歌詩 二十七','無名氏','唐','唐诗','tang','','[]','乞免五難中，制召諸天魔。',24,'全唐诗/poet.tang.57000.json','["乞免五難中，制召諸天魔。", "靈嶽不崩陷，福地更鍊胎。"]'),
('3160eef4-4932-4540-b125-7ecea07ef69a','道藏歌詩 二十八','無名氏','唐','唐诗','tang','','[]','運役自然氣，於是息三徒。',24,'全唐诗/poet.tang.57000.json','["運役自然氣，於是息三徒。", "一暢萬劫感，慶賀西玉那。"]'),
('f8ea27b3-9af7-42fa-9db2-2682ee5ff8be','道藏歌詩 二十九','無名氏','唐','唐诗','tang','','[]','五道息對魂，九幽罷三途。',24,'全唐诗/poet.tang.57000.json','["五道息對魂，九幽罷三途。", "不聞孤魂聲，但聞興樂歌。"]'),
('cc0182af-152c-466e-9e3a-c7124a1e5088','道藏歌詩 三十','無名氏','唐','唐诗','tang','','[]','榮秀椿却期，乘運應靈圖。',24,'全唐诗/poet.tang.57000.json','["榮秀椿却期，乘運應靈圖。", "兜術開大有，一慶享祚多。"]'),
('63ec33fb-e25e-449d-8edf-1e7f8c517189','道藏歌詩 三十一','無名氏','唐','唐诗','tang','','[]','下看榮竟子，篤似蛙與蟆。',24,'全唐诗/poet.tang.57000.json','["下看榮竟子，篤似蛙與蟆。", "顧盼慶濁中，憂患自相羅。"]'),
('256cd6b8-93ef-4de7-af4e-94aa7c3d09a6','道藏歌詩 三十二','無名氏','唐','唐诗','tang','','[]','靜心念至真，隨運順離羅。',24,'全唐诗/poet.tang.57000.json','["靜心念至真，隨運順離羅。", "感應理常通，神適逮自徂。"]'),
