('715f7043-3587-46a1-b936-4020aec1f157','迴文對詩','無名氏','唐','唐诗','tang','','[]','情親由得意，得意遂情親。',56,'全唐诗/poet.tang.57000.json','["情親由得意，得意遂情親。", "新情終會故，會故亦經新。", "（自《的名對詩》以下十題均出《文鏡秘府論》東卷《二十九種對》）。"]'),
('88b4fb28-0a22-4b3c-8bdb-e72a2e2905d5','詩','無名氏','唐','唐诗','tang','','[]','淨宮鄰博望，香剎對承華。',38,'全唐诗/poet.tang.57000.json','["淨宮鄰博望，香剎對承華。", "（見《文鏡秘府論》地卷《十四例》引皎公《詩議》引）。"]'),
('14324dab-386d-4b39-9546-eefbff340d6a','雙虛實對詩','無名氏','唐','唐诗','tang','','[]','故人雲雨散，空山來往疏。',12,'全唐诗/poet.tang.57000.json','["故人雲雨散，空山來往疏。"]'),
('45577ba6-3bdd-4aa1-8132-f41c8f00ebff','假對詩','無名氏','唐','唐诗','tang','','[]','不獻胸中策，空歸海上山。',27,'全唐诗/poet.tang.57000.json','["不獻胸中策，空歸海上山。", "（同前書東卷引皎然《詩議》）。"]'),
('f3dabde2-1c09-4caa-aad2-ac384a178c63','詠物階詩 一','無名氏','唐','唐诗','tang','','[]','雙眉學新綠，二臉例輕紅。',29,'全唐诗/poet.tang.57000.json','["雙眉學新綠，二臉例輕紅。", "言模（一作摸）出浪鳥，字寫入花蟲。"]'),
('7b93d83f-b4f5-4e1e-9423-b634f3d90246','詠物階詩 二','無名氏','唐','唐诗','tang','','[]','灑塵成細跡，點水作圓文。',25,'全唐诗/poet.tang.57000.json','["灑塵成細跡，點水作圓文。", "白銀花裏散，明珠葉上分。", "。"]'),
('ce899b18-7615-4b9d-9858-64582f9404a1','贈物階詩 一','無名氏','唐','唐诗','tang','','[]','心貞如玉性，志潔若金爲。',24,'全唐诗/poet.tang.57000.json','["心貞如玉性，志潔若金爲。", "託曾同心葉，因附合歡枝。"]'),
('1eff93e5-b186-4427-bc61-24c76b5c80ca','贈物階詩 二','無名氏','唐','唐诗','tang','','[]','合瞑刺縫罷，守啼方達曙。',24,'全唐诗/poet.tang.57000.json','["合瞑刺縫罷，守啼方達曙。", "帶長垂兩巾，代人交手處。"]'),
('209a68e4-0f85-4f7a-bdbe-3f2d06527044','述志階詩 一','無名氏','唐','唐诗','tang','','[]','有鳥異孤鸞，飛無羣獨漾。',32,'全唐诗/poet.tang.57000.json','["有鳥異孤鸞，飛無羣獨漾。", "鶴戲逐輕風，起響（一作「聊起」）三臺上。"]'),
('587f6d68-47ae-49f9-901f-d55adfc3414b','述志階詩 二','無名氏','唐','唐诗','tang','','[]','丈夫懷慷慨，膽（一作瞻）上湧波奔。',29,'全唐诗/poet.tang.57000.json','["丈夫懷慷慨，膽（一作瞻）上湧波奔。", "只將三尺劍，決搆一朱門。"]'),
('3ca7c62d-1b2b-4fe2-a092-e6d7f75f383a','寫心階詩 一','無名氏','唐','唐诗','tang','','[]','命禮遣舟車，佇望談言志。',29,'全唐诗/poet.tang.57000.json','["命禮遣舟車，佇望談言志。", "若值信來符（一作府），共子同琴瑟。"]'),
('b135add7-8a8c-4ba0-97b6-97efbd9c9f67','寫心階詩 二','無名氏','唐','唐诗','tang','','[]','插花花未歇，薰衣衣已香。',24,'全唐诗/poet.tang.57000.json','["插花花未歇，薰衣衣已香。", "望望遙心斷，悽悽愁切腸。"]'),
('84c6bf78-0bee-401a-88d0-f545f00d8849','近酬階詩 一','無名氏','唐','唐诗','tang','','[]','盛夏盛炎光（一作光炎），焦天焦氣烈。',18,'全唐诗/poet.tang.57000.json','["盛夏盛炎光（一作光炎），焦天焦氣烈。"]'),
('33c6ab89-6f5a-4352-a113-603b2211ddf2','近酬階詩 二','無名氏','唐','唐诗','tang','','[]','清階清溜瀉，涼戶涼風入。',12,'全唐诗/poet.tang.57000.json','["清階清溜瀉，涼戶涼風入。"]'),
('a2099b03-df8a-4148-a744-02391287011d','讚毀階詩 一','無名氏','唐','唐诗','tang','','[]','施朱桃惡彩，點黛柳慚色。',12,'全唐诗/poet.tang.57000.json','["施朱桃惡彩，點黛柳慚色。"]'),
('6026d6a3-4198-4210-8e25-1bd0ac9667c5','讚毀階詩 二','無名氏','唐','唐诗','tang','','[]','皓雪已藏暉，凝霜方疊影。',12,'全唐诗/poet.tang.57000.json','["皓雪已藏暉，凝霜方疊影。"]'),
('73482d57-21da-4be9-867c-e646506d8819','援寡階詩','無名氏','唐','唐诗','tang','','[]','。',1,'全唐诗/poet.tang.57000.json','["。"]'),
('5a0dfd57-db6a-4b01-a6a1-7dda510ff489','援寡階詩 一','無名氏','唐','唐诗','tang','','[]','女蘿本細草，抽莖信不功。',24,'全唐诗/poet.tang.57000.json','["女蘿本細草，抽莖信不功。", "憑高出嶺上，假樹入雲中。"]'),
('d723ae8e-d60b-40f4-ad53-c8f74ab077e7','援寡階詩 二','無名氏','唐','唐诗','tang','','[]','愁臨玉臺鏡，淚垂金縷裙。',12,'全唐诗/poet.tang.57000.json','["愁臨玉臺鏡，淚垂金縷裙。"]'),
('099b0cdf-0e1e-4461-907f-80ee49e8c42e','和詩階詩 一','無名氏','唐','唐诗','tang','','[]','花桃微散紅，萠蘭稍開紫。',24,'全唐诗/poet.tang.57000.json','["花桃微散紅，萠蘭稍開紫。", "客子情已多，春望復如此。"]'),
('b6b8b842-fdda-4930-8b70-aeca9d5dde35','和詩階詩 二','無名氏','唐','唐诗','tang','','[]','風光搖隴麥，日華映林蘂。',212,'全唐诗/poet.tang.57000.json','["風光搖隴麥，日華映林蘂。", "春情重以傷，歸念（一作命）何由弭？", "（均見《文鏡秘府論》地卷《八階》錄佚名《文筆式》）（〖1〗今人逯欽立《先秦漢魏晉南北朝詩後記》云：「又如《文鏡秘府》也曾徵引許多詩篇，但這些詩篇率不著作者，其中有一部分又可能是初唐之作，因此，這裏也不加輯錄。", "」按：逯說甚是。", "今參照王利器先生《文鏡秘府論校注》的考訂，將《文鏡秘府論》中不見於《先秦漢魏晉南北朝詩》及《全唐詩》的作品，皆錄入先宋詩，以便研究者檢用。", "）。"]'),
('9c488507-8cd2-4f51-9816-6d75ce5e5352','北方歌','無名氏','唐','唐诗','tang','','[]','北方玄武身本黑，家鄉體住崑崙國。',96,'全唐诗/poet.tang.57000.json','["北方玄武身本黑，家鄉體住崑崙國。", "尋常定志有長生，方圓任性可生得。", "隨流信運長爲客，誰識我身性無白。", "不獨含著五行精，就中偏感陰陽魄。", "調和兌震爲夫婦，四象排來在高處。", "分明指似後人言，莫使昏迷錯天路。"]'),
('c1bcc273-d38e-4922-a145-3b97eec1453a','西方歌','無名氏','唐','唐诗','tang','','[]','西方白虎本屬陰，爲男爲女亦爲金。',127,'全唐诗/poet.tang.57000.json','["西方白虎本屬陰，爲男爲女亦爲金。", "長立子宮胎產午，成形兌體坎同心。", "嬌姿玉貌欺冰雪，素質含光洒輕血。", "則知喚作白琅玕，怎識我身是明月。", "無媒自嫁得黃芽，生死在歸戊己家。", "炎烈下時寒國上，陰陽催強緫成砂。", "若人會得吾此語，目前便是三清路。", "駕鶴沖天日有菁定知永劫拋塵土。"]'),
('5b84cd9f-4e96-48f4-8d1d-2bcc97c5e66b','南方歌','無名氏','唐','唐诗','tang','','[]','南方朱雀其身赤，猛烈雄強勢難敵。',128,'全唐诗/poet.tang.57000.json','["南方朱雀其身赤，猛烈雄強勢難敵。", "性共乾坤造化齊，體並陰陽難消息。", "水妻土母木家子，白帝金形胎受此。", "四象皆因我氣生，萬類須由我氣死。", "性連甲乙氣偏通，媾扇金娘嫁木翁。", "歸投戊己到中宮，看看變轉緫交紅。", "此謌不悟慇懃說，句句從頭細分雪。", "莫言積學但陰功，始解消詳吾志訣。"]'),
('6f3c06b6-7643-4794-8144-363e13c3dcd1','東方歌','無名氏','唐','唐诗','tang','','[]','東方有木本名砂，爲男爲女亦爲芽。',128,'全唐诗/poet.tang.57000.json','["東方有木本名砂，爲男爲女亦爲芽。", "受氣午成須立子，含精育質長金家。", "自從成長多年月，朝朝各自向天涯。", "莫欺形貌黑皴皵，渾身緫是日精華。", "忽若遇著陰家子，不假良媒自相許。", "迎歸寶帳到中宮，陰陽氣合情意與。", "特地爲胎重造化，運動坎離巡八卦。", "十月懷胎母子分，定知霄漢驂鸞駕。"]'),
('d79b3944-ccf8-4855-85cc-80f657bb238e','中方歌','無名氏','唐','唐诗','tang','','[]','中央戊己屬句陳，體合虛無與道隣。',144,'全唐诗/poet.tang.57000.json','["中央戊己屬句陳，體合虛無與道隣。", "純抱元和精粹氣，陶身萬煉緫成真。", "木妻火子水家鬼，水土相鎮不能起。", "還教却產西方金，遞代相承壯精髓。", "雖然我身無正形，志事隈憑四象生。", "四象不因連我氣，水金木火豈能成？", "徧通金木恩情熟，留向胎中親養育。", "麗物相和氣緫幷，須憑丙火來煎蹙。", "丙火元來是我命，節候輪排依法令。"]'),
('e4c95cba-0eec-4e8f-aace-586dadcbcca7','二氣產黃芽歌','無名氏','唐','唐诗','tang','','[]','乾坤感應始爲形，造化元因北戶成。',64,'全唐诗/poet.tang.57000.json','["乾坤感應始爲形，造化元因北戶成。", "日月周旋魂魄合，陰陽交媾結爲精。", "分明一氣從金長，認取黃芽自水生。", "無限虛於塵世裏，時人日用不知名。"]'),
('c47a9c82-3268-48c3-8602-f807dc427496','廣成子口訣','無名氏','唐','唐诗','tang','','[]','世上忙忙沒了程，百年如夢瞥然榮。',64,'全唐诗/poet.tang.57000.json','["世上忙忙沒了程，百年如夢瞥然榮。", "不知道有雲衢客，剛自爭超塵裏名。", "若欲留年從太一，須吞靈藥便長生。", "純燒無地陰陽髓，煉取乾坤日月精。"]'),
('1488388b-4c95-4809-ab2e-5653bd7a4f00','廣成子傳附二味','無名氏','唐','唐诗','tang','','[]','要伏離宮亦等閑，搜求坎戶取精研。',87,'全唐诗/poet.tang.57000.json','["要伏離宮亦等閑，搜求坎戶取精研。", "但比夫婦成交感，孕出黃芽見本源。", "若不親傳師指受，此外徒勞虛費錢。", "火候仍修終九九，丹成直待是三年。", "（按：廣成子爲古神仙，事見《莊子·在宥》。", "）。"]'),
('1fe0920e-a984-4216-bf6b-58eed2191780','抱朴子口訣','無名氏','唐','唐诗','tang','','[]','朱砂水銀入華池，收得黃芽人不知。',93,'全唐诗/poet.tang.57000.json','["朱砂水銀入華池，收得黃芽人不知。", "本是仙人留口訣，世上喧喧亂言說。", "七十年中付一人，分付還須有仙骨。", "一一事須手眼傳，採取只在片時間。", "河專覆在丹田裏，制伏只在黃芽邊。", "（按：抱朴子即晉葛洪。", "）。"]'),
('c28bbfc9-018f-495b-8300-5e5d0612f204','張華真人鉛汞歌','無名氏','唐','唐诗','tang','','[]','赤龍化爲粉，白虎利如霜。',49,'全唐诗/poet.tang.57000.json','["赤龍化爲粉，白虎利如霜。", "其中投石液，還要帝流漿。", "調神清五臟，欲得鍊三光。", "專守堅冰性，如何陰使陽？。"]'),
('47b2e569-2a37-4386-88db-499306b051ff','張華真人二味口訣','無名氏','唐','唐诗','tang','','[]','虎伏龍亦藏，龍潛先伏虎。',97,'全唐诗/poet.tang.57000.json','["虎伏龍亦藏，龍潛先伏虎。", "但畢河車功，不用隄防慮。", "黃老學飛仙，狂迷不得路。", "迴首指牝鷄，不測陰陽數。", "却坐太一宮，參商方始遇。", "左右得近神，四相皆扶護。", "乾坤法象成，自有仙人顧。", "（按：張華爲西晉時人。", "）。"]'),
('cf4f31b1-c909-4be2-808e-f620e73dada1','尹喜真人口訣','無名氏','唐','唐诗','tang','','[]','至藥須用鉛，盃向黑中聚。',68,'全唐诗/poet.tang.57000.json','["至藥須用鉛，盃向黑中聚。", "若欲識黃芽，先應問陰土。", "真鉛配坎男，戊己來相顧。", "只此號黃礬，便是還丹祖。", "（按：尹喜即關尹喜，傳爲老子同時人。", "）。"]'),
('bc3276c3-3a78-4a78-bd37-466876bbb7a3','函谷關元君鉛汞謌','無名氏','唐','唐诗','tang','','[]','紅鉛黑鉛大丹頭，紅鉛黑鉛體同金。',96,'全唐诗/poet.tang.57000.json','["紅鉛黑鉛大丹頭，紅鉛黑鉛體同金。", "黑金取精赤取髓，解用赤黑藥無比。", "用赤入黑保長生，用黑入赤天仙矣。", "顛倒兩法緫稱鉛，黑能變化赤天仙。", "至道之人莫容易，貪財好色不須傳。", "函谷關頭梁石山，老君鐫石留此言。"]'),
('ea1a7e7a-36b3-4790-be58-83bd32fb97f7','漢祖天師口訣','無名氏','唐','唐诗','tang','','[]','鉛抽髓，髓抽精，精髓相合丹必成。',121,'全唐诗/poet.tang.57000.json','["鉛抽髓，髓抽精，精髓相合丹必成。", "一斤水銀十七兩，一兩變化是鉛精。", "將此鉛精作大丹，老子九轉入生研。", "一麗水銀特牛力，服之令人貌若仙，貌若仙兮筋骨堅。", "筋骨堅強返枯槁，截舌人間不須道。", "未能隱顯出沒藏，切慎懼口莫顛狂。", "若教上界天神怒，恐遭非橫及刀光。", "。"]'),
('7e6d323e-590d-4882-b7b5-c5c6136d80c0','嚴君平口訣','無名氏','唐','唐诗','tang','','[]','鉛是鉛，汞是汞，只這兩般是鉛汞。',166,'全唐诗/poet.tang.57000.json','["鉛是鉛，汞是汞，只這兩般是鉛汞。", "龍是龍，虎是虎，只這兩箇同宗祖。", "若能識此坎離宮，離宮之下出黃土。", "黃土出黃芽，黃芽之下金花成。", "金花成，金花之下結紫精。", "紫精成，紫精之下出白金。", "白金沉，黃金浮，世人採沉作丹頭，搜取赤髓相和種。", "種有時，採有日，換筋骨，添壽歷，天仙地仙不思議。", "點鉛鐵，兼瓦礫，一二三四五，水火木金土。", "但知明此訣，便是長生路。"]'),
('4bb8a6ab-81ce-41da-add8-a4cfa56ac5e8','陰長生口訣','無名氏','唐','唐诗','tang','','[]','金作骨兮鉛作身，陰陽定配龍虎親。',209,'全唐诗/poet.tang.57000.json','["金作骨兮鉛作身，陰陽定配龍虎親。", "紅顏二八三才合，八卦分張斗建寅。", "從子午，不須移，七十二候莫參差。", "姹女因媒歸太一，紫微宮內生雄雌。", "鉛中寶，砂中珍，此物含弘象五神。", "七月懷胎分六甲，終歲人轉乃成真。", "淮南法，煉秋石，黃帝金花燒琥珀。", "白酒盃添九醖香，晶輝甘甜號龍液。", "一人有，一人無，三姓同家二子俱。", "狐兔非羣不乳馬，異類天然種性殊。", "冥復冥，玄復玄，此法非人不可傳。", "世人不知世上藥，知我還命不由天。", "（按：嚴君平、陰長生皆漢時人。", "）。"]'),
('5c9a6197-e92b-42b2-a0e7-cb3f2f46be82','果州謝自然口訣','無名氏','唐','唐诗','tang','','[]','白女正當年十六，自誇弱質顏如玉。',390,'全唐诗/poet.tang.57000.json','["白女正當年十六，自誇弱質顏如玉。", "常嗟歲月無良媒，晝夜孤單唯獨宿。", "爺娘不審他心意，謾說張三並李四。", "幾度爲話緫不成，教人羞天復愧地。", "忽遇黃婆來扣門，說道金公體性溫，遂將二命問君平。", "君平斷言此好婚，不偏不曲合乾坤。", "審此因緣甚宜良，至今子孫滿帝鄉。", "昔時不因黃婆力，如何得契合陰陽。", "（以上皆見《正統道藏》本《大還丹照鑑》）（按：《大還丹照鑑》編者不詳，卷首有後蜀廣政二十五年序，稱「偶因閑暇，採摭仙經，重刪先聖格言，留爲後人軌範，名曰《照鑑登仙集》，總成一卷，分作三十三篇」。", "《通志·藝文略》著錄作《大還丹照鑑登仙集》一卷。", "知今本書名未完。", "此書所收詩以唐的之作爲多。", "上錄自《北方歌》以下六篇不題撰人，自《廣成子口訣》以下十篇皆題古聖前哲之名，應皆爲唐人或唐以前人所依託。", "謝自然，爲唐德宗貞元時人，事詳《太平廣記》卷六六引《集仙錄》。", "然此詩顯爲時人詠其事之作。", "與前列諸詩不同，姑錄存於此。", "）。"]'),
('adaaca24-e740-4037-9f4e-c23c3b2cc4d6','太微天帝君讚大有妙經頌一章','無名氏','唐','唐诗','tang','','[]','丹暉映雲庭，紫煙光玉林。',48,'全唐诗/poet.tang.57000.json','["丹暉映雲庭，紫煙光玉林。", "煥爛七寶花，璀璨瑤靈音。", "宮商自相和，妙靈開人衿。", "玄唱種福田，廣度無界心。"]'),
('14e2c24b-656b-4ad5-b754-aaecc22e0da5','天帝君讚大有妙經頌一章','無名氏','唐','唐诗','tang','','[]','玄化本無跡，有跡生道宗。',48,'全唐诗/poet.tang.57000.json','["玄化本無跡，有跡生道宗。", "遨遊九天際，息駕六領宮，道暢虛漠內，靈歌發太空。", "形感至寂庭，思詠希微通。"]'),
('a17bb619-a31d-4dc3-8231-3053754c9040','太帝君讚大有妙經頌一章','無名氏','唐','唐诗','tang','','[]','翳翳元化初，眇眇晨霞散。',60,'全唐诗/poet.tang.57000.json','["翳翳元化初，眇眇晨霞散。", "太寂空玄上，寥朗二儀判。", "凝精抱空胎，結化孕靈觀。", "含真頤神內，倏歘啓㝠旦。", "始悟憂促齡，運交反天漢。"]'),
('31cc9034-da97-43ea-92ef-102bf10f6a31','老君本生經頌一章','無名氏','唐','唐诗','tang','','[]','衆生之本際，寂然無起滅。',96,'全唐诗/poet.tang.57000.json','["衆生之本際，寂然無起滅。", "弱喪迷其根，自與真源別。", "妄作善惡緣，禍福報無絕。", "欲得苦海傾，當使愛河竭。", "守一固專柔，持此無疵缺。", "正智通羣有，妙慧摧諸結。", "萬行混同歸，三乘泯殊轍。", "真靜離塵垢，清涼無惱熱。"]'),
('7c827828-384b-498e-8de3-3d246a8d39b8','太上智慧佪玄經頌一章','無名氏','唐','唐诗','tang','','[]','靈仙乘慶霄，駕龍躡玄波。',60,'全唐诗/poet.tang.57000.json','["靈仙乘慶霄，駕龍躡玄波。", "洽真表嘉祥，濯足八天河。", "福應不我期，故能釋天羅。", "道德冠三界，地網亦以過。", "感遇靈真會，淨慧經蓮華。"]'),
('1c527ae6-0f3d-4198-9a70-216932b42cea','太上智慧經讚一章','無名氏','唐','唐诗','tang','','[]','學仙絕華念，念念相因積。',60,'全唐诗/poet.tang.57000.json','["學仙絕華念，念念相因積。", "去來亂我神，神躁靡不歷。", "滅念停虛閑，蕭蕭入空寂。", "請經若飢渴，持志如金石。", "保子飛玄路，五靈度符籍。"]'),
('05fa7fbf-19fc-4fa7-947c-f6445d734fb2','本願大戒經頌一章','無名氏','唐','唐诗','tang','','[]','學自行爲急，奉戒制情心。',24,'全唐诗/poet.tang.57000.json','["學自行爲急，奉戒制情心。", "虛夷正氣居，仙聖自相尋。"]'),
('9c28112b-597f-4195-bc31-7610c231912e','玉皇授歘生大洞三十九章與登龍臺歌二章 一','無名氏','唐','唐诗','tang','','[]','飈飈三霞領，佪剛七元蓋。',72,'全唐诗/poet.tang.57000.json','["飈飈三霞領，佪剛七元蓋。", "八景入太元，飛灑九天外。", "瓊扉生景雲，靈煙絶幽藹。", "西宮詠洞玄，清唱扶桑際。", "守雌森峯間，玄吟五老會。", "歘生有心哉，與爾結中帶。"]'),
('d5258933-09e2-4115-b3e5-ff5bc2e9e34f','玉皇授歘生大洞三十九章與登龍臺歌二章 二','無名氏','唐','唐诗','tang','','[]','匏河振滄茫，天津鼓萬流。',61,'全唐诗/poet.tang.57000.json','["匏河振滄茫，天津鼓萬流。", "八風駕神霄，緬緬虛中遊。", "詠洞神明唱，音爲汝玄投。", "歘生必至行，肘伏塵中趨。", "可爲苦心哉，當告爾所求。", "。"]'),
('a5f4a8f9-7e00-44db-bc91-bc4593115c5b','西王母授紫度炎光神變經頌三篇 一','無名氏','唐','唐诗','tang','','[]','嘯歌九玄臺，崖嶺凝淒端。',60,'全唐诗/poet.tang.57000.json','["嘯歌九玄臺，崖嶺凝淒端。", "心理六覺暢，目棄塵滓氛。", "流霞耀金室，虛堂散重玄。", "積感致靈降，形單道亦分。", "倏歘盼萬劫，豈覺周億椿。"]'),
('02cf0323-ca5f-4be1-8a4e-03abf7611d1d','西王母授紫度炎光神變經頌三篇 二','無名氏','唐','唐诗','tang','','[]','秀圃蔚神階，朱扉瓊林庭。',72,'全唐诗/poet.tang.57000.json','["秀圃蔚神階，朱扉瓊林庭。", "流風鼓空洞，玉籟乘虛鳴。", "紫烟纏曲戶，丹暉映綠軿。", "飛旗欝玄蓋，羽節耀紫清。", "登景九霄際，遨遊戲鳳城。", "顧愛幽境子，一樂同朝生。"]'),
('fa2cb517-b622-43b0-8251-1c653e8b0ce1','西王母授紫度炎光神變經頌三篇 三','無名氏','唐','唐诗','tang','','[]','騰轡控朗暉，宴景洞野外。',72,'全唐诗/poet.tang.57000.json','["騰轡控朗暉，宴景洞野外。", "流浪尋靈人，合形慶霄際。", "手披朱島戶，朗若神沖泰。", "金闕欝嵯峨，清景無塵穢，解衿玄閬臺，適我良願會。", "脫屣三塗難，保鍊固年邁。"]'),
('73a08b84-df6d-4c40-a17b-c5361d0c3198','靈寶真一自然太上玄一真人頌一章','無名氏','唐','唐诗','tang','','[]','衆妙出洞真，煥爛曜太清。',108,'全唐诗/poet.tang.57000.json','["衆妙出洞真，煥爛曜太清。", "奉者號仙人，體無永長生。", "逍遙戲玄虛，宮殿羅無形。", "蒨粲七寶林，晃朗日月精。", "龍鱗交橫馳，鳳皇翔悲鳴。", "太上治紫臺，衆真誦洞經。", "捻香稽首禮，旋行遶宮城。", "三周歸高座，道王爲應聲。", "人主弘至道，天下普安寧。"]'),
('b9cbf372-b4c8-4428-8f94-a7cab160556d','太上弘道頌一章','無名氏','唐','唐诗','tang','','[]','太上玄虛宗，弘道尊其經。',60,'全唐诗/poet.tang.57000.json','["太上玄虛宗，弘道尊其經。", "俯仰已得仙，歷劫無數齡。", "巍巍太真德，寂寂因無生。", "霄景結空構，乘虛自然征。", "明月光炳灼，安和樂未央。"]'),
('3225b4d2-7027-401f-bc26-329f45be25d3','吳王夫差書一章（幷序）','無名氏','唐','唐诗','tang','','[]','玄津流絳波，崑碧映琅山。',232,'全唐诗/poet.tang.57000.json','["玄津流絳波，崑碧映琅山。", "朝日控晨輝，薈豔何婉蜒。", "遊雲落太陽，飈景淩三天。", "靈寶曜九虛，幽明鍾山間。", "夏禹登八牕，散氣響金蘭。", "因枝振玉條，緣波討洪源。", "扶質立靈榦，垂葉以結繁。", "渺邈龍鳳跡，煥爛九天翰。", "仰挹三辰精，保身永長安。", "俯漱五華液，還復反童顏。", "騰神溫涼宮，豈知熱與寒。", "千秋似清旦，萬歲猶日半。", "鼓翼空洞上，要我靈寶官。", "棼棼五帝駕，俱會景漠端。", "相問飢與渴，玄泉饒流丹。", "永仙方寸內，八遐無易難。", "顧聞朱門臭，當塗中有難。", "銘碣勞巖陰，穴岫可稽盤。", "（以上皆見《雲笈七籤》卷九六）。"]'),
('1edcf79a-6b17-408c-a6a1-37f4f8277872','衆仙步虛詞五首 一','無名氏','唐','唐诗','tang','','[]','飄飄上雲路，黯黯入長霄。',48,'全唐诗/poet.tang.57000.json','["飄飄上雲路，黯黯入長霄。", "星宮日去遠，光陰劫數遙。", "仰德金顏隱，傾想佇神飈。", "願得暎霞軫，焚香稽首朝。"]'),
('fa819521-af85-4a95-ad62-ff13af26ca78','衆仙步虛詞五首 二','無名氏','唐','唐诗','tang','','[]','玄風轉飛蓋，紫氣汎仙車。',48,'全唐诗/poet.tang.57000.json','["玄風轉飛蓋，紫氣汎仙車。", "浮空不侍駕，倐忽昇虛無。", "徘徊哀下界，顧眄愍羣諸。", "三元真化畢，翛然入太虛。"]'),
('0dcdcb3d-0fcc-490f-a17a-f05c651877ca','衆仙步虛詞五首 三','無名氏','唐','唐诗','tang','','[]','萬氣浮空上，千光合太微。',48,'全唐诗/poet.tang.57000.json','["萬氣浮空上，千光合太微。", "霄間望華蓋，虛裏眄霞衣。", "真儀入雲路，圓曜逐風飛。", "願得三元會，金容乘運歸。"]'),
('746b3ca7-e7fa-4b22-806b-72b7c74cdbbe','衆仙步虛詞五首 四','無名氏','唐','唐诗','tang','','[]','吉光騰紫氣，霄路逸丹天。',84,'全唐诗/poet.tang.57000.json','["吉光騰紫氣，霄路逸丹天。", "蟠颺香風轉，蓋動超浮煙。", "道中還復道，玄中已復玄。", "真光不識際，大道竟無形。", "法輪常自轉，希音不可聽。", "空閑待三寶，虛中聞洞經。", "七變遊魂反，萬氣駐頹齡。"]'),
('5d47f9ab-605f-44b4-90b1-19c1d4e40c81','衆仙步虛詞五首 五','無名氏','唐','唐诗','tang','','[]','香風飄羽蓋，遊氣轉飈車。',60,'全唐诗/poet.tang.57000.json','["香風飄羽蓋，遊氣轉飈車。", "泠泠上雲路，窈窈入長虛。", "顧愍埃塵子，應運演靈書。", "妙果諧今日，㝠契自然符。", "（《雲笈七籤》卷九九）。"]'),
('d3a5b9ea-70fc-4c1d-ad67-12c498019caa','青童天君常吟一首','無名氏','唐','唐诗','tang','','[]','欲植滅度根，當拔生死栽。',29,'全唐诗/poet.tang.57000.json','["欲植滅度根，當拔生死栽。", "沉吟墮九泉，但坐惜形骸。", "（同前）。"]'),
('79c2288a-0eb6-42b0-b594-5961a44da7fd','陶隱居望江南 一','無名氏','唐','唐诗','tang','','[]','長生藥，本是五行作。',32,'全唐诗/poet.tang.57000.json','["長生藥，本是五行作。", "子午三門開卯酉，四時運火合乾坤。", "龍虎自相吞。"]'),
('559deef1-764f-4f72-ad38-023d298a67d7','過崔駙馬山池','王維','唐','唐诗','tang','','[]','畫樓吹笛妓，金椀酒家胡。',48,'全唐诗/poet.tang.6000.json','["畫樓吹笛妓，金椀酒家胡。", "錦石稱貞女，青松學大夫。", "脫貂貰桂醑，射雁與山廚。", "聞道高陽會，愚公谷正愚。"]'),
('595dc46d-917d-4e78-ad43-09fd253a689d','過福禪師蘭若','王維','唐','唐诗','tang','','[]','巖壑轉微逕，雲林隱法堂。',48,'全唐诗/poet.tang.6000.json','["巖壑轉微逕，雲林隱法堂。", "羽人飛奏樂，天女跪焚香。", "竹外峰偏曙，藤陰水更涼。", "欲知禪坐久，行路長春芳。"]');
